export const verseTranslations: Record<string, Partial<Record<"es"|"fr"|"pt"|"sv"|"no"|"da", string>>> = {
 "Acts 2:17-18": {
 es: " Y será en los postreros días, dice Dios, derramaré de mi Espíritu sobre toda carne, y vuestros hijos y vuestras hijas profetizarán; y vuestros mancebos verán visiones, y vuestros viejos soñarán sueños: Y de cierto sobre mis siervos y sobre mis siervas en aquellos días derramaré de mi Espíritu, y profetizarán.",
 fr: "Dans les derniers jours, dit Dieu, je répandrai de mon Esprit sur toute chair; Vos fils et vos filles prophétiseront, Vos jeunes gens auront des visions, Et vos vieillards auront des songes. Oui, sur mes serviteurs et sur mes servantes, Dans ces jours-là, je répandrai de mon Esprit; et ils prophétiseront.",
 pt: "E acontecerá nos últimos dias, diz o Senhor, que derramarei do meu Espírito sobre toda a carne; e os vossos filhos e as vossas filhas profetizarão, os vossos mancebos terão visões, os vossos anciãos terão sonhos; e sobre os meus servos e sobre as minhas servas derramarei do meu Espírito naqueles dias, e eles profetizarão.",
 sv: "'Och det skall ske i de yttersta dagarna, säger Gud, att jag skall utgjuta av min Ande över allt kött, och edra söner och edra döttrar skola profetera, och edra ynglingar skola se syner, och edra gamla män skola hava drömmar; ja, över mina tjänare och mina tjänarinnor skall jag i de dagarna utgjuta av min Ande, och de skola profetera.",
 no: "Og det skal skje i de siste dager, sier Gud, da vil jeg utgyde av min Ånd over alt kjød, og eders sønner og eders døtre skal tale profetiske ord, og eders unge menn skal se syner, og eders oldinger ha drømmer; ja, endog over mine træler og over mine trælkvinner vil jeg i hine dager utgyde av min Ånd, og de skal tale profetiske ord.",
 da: "v17 Og det skal ske i de sidste dage, siger Gud, da vil jeg udgyde af min ånd over alle mennesker; jeres sønner og døtre skal profetere, jeres unge mænd skal se syner, jeres gamle skal drømme drømme. v18 Selv over mine trælle og trælkvinder vil jeg i de dage udgyde af min ånd, og de skal profetere.",
 },
 "Acts 2:32-33": {
 es: " A este Jesús resucitó Dios, de lo cual todos nosotros somos testigos. Así que, levantado por la diestra de Dios, y recibiendo del Padre la promesa del Espíritu Santo, ha derramado esto que vosotros veis y oís.",
 fr: "C'est ce Jésus que Dieu a ressuscité; nous en sommes tous témoins. Elevé par la droite de Dieu, il a reçu du Père le Saint-Esprit qui avait été promis, et il l'a répandu, comme vous le voyez et l'entendez.",
 pt: "Ora, a este Jesus, Deus ressuscitou, do que todos nós somos testemunhas. De sorte que, exaltado pela dextra de Deus, e tendo recebido do Pai a promessa do Espírito Santo, derramou isto que vós agora vedes e ouvis.",
 sv: "Denne -- Jesus -- har nu Gud låtit uppstå; därom kunna vi alla vittna. Och sedan han genom Guds högra hand har blivit upphöjd och av Fadern undfått den utlovade helige Anden, har han utgjutit vad I här sen och hören.",
 no: "Denne Jesus opreiste Gud, som vi alle er vidner om. Efterat han nu er ophøiet ved Guds høire hånd og av sin Fader har fått den Hellige Ånd, som var lovt, så utgjød han dette som I både ser og hører.",
 da: "v32 Den Jesus har Gud ladet opstå, og det er vi alle vidner på. v33 Han er ophøjet til Guds højre hånd og har fra Faderen modtaget Helligånden som lovet, og den har han nu udgydt. Det er det, I både ser og hører.",
 },
 "Acts 2:34-35": {
 es: " Porque David no subió á los cielos; empero él dice: Dijo el Señor á mi Señor: Siéntate á mi diestra, Hasta que ponga á tus enemigos por estrado de tus pies.",
 fr: "Car David n'est point monté au ciel, mais il dit lui-même: Le Seigneur a dit à mon Seigneur: Assieds-toi à ma droite, Jusqu'à ce que je fasse de tes ennemis ton marchepied.",
 pt: "Porque Davi não subiu aos céus, mas ele próprio declara: Disse o Senhor ao meu Senhor: Assenta-te à minha direita, até que eu ponha os teus inimigos por escabelo de teus pés.",
 sv: "Ty icke har David farit upp till himmelen; fastmer säger han själv: 'Herren sade till min herre: Sätt dig på min högra sida, till dess jag har lagt dina fiender dig till en fotapall.",
 no: "For David fór ikke op til himmelen, men han sier selv: Herren sa til min herre: Sett dig ved min høire hånd, til jeg får lagt dine fiender til skammel for dine føtter!",
 da: "v34 For David steg ikke op til himlen, men han siger selv: Herren sagde til min herre: Sæt dig ved min højre hånd, v35 indtil jeg får lagt dine fjender som en skammel for dine fødder.",
 },
 "Acts 3:19-21": {
 es: " Así que, arrepentíos y convertíos, para que sean borrados vuestros pecados; pues que vendrán los tiempos del refrigerio de la presencia del Señor, Y enviará á Jesucristo, que os fué antes anunciado: Al cual de cierto es menester que el cielo tenga hasta los tiempos de la restauración de todas las cosas, que habló Dios por boca de sus santos profetas que han sido desde el siglo.",
 fr: "Repentez-vous donc et convertissez-vous, pour que vos péchés soient effacés, afin que des temps de rafraîchissement viennent de la part du Seigneur, et qu'il envoie celui qui vous a été destiné, Jésus-Christ, que le ciel doit recevoir jusqu'aux temps du rétablissement de toutes choses, dont Dieu a parlé anciennement par la bouche de ses saints prophètes.",
 pt: "Arrependei-vos, pois, e convertei-vos, para que sejam apagados os vossos pecados, de sorte que venham os tempos de refrigério, da presença do Senhor, e envie ele o Cristo, que já dantes vos foi indicado, Jesus, ao qual convém que o céu receba até os tempos da restauração de todas as coisas, das quais Deus falou pela boca dos seus santos profetas, desde o princípio.",
 sv: "Gören därför bättring och omvänden eder, så att edra synder bliva utplånade, på det att tider av vederkvickelse må komma från Herren, i det att han sänder den Messias som han har utsett åt eder, nämligen Jesus, vilken dock himmelen måste behålla intill de tider nå allt skall bliva upprättat igen, varom Gud har talat genom sina forntida heliga profeters mun.",
 no: "Så fatt da et annet sinn og vend om, forat eders synder må bli utslettet, så husvalelsens tider kan komme fra Herrens åsyn, og han kan sende den for eder utkårede Messias, Jesus, som himmelen skal huse inntil de tider da alt det blir gjenoprettet som Gud har talt om ved sine hellige profeters munn fra eldgamle dager av.",
 da: "v19 Derfor skal I omvende jer og vende om, for at jeres synder kan blive slettet ud, v20 for at de tider må komme fra Herren, da vi kan ånde frit, og for at han må sende den Messias, som forud var bestemt for jer, og det er Jesus. v21 Han skal bo i himlen, indtil de tider kommer, da alt det genoprettes, som Gud fra fordums tid har forkyndt gennem sine hellige profeters mund.",
 },
 "Acts 5:29-32": {
 es: " Y respondiendo Pedro y los apóstoles, dijeron: Es menester obedecer á Dios antes que á los hombres. El Dios de nuestros padres levantó á Jesús, al cual vosotros matasteis colgándole en un madero. A éste ha Dios ensalzado con su diestra por Príncipe y Salvador, para dar á Israel arrepentimiento y remisión de pecados. Y nosotros somos testigos suyos de estas cosas, y también el Espíritu Santo, el cual ha dado Dios á los que le obedecen.",
 fr: "Pierre et les apôtres répondirent: Il faut obéir à Dieu plutôt qu'aux hommes. Le Dieu de nos pères a ressuscité Jésus, que vous avez tué, en le pendant au bois. Dieu l'a élevé par sa droite comme Prince et Sauveur, pour donner à Israël la repentance et le pardon des péchés. Nous sommes témoins de ces choses, de même que le Saint-Esprit, que Dieu a donné à ceux qui lui obéissent.",
 pt: "Respondendo Pedro e os apóstolos, disseram: Importa antes obedecer a Deus que aos homens. O Deus de nossos pais ressuscitou a Jesus, ao qual vós matastes, suspendendo-o no madeiro; sim, Deus, com a sua destra, o elevou a Príncipe e Salvador, para dar a Israel o arrependimento e remissão de pecados. E nós somos testemunhas destas coisas, e bem assim o Espírito Santo, que Deus deu àqueles que lhe obedecem.",
 sv: "Men Petrus och de andra apostlarna svarade och sade: »Man måste lyda Gud mer än människor. Våra fäders Gud har uppväckt Jesus, som I haden upphängt på trä och dödat. Och Gud har med sin högra hand upphöjt honom till en hövding och frälsare, för att åt Israel förläna bättring och syndernas förlåtelse. Om allt detta kunna vi själva vittna, så ock den helige Ande, vilken Gud har givit åt dem som äro honom lydiga.»",
 no: "Da svarte Peter og apostlene: En skal lyde Gud mere enn mennesker. Våre fedres Gud opvakte Jesus, som I drepte ved å henge ham på et tre; ham ophøiet Gud ved sin høire hånd til høvding og frelser, for å gi Israel omvendelse og syndenes forlatelse. Og vi er hans vidner om disse ting, og likeså den Hellige Ånd, som Gud gav dem som lyder ham.",
 da: "v29 Men Peter og apostlene svarede: »Man bør adlyde Gud mere end mennesker. v30 Vore fædres Gud har oprejst Jesus, som I dræbte ved at hænge ham på et træ. v31 Ham har Gud ophøjet til sin højre hånd som anfører og frelser for at give Israel omvendelse og syndsforladelse. v32 Og vi er vidner om alt dette, vi og Helligånden, som Gud har givet dem, der adlyder ham.«",
 },
 "Acts 6:6-8": {
 es: " A estos presentaron delante de los apóstoles, los cuales orando les pusieron las manos encima. Y crecía la palabra del Señor, y el número de los discípulos se multiplicaba mucho en Jerusalem: también una gran multitud de los sacerdotes obedecía á la fe. Empero Esteban, lleno de gracia y de potencia, hacía prodigios y milagros grandes en el pueblo.",
 fr: "Ils les présentèrent aux apôtres, qui, après avoir prié, leur imposèrent les mains. La parole de Dieu se répandait de plus en plus, le nombre des disciples augmentait beaucoup à Jérusalem, et une grande foule de sacrificateurs obéissaient à la foi. Etienne, plein de grâce et de puissance, faisait des prodiges et de grands miracles parmi le peuple.",
 pt: "e os apresentaram perante os apóstolos; estes, tendo orado, lhes impuseram as mãos. E divulgava-se a palavra de Deus, de sorte que se multiplicava muito o número dos discípulos em Jerusalém e muitos sacerdotes obedeciam à fé. Ora, Estêvão, cheio de graça e poder, fazia prodígios e grandes sinais entre o povo.",
 sv: "Dem läto de träda fram för apostlarna, och dessa bådo och lade händerna på dem. Och Guds ord hade framgång, och lärjungarnas antal förökades mycket i Jerusalem; och en stor hop av prästerna blevo lydiga och trodde. Och Stefanus var full av nåd och kraft och gjorde stora under och tecken bland folket.",
 no: "dem stilte de frem for apostlene, og disse bad og la sine hender på dem. Og Guds ord hadde fremgang, og tallet på disiplene i Jerusalem øket sterkt, og en stor mengde av prestene blev lydige mot troen. Men Stefanus var full av nåde og kraft, og gjorde undergjerninger og store tegn blandt folket.",
 da: "v6 De blev stillet for apostlene, som bad og lagde hænderne på dem. v7 Og Guds ord fik fremgang, og antallet af disciple i Jerusalem voksede stærkt, og en stor del af præsterne blev lydige mod troen. v8 Stefanus var fuld af nåde og kraft og gjorde store undere og tegn blandt folket.",
 },
 "Acts 7:55-56": {
 es: " Mas él, estando lleno de Espíritu Santo, puestos los ojos en el cielo, vió la gloria de Dios, y á Jesús que estaba á la diestra de Dios, Y dijo: He aquí, veo los cielos abiertos, y al Hijo del hombre que está á la diestra de Dios.",
 fr: "Mais Etienne, rempli du Saint-Esprit, et fixant les regards vers le ciel, vit la gloire de Dieu et Jésus debout à la droite de Dieu. Et il dit: Voici, je vois les cieux ouverts, et le Fils de l'homme debout à la droite de Dieu.",
 pt: "Mas ele, cheio do Espírito Santo, fitando os olhos no céu, viu a glória de Deus, e Jesus em pé à direita de Deus, e disse: Eis que vejo os céus abertos, e o Filho do homem em pé à direita de Deus.",
 sv: "Men han, full av helig ande, skådade upp mot himmelen och fick se Guds härlighet och såg Jesus stå på Guds högra sida. Och han sade: »Jag ser himmelen öppen och Människosonen stå på Guds högra sida.»",
 no: "Men han var full av den Hellige Ånd og skuet ufravendt op mot himmelen, og han så Guds herlighet, og Jesus stå ved Guds høire hånd, og han sa: Nu ser jeg himlene åpne, og Menneskesønnen stå ved Guds høire hånd!",
 da: "v55 Men fuld af Helligånden stirrede Stefanus mod himlen og så Guds herlighed og Jesus stående ved Guds højre hånd, v56 og han sagde: »Jeg ser himlene åbne og Menneskesønnen stå ved Guds højre hånd.«",
 },
 "Acts 8:12-21": {
 es: " Mas cuando creyeron á Felipe, que anunciaba el evangelio del reino de Dios y el nombre de Jesucristo, se bautizaban hombres y mujeres. El mismo Simón creyó también entonces, y bautizándose, se llegó á Felipe: y viendo los milagros y grandes maravillas que se hacían, estaba atónito. Y los apóstoles que estaban en Jerusalem, habiendo oído que Samaria había recibido la palabra de Dios, les enviaron á Pedro y á Juan: Los cuales venidos, oraron por ellos, para que recibiesen el Espíritu Santo; (Porque aun no había descendido sobre ninguno de ellos, mas solamente eran bautizados en el nombre de Jesús.) Entonces les impusieron las manos, y recibieron el Espíritu Santo. Y como vió Simón que por la imposición de las manos de los apóstoles se daba el Espíritu Santo, les ofreció dinero, Diciendo: Dadme también á mí esta potestad, que á cualquiera que pusiere las manos encima, reciba el Espíritu Santo. Entonces Pedro le dijo: Tu dinero perezca contigo, que piensas que el don de Dios se gane por dinero. No tienes tú parte ni suerte en este negocio; porque tu corazón no es recto delante de Dios.",
 fr: "Mais, quand ils eurent cru à Philippe, qui leur annonçait la bonne nouvelle du royaume de Dieu et du nom de Jésus-Christ, hommes et femmes se firent baptiser. Simon lui-même crut, et, après avoir été baptisé, il ne quittait plus Philippe, et il voyait avec étonnement les miracles et les grands prodiges qui s'opéraient. Les apôtres, qui étaient à Jérusalem, ayant appris que la Samarie avait reçu la parole de Dieu, y envoyèrent Pierre et Jean. Ceux-ci, arrivés chez les Samaritains, prièrent pour eux, afin qu'ils reçussent le Saint-Esprit. Car il n'était encore descendu sur aucun d'eux; ils avaient seulement été baptisés au nom du Seigneur Jésus. Alors Pierre et Jean leur imposèrent les mains, et ils reçurent le Saint-Esprit. Lorsque Simon vit que le Saint-Esprit était donné par l'imposition des mains des apôtres, il leur offrit de l'argent, en disant: Accordez-moi aussi ce pouvoir, afin que celui à qui j'imposerai les mains reçoive le Saint-Esprit. Mais Pierre lui dit: Que ton argent périsse avec toi, puisque tu as cru que le don de Dieu s'acquérait à prix d'argent! Il n'y a pour toi ni part ni lot dans cette affaire, car ton coeur n'est pas droit devant Dieu.",
 pt: "Mas, quando creram em Filipe, que lhes pregava acerca do reino de Deus e do nome de Jesus, batizavam-se homens e mulheres. E creu até o próprio Simão e, sendo batizado, ficou de contínuo com Filipe; e admirava-se, vendo os sinais e os grandes milagres que se faziam. Os apóstolos, pois, que estavam em Jerusalém, tendo ouvido que os da Samária haviam recebido a palavra de Deus, enviaram-lhes Pedro e João; os quais, tendo descido, oraram por eles, para que recebessem o Espírito Santo. Porque sobre nenhum deles havia ele descido ainda; mas somente tinham sido batizados em nome do Senhor Jesus. Então lhes impuseram as mãos, e eles receberam o Espírito Santo. Quando Simão viu que pela imposição das mãos dos apóstolos se dava o Espírito Santo, ofereceu-lhes dinheiro, dizendo: Dai-me também a mim esse poder, para que aquele sobre quem eu impuser as mãos, receba o Espírito Santo. Mas disse-lhe Pedro: Vá tua prata contigo à perdição, pois cuidaste adquirir com dinheiro o dom de Deus. Tu não tens parte nem sorte neste ministério, porque o teu coração não é reto diante de Deus.",
 sv: "Men nu, då de satte tro till Filippus, som förkunnade evangelium om Guds rike och om Jesu Kristi namn, läto de döpa sig, både män och kvinnor. Ja, Simon själv kom till tro; och sedan han hade blivit döpt, höll han sig ständigt till Filippus. Och när han såg de stora tecken och kraftgärningar som denne gjorde, betogs han av häpnad. Då nu apostlarna i Jerusalem fingo höra att Samarien hade tagit emot Guds ord, sände de dit Petrus och Johannes. Och när dessa kommo ditned, bådo de för dem, att de måtte undfå helig ande; ty helig ande hade ännu icke fallit på någon av dem, utan de voro allenast döpta i Herren Jesu namn. De lade då händerna på dem, och de undfingo helig ande. När då Simon såg att det var genom apostlarnas handpåläggning som Anden blev given, bjöd han dem penningar och sade: »Given ock mig den makten, så att var och en som jag lägger händerna på undfår helig ande.» Då sade Petrus till honom: »Må dina penningar med dig själv gå i fördärvet, eftersom du menar att Guds gåva kan köpas för penningar. Du har ingen del eller lott i det som här är fråga om, ty ditt hjärta är icke rättsinnigt inför Gud.",
 no: "Men da de nu trodde Filip, som forkynte dem evangeliet om Guds rike og Jesu Kristi navn, så lot de sig døpe, både menn og kvinner. Og Simon tok ved troen han også, og da han var blitt døpt, holdt han sig nær til Filip, og da han så de kraftige gjerninger og tegn som blev gjort, blev han ute av sig selv av forundring. Da nu apostlene i Jerusalem fikk høre at Samaria hadde tatt imot Guds ord, sendte de Peter og Johannes til dem; disse kom ned og bad for dem, forat de skulde få den Hellige Ånd; for Ånden var ennu ikke falt på nogen av dem, de var bare døpt til den Herre Jesu navn. De la da sine hender på dem, og de fikk den Hellige Ånd. Men da Simon så at Ånden blev gitt ved apostlenes håndspåleggelse, kom han til dem med penger og sa: Gi også mig denne makt at den som jeg legger mine hender på, må få den Hellige Ånd! Men Peter sa til ham: Ditt sølv være forbannet, både det og du selv, fordi du tenkte å kjøpe Guds gave for penger! Du har ikke del eller lodd i dette ord; for ditt hjerte er ikke rett for Gud.",
 da: "v12 Men da de nu troede Filip, der forkyndte evangeliet om Guds rige og om Jesu Kristi navn, lod de sig døbe, både mænd og kvinder. v13 Selv Simon kom til tro, og da han var blevet døbt, sluttede han sig til Filip, og han var slået af undren, da han så de tegn og store, kraftige gerninger, der skete. v14 Da apostlene i Jerusalem hørte, at Samaria havde taget imod Guds ord, sendte de Peter og Johannes ned til dem. v15 De kom derned og bad for dem, om at de måtte få Helligånden. v16 For Helligånden var endnu ikke faldet på nogen af dem; de var kun døbt i Herren Jesu navn. v17 De lagde så hænderne på dem, og de fik Helligånden. v18 Da Simon så, at det var ved apostlenes håndspålæggelse, at Ånden blev givet, tilbød han dem penge v19 og sagde: »Giv også mig den magt, så at den, jeg lægger hænderne på, får Helligånden.« v20 Men Peter sagde til ham: »Gid dit sølv må forgå og du med det, fordi du tror, at du kan købe Guds gave for penge. v21 Du har ikke lod og del i dette, for dit hjerte er ikke rent i Guds øjne.",
 },
 "Acts 10:38": {
 es: " Cuanto á Jesús de Nazaret; cómo le ungió Dios de Espíritu Santo y de potencia; el cual anduvo haciendo bienes, y sanando á todos los oprimidos del diablo; porque Dios era con él.",
 fr: "vous savez comment Dieu a oint du Saint-Esprit et de force Jésus de Nazareth, qui allait de lieu en lieu faisant du bien et guérissant tous ceux qui étaient sous l'empire du diable, car Dieu était avec lui.",
 pt: "concernente a Jesus de Nazaré, como Deus o ungiu com o Espírito Santo e com poder; o qual andou por toda parte, fazendo o bem e curando a todos os oprimidos do Diabo, porque Deus era com ele.",
 sv: "förkunnelsen om Jesus från Nasaret och om huru Gud hade smort honom med helig ande och kraft, honom som vandrade omkring och gjorde gott och botade alla som voro under djävulens våld; ty Gud var med honom.",
 no: "hvorledes Gud salvet Jesus fra Nasaret med den Hellige Ånd og kraft, han som gikk omkring og gjorde vel og helbredet alle som var overveldet av djevelen, fordi Gud var med ham.",
 da: "v38 det var med Jesus fra Nazaret, hvordan Gud salvede ham med Helligånd og kraft, han, som drog omkring og gjorde godt og helbredte alle, der var under Djævelens herredømme; for Gud var med ham.",
 },
 "Acts 10:40-41": {
 es: " A éste levantó Dios al tercer día, é hizo que apareciese manifiesto, No á todo el pueblo, sino á los testigos que Dios antes había ordenado, es á saber, á nosotros que comimos y bebimos con él, después que resucitó de los muertos.",
 fr: "Dieu l'a ressuscité le troisième jour, et il a permis qu'il apparût, non à tout le peuple, mais aux témoins choisis d'avance par Dieu, à nous qui avons mangé et bu avec lui, après qu'il fut ressuscité des morts.",
 pt: "A este ressuscitou Deus ao terceiro dia e lhe concedeu que se manifestasse, não a todo povo, mas às testemunhas predeterminadas por Deus, a nós, que comemos e bebemos juntamente com ele depois que ressurgiu dentre os mortos;",
 sv: "Men honom har Gud uppväckt på tredje dagen och låtit honom bliva uppenbar, väl icke för allt folket, men för oss, som redan förut av Gud hade blivit utvalda till vittnen, och som åto och drucko med honom, sedan han hade uppstått från de döda.",
 no: "Ham opvakte Gud på den tredje dag, og gav ham å åpenbare sig, ikke for hele folket, men for de vidner som var forut valgt av Gud, for oss, vi som åt og drakk sammen med ham efterat han var opstanden fra de døde.",
 da: "v40 Ham lod Gud opstå på den tredje dag og lod ham træde synligt frem, v41 ikke for hele folket, men for de vidner, som Gud i forvejen havde udvalgt, for os, der spiste og drak sammen med ham, efter at han var opstået fra de døde.",
 },
 "Acts 14:23": {
 es: " Y habiéndoles constituído ancianos en cada una de las iglesias, y habiendo orado con ayunos, los encomendaron al Señor en el cual habían creído.",
 fr: "Ils firent nommer des anciens dans chaque Eglise, et, après avoir prié et jeûné, ils les recommandèrent au Seigneur, en qui ils avaient cru.",
 pt: "E, havendo-lhes feito eleger anciãos em cada igreja e orado com jejuns, os encomendaram ao Senhor em quem haviam crido.",
 sv: "Därefter utvalde de åt dem »äldste» för var särskild församling och anbefallde dem efter bön och fastor åt Herren, som de nu trodde på.",
 no: "Og efterat de hadde valgt eldste for dem i hver menighet, overgav de dem med bønn og faste til den Herre som de hadde satt sin tro til.",
 da: "v23 I hver menighed indsatte de ældste for dem, og under bøn og faste befalede de dem til Herren, som de var kommet til tro på.",
 },
 "Acts 15:4, 22-23": {
 es: " Y llegados á Jerusalem, fueron recibidos de la iglesia y de los apóstoles y de los ancianos: y refirieron todas las cosas que Dios había hecho con ellos. Entonces pareció bien á los apóstoles y á los ancianos, con toda la iglesia, elegir varones de ellos, y enviarlos á Antioquía con Pablo y Bernabé: á Judas que tenía por sobrenombre Barsabas, y á Silas, varones principales entre los hermanos; Y escribir por mano de ellos: Los apóstoles y los ancianos y los hermanos, á los hermanos de los Gentiles que están en Antioquía, y en Siria, y en Cilicia, salud:",
 fr: "Arrivés à Jérusalem, ils furent reçus par l'Eglise, les apôtres et les anciens, et ils racontèrent tout ce que Dieu avait fait avec eux. Alors il parut bon aux apôtres et aux anciens, et à toute l'Eglise, de choisir parmi eux et d'envoyer à Antioche, avec Paul et Barnabas, Jude appelé Barsabas et Silas, hommes considérés entre les frères. Ils les chargèrent d'une lettre ainsi conçue: Les apôtres, les anciens, et les frères, aux frères d'entre les païens, qui sont à Antioche, en Syrie, et en Cilicie, salut!",
 pt: "E, quando chegaram a Jerusalém, foram recebidos pela igreja e pelos apóstolos e anciãos, e relataram tudo quanto Deus fizera por meio deles. Então pareceu bem aos apóstolos e aos anciãos com toda a igreja escolher homens dentre eles e enviá-los a Antioquia com Paulo e Barnabé, a saber: Judas, chamado Barsabás, e Silas, homens influentes entre os irmãos. E por intermédio deles escreveram o seguinte: Os apóstolos e os anciãos, irmãos, aos irmãos dentre os gentios em Antioquia, na Síria e na Cicília, saúde.",
 sv: "När de sedan kommo fram till Jerusalem, mottogos de av församlingen och av apostlarna och de äldste och omtalade huru stora ting Gud hade gjort med dem. Därefter beslöto apostlarna och de äldste, tillika med hela församlingen, att bland sig utvälja några män, som jämte Paulus och Barnabas skulle sändas till Antiokia; och de valde Judas, som kallades Barsabbas, och Silas, vilka bland bröderna voro ledande män. Och man översände genom dem följande skrivelse: »Apostlarna och de äldste, edra bröder, hälsa eder, I bröder av hednisk börd, som bon i Antiokia, Syrien och Cilicien.",
 no: "Og da de kom frem til Jerusalem, blev de mottatt av menigheten og apostlene og de eldste, og de fortalte hvor store ting Gud hadde gjort ved dem. Da vedtok apostlene og de eldste sammen med hele menigheten å velge nogen menn iblandt sig og sende dem til Antiokia sammen med Paulus og Barnabas; det var Judas med tilnavnet Barsabbas og Silas, som var høit aktede menn blandt brødrene, og de skrev således med dem: Apostlene og eldste-brødrene hilser brødrene av hedningene i Antiokia og Syria og Kilikia.",
 da: "v4 Ved ankomsten til Jerusalem blev de modtaget af menigheden og af apostlene og de ældste, og de fortalte om alt, hvad Gud havde gjort gennem dem. ... v22 Da besluttede apostlene og de ældste sammen med hele menigheden at udvælge nogle mænd iblandt sig og sende dem til Antiokia sammen med Paulus og Barnabas. Det blev Judas, med tilnavnet Barsabbas, og Silas, som var ledende mænd blandt brødrene. v23 De fik denne skrivelse med: »Apostlene og de ældste, jeres brødre, hilser brødrene af hedensk herkomst i Antiokia og Syrien og Kilikien.",
 },
 "Acts 16:4": {
 es: " Y como pasaban por las ciudades, les daban que guardasen los decretos que habían sido determinados por los apóstoles y los ancianos que estaban en Jerusalem.",
 fr: "En passant par les villes, ils recommandaient aux frères d'observer les décisions des apôtres et des anciens de Jérusalem.",
 pt: "Quando iam passando pelas cidades, entregavam aos irmãos, para serem observadas, as decisões que haviam sido tomadas pelos apóstolos e anciãos em Jerusalém.",
 sv: "Och när de sedan foro genom städerna, meddelade de församlingarna till efterföljd de stadgar som voro fastställda av apostlarna och de äldste i Jerusalem.",
 no: "Efter som de nu drog fra by til by, påla de brødrene å holde de bud som var vedtatt av apostlene og de eldste i Jerusalem.",
 da: "v4 I de byer, de rejste igennem, meddelte de dem de bestemmelser, som apostlene og de ældste i Jerusalem havde vedtaget, og pålagde dem at overholde dem.",
 },
 "James 1:5": {
 es: " Y si alguno de vosotros tiene falta de sabiduría, demándela á Dios, el cual da á todos abundantemente, y no zahiere; y le será dada.",
 fr: "Si quelqu'un d'entre vous manque de sagesse, qu'il la demande à Dieu, qui donne à tous simplement et sans reproche, et elle lui sera donnée.",
 pt: "Ora, se algum de vós tem falta de sabedoria, peça-a a Deus, que a todos dá liberalmente e não censura, e ser-lhe-á dada.",
 sv: "I som med Guds makt bliven genom tro bevarade till en frälsning som är beredd för att uppenbaras i den yttersta tiden.",
 no: "Men dersom nogen av eder mangler visdom, da bede han Gud, han som gir alle villig og uten onde ord, og den skal gis ham.",
 da: "v5 Men hvis nogen af jer står tilbage i visdom, skal han bede om at få den af Gud, som giver alle rundhåndet og uden bebrejdelser, og så vil han få den.",
 },
 "James 2:17-20": {
 es: " Así también la fe, si no tuviere obras, es muerta en sí misma. Pero alguno dirá: Tú tienes fe, y yo tengo obras: muéstrame tu fe sin tus obras, y yo te mostraré mi fe por mis obras. Tú crees que Dios es uno; bien haces: también los demonios creen, y tiemblan. ¿Mas quieres saber, hombre vano, que la fe sin obras es muerta?",
 fr: "Il en est ainsi de la foi: si elle n'a pas les oeuvres, elle est morte en elle-même. Mais quelqu'un dira: Toi, tu as la foi; et moi, j'ai les oeuvres. Montre-moi ta foi sans les oeuvres, et moi, je te montrerai la foi par mes oeuvres. Tu crois qu'il y a un seul Dieu, tu fais bien; les démons le croient aussi, et ils tremblent. Veux-tu savoir, ô homme vain, que la foi sans les oeuvres est inutile?",
 pt: "Assim também a fé, se não tiver obras, é morta em si mesma. Mas dirá alguém: Tu tens fé, e eu tenho obras; mostra-me a tua fé sem as obras, e eu te mostrarei a minha fé pelas minhas obras. Crês tu que Deus é um só? Fazes bem; os demônios também o crêem, e estremecem. Mas queres saber, ó homem vão, que a fé sem as obras é estéril?",
 sv: "Bevisen var man ära, älsken bröderna, »frukten Gud, ären konungen». I tjänare, underordnen eder edra herrar med all fruktan, icke allenast de goda och milda, utan också de obilliga. Ty det är välbehagligt för Gud, om någon, med honom för ögonen, tåligt uthärdar sina vedervärdigheter, när han får lida oförskylt. Ty vad berömligt är däri att I bevisen tålamod, när I för edra synders skull fån uppbära hugg och slag? Men om I bevisen tålamod, när I fån lida för goda gärningars skull, då är detta välbehaglig för Gud.",
 no: "Således og med troen: har den ikke gjerninger, er den død i sig selv. Men en kan si: Du har tro, og jeg har gjerninger. Vis mig din tro uten gjerninger, og jeg vil vise dig min tro av mine gjerninger! Du tror at Gud er én; du gjør vel; djevlene tror det også og skjelver. Og vil du vite det, du dårlige menneske, at troen uten gjerninger er unyttig?",
 da: "17 Sådan er det også med troen: i sig selv, uden gerninger, er den død. 18 Måske vil nogen sige: »Du har tro, jeg har gerninger.« Vis mig din tro uden gerninger, så skal jeg med mine gerninger vise dig min tro. 19 Du tror, at Gud er én. Det gør du ret i. Det tror de onde ånder også – og skælver. 20 Tåbelige menneske, vil du da ikke indse, at tro uden gerninger er ufrugtbar?",
 },
 "James 3:17": {
 es: " Mas la sabiduría que es de lo alto, primeramente es pura, después pacífica, modesta, benigna, llena de misericordia y de buenos frutos, no juzgadora, no fingida.",
 fr: "La sagesse d'en haut est premièrement pure, ensuite pacifique, modérée, conciliante, pleine de miséricorde et de bons fruits, exempte de duplicité, d'hypocrisie.",
 pt: "Mas a sabedoria que vem do alto é, primeiramente, pura, depois pacífica, moderada, tratável, cheia de misericórdia e de bons frutos, sem parcialidade, e sem hipocrisia.",
 sv: "Ty det är bättre att lida för goda gärningar, om så skulle vara Guds vilja, än att lida för onda.",
 no: "Men den visdom som er ovenfra, er først og fremst ren, dernæst fredsommelig, rimelig, eftergivende, full av barmhjertighet og gode frukter, uten tvil, uten skrømt.",
 da: "Men visdommen ovenfra er først og fremmest ren, og desuden fredselskende, mild, omgængelig, rig på barmhjertighed og gode frugter, upartisk og uden hykleri.",
 },
 "Acts 26:20": {
 es: " Antes anuncié primeramente á los que están en Damasco, y Jerusalem, y por toda la tierra de Judea, y á los Gentiles, que se arrepintiesen y se convirtiesen á Dios, haciendo obras dignas de arrepentimiento.",
 fr: "à ceux de Damas d'abord, puis à Jérusalem, dans toute la Judée, et chez les païens, j'ai prêché la repentance et la conversion à Dieu, avec la pratique d'oeuvres dignes de la repentance.",
 pt: "antes anunciei primeiramente aos que estão em Damasco, e depois em Jerusalém, e por toda a terra da Judéia e também aos gentios, que se arrependessem e se convertessem a Deus, praticando obras dignas de arrependimento.",
 sv: "utan predikade först för dem som voro i Damaskus och i Jerusalem, och sedan över hela judiska landet och för hedningarna, att de skulle göra bättring och omvända sig till Gud och göra sådana gärningar som tillhöra bättringen.",
 no: "men både for dem i Damaskus først og for Jerusalem og i hele Judeas land og for hedningene forkynte jeg at de skulde omvende sig og komme tilbake til Gud og gjøre gjerninger som er omvendelsen verdige.",
 da: "v20 Men først for dem i Damaskus og i Jerusalem og i hele Judæas land og for hedningerne har jeg prædiket, at de skulle omvende sig og vende om til Gud og gøre de gerninger, som omvendelsen kræver.",
 },
 "James 1:22": {
 es: " Mas sed hacedores de la palabra, y no tan solamente oidores, engañándoos á vosotros mismos.",
 fr: "Mettez en pratique la parole, et ne vous bornez pas à l'écouter, en vous trompant vous-mêmes par de faux raisonnements.",
 pt: "E sede cumpridores da palavra e não somente ouvintes, enganando-vos a vós mesmos.",
 sv: "Renen edra själar, i lydnad för sanningen, till oskrymtad broderlig kärlek, och älsken varandra av hjärtat med uthållig kärlek,",
 no: "Men vær ordets gjørere, og ikke bare dets hørere, idet I dårer eder selv.",
 da: "Men vær ordets gørere, ikke blot dets hørere, ellers bedrager I jer selv.",
 },
 "Jude 1:3": {
 es: " Amados, por la gran solicitud que tenía de escribiros de la común salud, me ha sido necesario escribiros amonestándoos que contendáis eficazmente por la fe que ha sido una vez dada á los santos.",
 fr: "Bien-aimés, comme je désirais vivement vous écrire au sujet de notre salut commun, je me suis senti obligé de le faire afin de vous exhorter à combattre pour la foi qui a été transmise aux saints une fois pour toutes.",
 pt: "Amados, enquanto eu empregava toda a diligência para escrever-vos acerca da salvação que nos é comum, senti a necessidade de vos escrever, exortando-vos a pelejar pela fé que de uma vez para sempre foi entregue aos santos.",
 sv: "Mina älskade, då jag nu med all iver har tagit mig för att skriva till eder om vår gemensamma frälsning, finner jag det nödigt att i min skrivelse förmana eder att kämpa för den tro som en gång för alla har blivit meddelad åt de heliga.",
 no: "I elskede! mens jeg gjorde mig all flid for å skrive til eder om vår felles frelse, så jeg mig nødt til å skrive til eder med formaning om å stride for den tro som én gang er overgitt til de hellige.",
 da: "Mine kære, mens jeg har været ivrigt optaget af at skrive til jer om vor fælles frelse, har jeg fundet det nødvendigt at skrive til jer for at formane jer til at kæmpe for den tro, som én gang for alle er overdraget de hellige.",
 },
 "Jude 1:6": {
 es: " Y á los ángeles que no guardaron su dignidad, mas dejaron su habitación, los ha reservado debajo de oscuridad en prisiones eternas hasta el juicio del gran día:",
 fr: "qu'il a réservé pour le jugement du grand jour, enchaînés éternellement par les ténèbres, les anges qui n'ont pas gardé leur dignité, mais qui ont abandonné leur propre demeure;",
 pt: "aos anjos que não guardaram o seu principado, mas deixaram a sua própria habitação, ele os tem reservado em prisões eternas na escuridão para o juízo do grande dia,",
 sv: "så ock därom, att de änglar som icke behöllo sin furstehöghet, utan övergåvo sin boning, hava av honom med eviga bojor blivit förvarade i mörker till den stora dagens dom.",
 no: "og om at de engler som ikke tok vare på sin høie stand, men forlot sin egen bolig, dem holder han i varetekt i evige lenker under mørket til dommen på den store dag;",
 da: "og de engle, som ikke tog vare på deres høje hverv, men forlod deres bolig, dem har han holdt i evige lænker i mørket indtil dommen på den store dag.",
 },
 "Acts 19:1-6": {
 es: " Y ACONTECIÓ que entre tanto que Apolos estaba en Corinto, Pablo, andadas las regiones superiores, vino á Efeso, y hallando ciertos discípulos, Díjoles: ¿Habéis recibido el Espíritu Santo después que creísteis? Y ellos le dijeron: Antes ni aun hemos oído si hay Espíritu Santo. Entonces dijo: ¿En qué pues sois bautizados? Y ellos dijeron: En el bautismo de Juan. Y dijo Pablo: Juan bautizó con bautismo de arrepentimiento, diciendo al pueblo que creyesen en el que había de venir después de él, es á saber, en Jesús el Cristo. Oído que hubieron esto, fueron bautizados en el nombre del Señor Jesús. Y habiéndoles impuesto Pablo las manos, vino sobre ellos el Espíritu Santo; y hablaban en lenguas, y profetizaban.",
 fr: "Pendant qu'Apollos était à Corinthe, Paul, après avoir parcouru les hautes provinces de l'Asie, arriva à Ephèse. Ayant rencontré quelques disciples, il leur dit: Avez-vous reçu le Saint-Esprit, quand vous avez cru? Ils lui répondirent: Nous n'avons pas même entendu dire qu'il y ait un Saint-Esprit. Il dit: De quel baptême avez-vous donc été baptisés? Et ils répondirent: Du baptême de Jean. Alors Paul dit: Jean a baptisé du baptême de repentance, disant au peuple de croire en celui qui venait après lui, c'est-à-dire, en Jésus. Sur ces paroles, ils furent baptisés au nom du Seigneur Jésus. Lorsque Paul leur eut imposé les mains, le Saint-Esprit vint sur eux, et ils parlaient en langues et prophétisaient.",
 pt: "E sucedeu que, enquanto Apolo estava em Corinto, Paulo tendo atravessado as regiões mais altas, chegou a Éfeso e, achando ali alguns discípulos, perguntou-lhes: Recebestes vós o Espírito Santo quando crestes? Responderam-lhe eles: Não, nem sequer ouvimos que haja Espírito Santo. Tornou-lhes ele: Em que fostes batizados então? E eles disseram: No batismo de João. Mas Paulo respondeu: João administrou o batismo do arrependimento, dizendo ao povo que cresse naquele que após ele havia de vir, isto é, em Jesus. Quando ouviram isso, foram batizados em nome do Senhor Jesus. Havendo-lhes Paulo imposto as mãos, veio sobre eles o Espírito Santo, e falavam em línguas e profetizavam.",
 sv: "Medan Apollos var i Korint, kom Paulus, sedan han hade farit genom de övre delarna av landet, ned till Efesus. Där träffade han några lärjungar. Och han frågade dessa: »Undfingen I helig ande, när I kommen till tro?» De svarade honom: »Nej, vi hava icke ens hört att helig ande är given.» Han frågade: »Vilken döpelse bleven I då döpta med?» De svarade: »Vi döptes med Johannes' döpelse» Då sade Paulus: »Johannes' döpelse var en döpelse till bättring; och han sade därvid till folket, att det var på den som skulle komma efter honom, det är på Jesus, som de skulle tro.» Sedan de hade hört detta, läto de döpa sig i Herren Jesu namn. Och när Paulus lade händerna på dem, kom den helige Ande över dem, och de talade tungomål och profeterade.",
 no: "Mens Apollos var i Korint, skjedde det at Paulus kom til Efesus, efterat han hadde vandret igjennem de øvre landskaper. Der fant han nogen disipler og sa til dem: Fikk I den Hellige Ånd da I kom til troen? De svarte ham: Vi har ikke engang hørt om den Hellige Ånd er kommet. Han sa da: Hvad dåp blev I da døpt med? De sa: Med Johannes' dåp. Da sa Paulus: Johannes, han døpte med omvendelses dåp, idet han sa til folket at de skulde tro på den som kom efter ham, det er på Jesus. Da de hørte dette, lot de sig døpe til den Herre Jesu navn, og da Paulus la hendene på dem, kom den Hellige Ånd over dem, og de talte med tunger og profetiske ord.",
 da: "1 Mens Apollos var i Korinth, kom Paulus efter en rejse gennem landene i det indre af provinsen til Efesos. Dér traf han nogle disciple 2 og spurgte dem: »Fik I Helligånden, da I kom til tro?« De svarede: »Vi har ikke engang hørt, at der er en Helligånd.« 3 »Hvad blev I da døbt med?« spurgte Paulus, og de svarede: »Med Johannes' dåb.« 4 Da sagde Paulus: »Johannes døbte med omvendelsesdåb og sagde til folket, at de skulle tro på ham, der fulgte efter, det vil sige på Jesus.« 5 Da de hørte det, blev de døbt i Herren Jesu navn. 6 Og da Paulus lagde hænderne på dem, kom Helligånden over dem, og de talte i tunger og profeterede.",
 },
 "Acts 20:28-30": {
 es: " Por tanto mirad por vosotros, y por todo el rebaño en que el Espíritu Santo os ha puesto por obispos, para apacentar la iglesia del Señor, la cual ganó por su sangre. Porque yo sé que después de mi partida entrarán en medio de vosotros lobos rapaces, que no perdonarán al ganado; Y de vosotros mismos se levantarán hombres que hablen cosas perversas, para llevar discípulos tras sí.",
 fr: "Prenez donc garde à vous-mêmes, et à tout le troupeau sur lequel le Saint-Esprit vous a établis évêques, pour paître l'Eglise du Seigneur, qu'il s'est acquise par son propre sang. Je sais qu'il s'introduira parmi vous, après mon départ, des loups cruels qui n'épargneront pas le troupeau, et qu'il s'élèvera du milieu de vous des hommes qui enseigneront des choses pernicieuses, pour entraîner les disciples après eux.",
 pt: "Cuidai pois de vós mesmos e de todo o rebanho sobre o qual o Espírito Santo vos constituiu bispos, para apascentardes a igreja de Deus, que ele adquiriu com seu próprio sangue. Eu sei que depois da minha partida entrarão no meio de vós lobos cruéis que não pouparão rebanho, e que dentre vós mesmos se levantarão homens, falando coisas perversas para atrair os discípulos após si.",
 sv: "Så haven nu akt på eder själva och på hela den hjord i vilken den helige Ande har satt eder till föreståndare, till att vara herdar för Guds församling, som han har vunnit med sitt eget blod. Jag vet, att sedan jag har skilts från eder svåra ulvar skola komma in bland eder, och att de icke skola skona hjorden. Ja, bland eder själva skola män uppträda, som tala vad förvänt är, för att locka lärjungarna att följa sig.",
 no: "Så gi da akt på eder selv, og på hele den hjord som den Hellige Ånd satte eder til tilsynsmenn i, for å vokte Guds menighet, som han vant sig ved sitt eget blod! Jeg vet at efter min bortgang skal det komme glupende ulver inn blandt eder, som ikke skåner hjorden; ja, blandt eder selv skal det fremstå menn som fører forvendt tale for å lokke disiplene efter sig.",
 da: "28 Tag vare på jer selv og på hele hjorden; i den har Helligånden sat jer som tilsynsmænd, for at I kan være hyrder for Guds kirke, som han har vundet sig med sit eget blod. 29 Jeg ved, at når jeg er borte, vil der komme glubske ulve til jer, som ikke vil skåne hjorden. 30 Ja, blandt jer selv vil der fremstå mænd, som fører falsk tale for at få disciplene med sig.",
 },
 "Ephesians 1:4": {
 es: " Según nos escogió en él antes de la fundación del mundo, para que fuésemos santos y sin mancha delante de él en amor;",
 fr: "En lui Dieu nous a élus avant la fondation du monde, pour que nous soyons saints et irrépréhensibles devant lui,",
 pt: "como também nos elegeu nele antes da fundação do mundo, para sermos santos e irrepreensíveis diante dele em amor;",
 sv: "såsom han ju, förrän världens grund var lagd, har utvalt oss i honom till att vara heliga och ostraffliga inför sig.",
 no: "likesom han utvalgte oss i ham før verdens grunnvoll blev lagt, forat vi skulde være hellige og ulastelige for hans åsyn,",
 da: "For før verdens grundvold blev lagt, har Gud i ham udvalgt os til at stå hellige og uden fejl for hans ansigt i kærlighed.",
 },
 "Ephesians 1:10": {
 es: " De reunir todas las cosas en Cristo, en la dispensación del cumplimiento de los tiempos, así las que están en los cielos, como las que están en la tierra:",
 fr: "pour le mettre à exécution lorsque les temps seraient accomplis, de réunir toutes choses en Christ, celles qui sont dans les cieux et celles qui sont sur la terre.",
 pt: "para a dispensação da plenitude dos tempos, de fazer convergir em Cristo todas as coisas, tanto as que estão nos céus como as que estão na terra,",
 sv: "om en ordning som i tidernas fullbordan skulle komma till stånd, det beslutet att i Kristus sammanfatta allt som finnes i himmelen och på jorden.",
 no: "om en husholdning i tidenes fylde: at han atter vilde samle alt til ett i Kristus, både det som er i himlene, og det som er på jorden;",
 da: "om den frelsesplan for tidernes fylde: at sammenfatte alt i Kristus, både det himmelske og det jordiske.",
 },
 "Ephesians 1:20": {
 es: " La cual obró en Cristo, resucitándole de los muertos, y colocándole á su diestra en los cielos,",
 fr: "Il l'a déployée en Christ, en le ressuscitant des morts, et en le faisant asseoir à sa droite dans les lieux célestes,",
 pt: "que operou em Cristo, ressuscitando-o dentre os mortos e fazendo-o sentar-se à sua direita nos céus,",
 sv: "varmed han har verkat i Kristus, i det att han uppväckte honom från de döda och satte honom på sin högra sida i den himmelska världen,",
 no: "som han viste på Kristus da han opvakte ham fra de døde og satte ham ved sin høire hånd i himmelen,",
 da: "Den virkede i Kristus, da han oprejste ham fra de døde og satte ham ved sin højre hånd i himlen,",
 },
 "Ephesians 2:19-21": {
 es: " Así que ya no sois extranjeros ni advenedizos, sino juntamente ciudadanos con los santos, y domésticos de Dios; Edificados sobre el fundamento de los apóstoles y profetas, siendo la principal piedra del ángulo Jesucristo mismo; En el cual, compaginado todo el edificio, va creciendo para ser un templo santo en el Señor:",
 fr: "Ainsi donc, vous n'êtes plus des étrangers, ni des gens du dehors; mais vous êtes concitoyens des saints, gens de la maison de Dieu. Vous avez été édifiés sur le fondement des apôtres et des prophètes, Jésus-Christ lui-même étant la pierre angulaire. En lui tout l'édifice, bien coordonné, s'élève pour être un temple saint dans le Seigneur.",
 pt: "Assim, pois, não sois mais estrangeiros, nem forasteiros, antes sois concidadãos dos santos e membros da família de Deus, edificados sobre o fundamento dos apóstolos e dos profetas, sendo o próprio Cristo Jesus a principal pedra da esquina; no qual todo o edifício bem ajustado cresce para templo santo no Senhor,",
 sv: "Alltså ären I nu icke mer främlingar och gäster, utan I haven medborgarskap med de heliga och ären Guds husfolk, uppbyggda på apostlarnas och profeternas grundval, där hörnstenen är Kristus Jesus själv, i vilken allt det som uppbygges bliver sammanslutet och så växer upp till ett heligt tempel i Herren.",
 no: "Så er I da ikke lenger fremmede og utlendinger, men I er de helliges medborgere og Guds husfolk, I som er bygget op på apostlenes og profetenes grunnvoll, mens hjørnestenen er Kristus Jesus selv, i hvem hver bygning føies sammen og vokser til et hellig tempel i Herren,",
 da: "19 I er altså ikke længere fremmede og udlændinge. I er de helliges medborgere og hører til Guds husstand. 20 I er bygget på apostlenes og profeternes grundvold med Kristus Jesus selv som hovedhjørnesten. 21 I ham holdes hele bygningen sammen og vokser til et helligt tempel i Herren,",
 },
 "Ephesians 3:5": {
 es: " El cual misterio en los otros siglos no se dió á conocer á los hijos de los hombres como ahora es revelado á sus santos apóstoles y profetas en el Espíritu:",
 fr: "Il n'a pas été manifesté aux fils des hommes dans les autres générations, comme il a été révélé maintenant par l'Esprit aux saints apôtres et prophètes de Christ.",
 pt: "o qual em outras gerações não foi manifestado aos filhos dos homens, como se revelou agora no Espírito aos seus santos apóstolos e profetas,",
 sv: "som under förgångna släktens tider icke hade blivit kungjord för människors barn, såsom den nu genom andeingivelse har blivit uppenbarad för hans heliga apostlar och profeter.",
 no: "som i de forrige tidsaldre ikke er blitt kunngjort for menneskenes barn således som den nu er åpenbaret for hans hellige apostler og profeter i Ånden:",
 da: "som i tidligere slægtled ikke er blevet gjort kendt for menneskenes børn, som den nu ved Ånden er blevet åbenbaret for hans hellige apostle og profeter:",
 },
 "Ephesians 3:9": {
 es: " Y de aclarar á todos cuál sea la dispensación del misterio escondido desde los siglos en Dios, que crió todas las cosas.",
 fr: "et de mettre en lumière quelle est la dispensation du mystère caché de tout temps en Dieu qui a créé toutes choses,",
 pt: "e demonstrar a todos qual seja a dispensação do mistério que desde os séculos esteve oculto em Deus, que tudo criou,",
 sv: "och att lägga i dagen huru det rådslut har blivit utfört, som tidsåldrarna igenom hade såsom en hemlighet varit fördolt i Gud, alltings skapare.",
 no: "og å oplyse alle om hvorledes husholdningen er med den hemmelighet som har vært skjult fra evige tider i Gud, som har skapt alt,",
 da: "og at bringe lys over, hvordan den hemmelighed, der fra evighed af var skjult i Gud, altings skaber, skulle forvaltes,",
 },
 "Ephesians 4:5": {
 es: " Un Señor, una fe, un bautismo,",
 fr: "il y a un seul Seigneur, une seule foi, un seul baptême,",
 pt: "um só Senhor, uma só fé, um só batismo;",
 sv: "en Herre, en tro, ett dop, en Gud, som är allas Fader,",
 no: "én Herre, én tro, én dåp,",
 da: "én Herre, én tro, én dåb,",
 },
 "Ephesians 4:11-14": {
 es: " Y él mismo dió unos, ciertamente apóstoles; y otros, profetas; y otros, evangelistas; y otros, pastores y doctores; Para perfección de los santos, para la obra del ministerio, para edificación del cuerpo de Cristo; Hasta que todos lleguemos á la unidad de la fe y del conocimiento del Hijo de Dios, á un varón perfecto, á la medida de la edad de la plenitud de Cristo: Que ya no seamos niños fluctuantes, y llevados por doquiera de todo viento de doctrina, por estratagema de hombres que, para engañar, emplean con astucia los artificios del error:",
 fr: "Et il a donné les uns comme apôtres, les autres comme prophètes, les autres comme évangélistes, les autres comme pasteurs et docteurs, pour le perfectionnement des saints en vue de l'oeuvre du ministère et de l'édification du corps de Christ, jusqu'à ce que nous soyons tous parvenus à l'unité de la foi et de la connaissance du Fils de Dieu, à l'état d'homme fait, à la mesure de la stature parfaite de Christ, afin que nous ne soyons plus des enfants, flottants et emportés à tout vent de doctrine, par la tromperie des hommes, par leur ruse dans les moyens de séduction,",
 pt: "E ele deu uns como apóstolos, e outros como profetas, e outros como evangelistas, e outros como pastores e mestres, tendo em vista o aperfeiçoamento dos santos, para a obra do ministério, para edificação do corpo de Cristo; até que todos cheguemos à unidade da fé e do pleno conhecimento do Filho de Deus, ao estado de homem feito, à medida da estatura da plenitude de Cristo; para que não mais sejamos meninos, inconstantes, levados ao redor por todo vento de doutrina, pela fraudulência dos homens, pela astúcia tendente à maquinação do erro;",
 sv: "Och han gav oss somliga till apostlar, somliga till profeter, somliga till evangelister, somliga till herdar och lärare. Ty han ville göra de heliga skickliga till att utföra sitt tjänarvärv, att uppbygga Kristi kropp, till dess att vi allasammans komma fram till enheten i tron och i kunskapen om Guds Son, till manlig mognad, och så bliva fullvuxna, intill Kristi fullhet. Så skulle vi icke mer vara barn, icke såsom havets vågor drivas omkring av vart vindkast i läran, vid människornas bedrägliga spel, när de illfundigt söka främja villfarelsens listiga anslag.",
 no: "Og det er han som gav oss nogen til apostler, nogen til profeter, nogen til evangelister, nogen til hyrder og lærere, forat de hellige kunde bli fullkommengjort til tjenestegjerning, til Kristi legemes opbyggelse, inntil vi alle når frem til enhet i tro på Guds Sønn og i kjennskap til ham, til manns modenhet, til aldersmålet for Kristi fylde, forat vi ikke lenger skal være umyndige og la oss kaste og drive om av ethvert lærdoms vær ved menneskenes spill, ved kløkt i villfarelsens kunster,",
 da: "11 Og han har givet nogle som apostle, andre som profeter, andre som evangelister, andre som hyrder og lærere, 12 for at udruste de hellige til at gøre tjeneste, så Kristi legeme bygges op, 13 indtil vi alle når frem til enheden i troen og i erkendelsen af Guds søn, til at være et fuldvoksent menneske, en vækst, som kan måles med Kristi fylde, 14 så vi ikke længere skal være umyndige og drives omkring og kastes hid og did af enhver lærdoms vind, ved menneskers terningespil, når de underfundigt forleder til vildfarelse.",
 },
 "Ephesians 6:12": {
 es: " Porque no tenemos lucha contra sangre y carne; sino contra principados, contra potestades, contra señores del mundo, gobernadores de estas tinieblas, contra malicias espirituales en los aires.",
 fr: "Car nous n'avons pas à lutter contre la chair et le sang, mais contre les dominations, contre les autorités, contre les princes de ce monde de ténèbres, contre les esprits méchants dans les lieux célestes.",
 pt: "pois não é contra carne e sangue que temos que lutar, mas sim contra os principados, contra as potestades, conta os príncipes do mundo destas trevas, contra as hostes espirituais da iniqüidade nas regiões celestes.",
 sv: "Ty den kamp vi hava att utkämpa är en kamp icke mot kött och blod, utan mot furstar och väldigheter och världshärskare, som råda här i mörkret, mot ondskans andemakter i himlarymderna.",
 no: "for vi har ikke kamp mot blod og kjød, men mot makter, mot myndigheter, mot verdens herrer i dette mørke, mot ondskapens ånde-hær i himmelrummet.",
 da: "Thi for os står kampen ikke mod kød og blod, men mod myndigheder og magter, mod verdensherskerne i dette mørke, mod ondskabens åndemagter i himmelrummet.",
 },
 "1 Timothy 2:3-6": {
 es: " Porque esto es bueno y agradable delante de Dios nuestro Salvador; El cual quiere que todos los hombres sean salvos, y que vengan al conocimiento de la verdad. Porque hay un Dios, asimismo un mediador entre Dios y los hombres, Jesucristo hombre; El cual se dió á sí mismo en precio del rescate por todos, para testimonio en sus tiempos:",
 fr: "Cela est bon et agréable devant Dieu notre Sauveur, qui veut que tous les hommes soient sauvés et parviennent à la connaissance de la vérité. Car il y a un seul Dieu, et aussi un seul médiateur entre Dieu et les hommes, Jésus-Christ homme, qui s'est donné lui-même en rançon pour tous. C'est là le témoignage rendu en son propre temps,",
 pt: "Pois isto é bom e agradável diante de Deus nosso Salvador, o qual deseja que todos os homens sejam salvos e cheguem ao pleno conhecimento da verdade. Porque há um só Deus, e um só Mediador entre Deus e os homens, Cristo Jesus, homem, o qual se deu a si mesmo em resgate por todos, para servir de testemunho a seu tempo;",
 sv: "Sådant är gott och välbehagligt inför Gud, vår Frälsare, som vill att alla människor skola bliva frälsta och komma till kunskap om sanningen. Ty en enda är Gud, och en enda är medlare emellan Gud och människor: en människa, Kristus Jesus, han som gav sig själv till lösen för alla, varom ock vittnesbördet skulle frambäras, när tiden var inne.",
 no: "For dette er godt og tekkelig for Gud, vår frelser, han som vil at alle mennesker skal bli frelst og komme til sannhets erkjennelse. For det er én Gud og én mellemmann imellem Gud og mennesker, mennesket Kristus Jesus, han som gav sig selv til en løsepenge for alle, et vidnesbyrd i sin tid,",
 da: "Det er godt og værd at efterstræbe i Gud, vor frelsers, øjne, han som vil, at alle mennesker skal frelses og komme til erkendelse af sandheden. For der er én Gud og én formidler mellem Gud og mennesker, mennesket Kristus Jesus, som gav sig selv som løsesum for alle – et vidnesbyrd i rette tid.",
 },
 "1 Timothy 3:1-5": {
 es: " PALABRA fiel: Si alguno apetece obispado, buena obra desea. Conviene, pues, que el obispo sea irreprensible, marido de una mujer, solícito, templado, compuesto, hospedador, apto para enseñar; No amador del vino, no heridor, no codicioso de torpes ganancias, sino moderado, no litigioso, ajeno de avaricia; Que gobierne bien su casa, que tenga sus hijos en sujeción con toda honestidad; (Porque el que no sabe gobernar su casa, ¿cómo cuidará de la iglesia de Dios?)",
 fr: "Cette parole est certaine: Si quelqu'un aspire à la charge d'évêque, il désire une oeuvre excellente. Il faut donc que l'évêque soit irréprochable, mari d'une seule femme, sobre, modéré, réglé dans sa conduite, hospitalier, propre à l'enseignement. Il faut qu'il ne soit ni adonné au vin, ni violent, mais indulgent, pacifique, désintéressé. Il faut qu'il dirige bien sa propre maison, et qu'il tienne ses enfants dans la soumission et dans une parfaite honnêteté; car si quelqu'un ne sait pas diriger sa propre maison, comment prendra-t-il soin de l'Eglise de Dieu?",
 pt: "Fiel é esta palavra: Se alguém aspira ao episcopado, excelente obra deseja. É necessário, pois, que o bispo seja irrepreensível, marido de uma só mulher, temperante, sóbrio, ordeiro, hospitaleiro, apto para ensinar; não dado ao vinho, não espancador, mas moderado, inimigo de contendas, não ganancioso; que governe bem a sua própria casa, tendo seus filhos em sujeição, com todo o respeito (pois, se alguém não sabe governar a sua própria casa, como cuidará da igreja de Deus?);",
 sv: "Det är ett visst ord, att om någons håg står till en församlingsföreståndares ämbete, så är det en god verksamhet han åstundar. En församlingsföreståndare bör därför vara oförvitlig; han bör vara en enda kvinnas man, nykter och tuktig, hövisk i sitt skick, gästvänlig, väl skickad att undervisa, icke begiven på vin, icke våldsam, utan foglig, icke stridslysten, fri ifrån penningbegär. Han bör väl förestå sitt eget hus och hålla sina barn i lydnad, med all värdighet; ty huru skulle dem som icke vet att förestå sitt eget hus kunna sköta Guds församling?",
 no: "Det er et troverdig ord: Om nogen attrår et tilsyns-embede, da har han lyst til en god gjerning. Derfor skal en tilsynsmann være ulastelig, én kvinnes mann, edruelig, sindig, verdig, gjestfri, duelig til å lære andre, ikke drikkfeldig, ikke voldsom, men saktmodig, ikke stridslysten, ikke pengekjær, en som styrer sitt eget hus vel og har lydige barn med all sømmelighet - men hvis nogen ikke vet å styre sitt eget hus, hvorledes kan han da ha omsorg for Guds menighet? -",
 da: "Troværdig er den tale: Stræber nogen efter at blive tilsynsmand, er det en smuk opgave, han ønsker sig. En tilsynsmand skal være ulastelig, én kvindes mand, ædruelig, besindig, høvisk, gæstfri, en god lærer, ikke drikfældig og voldelig, men mild, ikke stridbar og ikke glad for penge. Han skal kunne lede sit eget hus og holde sine børn i lydighed og al ære værd; for hvordan kan en mand, der ikke forstår at lede sit eget hus, have omsorg for Guds menighed?",
 },
 "1 Timothy 4:1-3": {
 es: " EMPERO el Espíritu dice manifiestamente, que en los venideros tiempos algunos apostatarán de la fe, escuchando á espíritus de error y á doctrinas de demonios; Que con hipocresía hablarán mentira, teniendo cauterizada la conciencia. Que prohibirán casarse, y mandarán abstenerse de las viandas que Dios crió para que con hacimiento de gracias participasen de ellas los fieles, y los que han conocido la verdad.",
 fr: "Mais l'Esprit dit expressément que, dans les derniers temps, quelques-uns abandonneront la foi, pour s'attacher à des esprits séducteurs et à des doctrines de démons, par l'hypocrisie de faux docteurs portant la marque de la flétrissure dans leur propre conscience, prescrivant de ne pas se marier, et de s'abstenir d'aliments que Dieu a créés pour qu'ils soient pris avec actions de grâces par ceux qui sont fidèles et qui ont connu la vérité.",
 pt: "Mas o Espírito expressamente diz que em tempos posteriores alguns apostatarão da fé, dando ouvidos a espíritos enganadores, e a doutrinas de demônios, pela hipocrisia de homens que falam mentiras e têm a sua própria consciência cauterizada, proibindo o casamento, e ordenando a abstinência de alimentos que Deus criou para serem recebidos com ações de graças pelos que são fiéis e que conhecem bem a verdade;",
 sv: "Men Anden säger uttryckligen, att i kommande tider somliga skola avfalla från tron och hålla sig till villoandar och till onda andars läror. Så skall ske genom lögnpredikanters skrymteri, människors som i sina egna samveten äro brännmärkta såsom brottslingar, och som förbjuda äktenskap och vilja att man skall avhålla sig från allahanda mat, som Gud har skapat till att med tacksägelse mottagas av dem som tro och hava lärt känna sanningen.",
 no: "Men Ånden sier med tydelige ord at i de kommende tider skal nogen falle fra troen, idet de holder sig til forførende ånder og djevlers lærdommer ved hykleri av falske lærere, som er brennemerket i sin egen samvittighet, som forbyder å gifte sig og byder å avholde sig fra mat, den Gud har skapt til å nytes med takk av dem som tror og har lært sannheten å kjenne.",
 da: "Men Ånden siger udtrykkeligt, at i de sidste tider skal nogle falde fra troen, fordi de lytter til vildledende ånder og dæmoners lærdomme, som udbredes af løgnagtige hyklere, der er brændemærket i deres samvittighed, og som forbyder ægteskab og kræver afholdenhed fra føde, som Gud har skabt til at modtages med tak af dem, der tror og har erkendt sandheden.",
 },
 "1 Timothy 4:14": {
 es: " No descuides el don que está en ti, que te es dado por profecía con la imposición de las manos del presbiterio.",
 fr: "Ne néglige pas le don qui est en toi, et qui t'a été donné par prophétie avec l'imposition des mains de l'assemblée des anciens.",
 pt: "Não negligencies o dom que há em ti, o qual te foi dado por profecia, com a imposição das mãos do presbítero.",
 sv: "Försumma icke att vårda den nådegåva som finnes i dig, och som gavs dig i kraft av profetord, under handpåläggning av de äldste.",
 no: "Vanskjøtt ikke den nådegave som er i dig, som blev dig gitt ved profetiske ord med håndspåleggelse av de eldste.",
 da: "Forsøm ikke nådegaven i dig, som du fik ved profetiske ord under håndspålæggelse af de ældste.",
 },
 "2 Timothy 1:6": {
 es: " Por lo cual te aconsejo que despiertes el don de Dios, que está en ti por la imposición de mis manos.",
 fr: "C'est pourquoi je t'exhorte à ranimer le don de Dieu que tu as reçu par l'imposition de mes mains.",
 pt: "Por esta razão te lembro que despertes o dom de Deus, que há em ti pela imposição das minhas mãos.",
 sv: "Fördenskull påminner jag dig att du må uppliva den nådegåva från Gud, som i följd av min handpåläggning finnes i dig.",
 no: "Derfor minner jeg dig om at du igjen optender den Guds nådegave som er i dig ved min håndspåleggelse.",
 da: "Derfor minder jeg dig om at lade den nådegave fra Gud, som du fik ved min håndspålæggelse, flamme op.",
 },
 "2 Timothy 1:9": {
 es: " Que nos salvó y llamó con vocación santa, no conforme á nuestras obras, mas según el intento suyo y gracia, la cual nos es dada en Cristo Jesús antes de los tiempos de los siglos,",
 fr: "qui nous a sauvés, et nous a adressé une sainte vocation, non à cause de nos oeuvres, mais selon son propre dessein, et selon la grâce qui nous a été donnée en Jésus-Christ avant les temps éternels,",
 pt: "que nos salvou, e chamou com uma santa vocação, não segundo as nossas obras, mas segundo o seu próprio propósito e a graça que nos foi dada em Cristo Jesus antes dos tempos eternos,",
 sv: "han som har frälst oss och kallat oss med en helig kallelse, icke på grund av våra gärningar, utan efter sitt eget rådslut och sin nåd, den nåd som redan för evärdliga tider sedan gavs oss i Kristus Jesus,",
 no: "han som frelste oss og kalte oss med et hellig kall, ikke efter våre gjerninger, men efter sitt eget forsett og den nåde som er oss gitt i Kristus Jesus fra evige tider,",
 da: "han frelste os og kaldte os med en hellig kaldelse, ikke på grund af vore gerninger, men efter egen beslutning og af den nåde, som er givet os i Kristus Jesus fra evighed af,",
 },
 "2 Timothy 2:9": {
 es: " En el que sufro trabajo, hasta las prisiones á modo de malhechor; mas la palabra de Dios no está presa.",
 fr: "pour lequel je souffre jusqu'à être lié comme un malfaiteur. Mais la parole de Dieu n'est pas liée.",
 pt: "pelo qual sofro a ponto de ser preso como malfeitor; mas a palavra de Deus não está presa.",
 sv: "och i vars tjänst jag jämväl utstår lidande, ja, till och med måste bära bojor såsom en ogärningsman. Men Guds ord bär icke bojor.",
 no: "for hvis skyld jeg lider ondt like til dette å være bundet som en ugjerningsmann; men Guds ord er ikke bundet.",
 da: "for evangeliets skyld lider jeg ondt, ja, er jeg endog bundet i lænker som en forbryder. Men Guds ord er ikke bundet.",
 },
 "2 Timothy 3:1-5": {
 es: " ESTO también sepas, que en los postreros días vendrán tiempos peligrosos: Que habrá hombres amadores de sí mismos, avaros, vanagloriosos, soberbios, detractores, desobedientes á los padres, ingratos, sin santidad, Sin afecto, desleales, calumniadores, destemplados, crueles, aborrecedores de lo bueno, Traidores, arrebatados, hinchados, amadores de los deleites más que de Dios; Teniendo apariencia de piedad, mas habiendo negado la eficacia de ella: y á éstos evita.",
 fr: "Sache que, dans les derniers jours, il y aura des temps difficiles. Car les hommes seront égoïstes, amis de l'argent, fanfarons, hautains, blasphémateurs, rebelles à leurs parents, ingrats, irréligieux, insensibles, déloyaux, calomniateurs, intempérants, cruels, ennemis des gens de bien, traîtres, emportés, enflés d'orgueil, aimant le plaisir plus que Dieu, ayant l'apparence de la piété, mais reniant ce qui en fait la force. Eloigne-toi de ces hommes-là.",
 pt: "Sabe, porém, isto, que nos últimos dias sobrevirão tempos penosos; pois os homens serão amantes de si mesmos, gananciosos, presunçosos, soberbos, blasfemos, desobedientes a seus pais, ingratos, ímpios, sem afeição natural, implacáveis, caluniadores, incontinentes, cruéis, inimigos do bem, traidores, atrevidos, orgulhosos, mais amigos dos deleites do que amigos de Deus, tendo aparência de piedade, mas negando-lhe o poder. Afasta- te também desses.",
 sv: "Men det må du veta, att i de yttersta dagarna svåra tider skola komma. Ty människorna skola då vara själviska, penningkära, stortaliga, övermodiga, smädelystna, olydiga mot sina föräldrar, otacksamma, gudlösa, kärlekslösa mot sina närmaste, trolösa, begivna på förtal, omåttliga, tygellösa, fientliga mot det goda, förrädiska, besinningslösa, förblindade av högmod; de skola älska vällust mer än Gud, de skola hava ett sken av gudsfruktan, men skola icke vilja veta av dess kraft. Vänd dig bort ifrån sådana.",
 no: "Men dette skal du vite at i de siste dager skal det komme vanskelige tider. For menneskene skal da være egenkjærlige, pengekjære, stortalende, overmodige, spottende, ulydige mot foreldre, utakknemlige, vanhellige, ukjærlige, upålitelige, baktalende, umåtelige, umilde, uten kjærlighet til det gode, svikefulle, fremfusende, opblåste, slike som elsker sine lyster høiere enn Gud, som har gudfryktighets skinn, men fornekter dens kraft - og disse skal du vende dig fra.",
 da: "Men det skal du vide, at i de sidste dage skal der komme hårde tider. For da skal mennesker blive egenkærlige, pengekære, pralende, overmodige, fulde af hån, ulydige mod deres forældre, utaknemlige, new, ukærlige, uforsonlige, sladderagtige, umådeholdne, brutale, fjender af det gode, forrædere, fremfusende, hovblæste, de elsker nydelser højere end Gud; i det ydre har de gudsfrygt, men de fornægter dens kraft. Dem skal du vende dig fra.",
 },
 "2 Timothy 3:16-17": {
 es: " Toda Escritura es inspirada divinamente y útil para enseñar, para redargüir, para corregir, para instituir en justicia, Para que el hombre de Dios sea perfecto, enteramente instruído para toda buena obra.",
 fr: "Toute Ecriture est inspirée de Dieu, et utile pour enseigner, pour convaincre, pour corriger, pour instruire dans la justice, afin que l'homme de Dieu soit accompli et propre à toute bonne oeuvre.",
 pt: "Toda Escritura é divinamente inspirada e proveitosa para ensinar, para repreender, para corrigir, para instruir em justiça; para que o homem de Deus seja perfeito, e perfeitamente preparado para toda boa obra.",
 sv: "All skrift som är ingiven av Gud är ock nyttig till undervisning, till bestraffning, till upprättelse, till fostran i rättfärdighet, så att en gudsmänniska kan bliva fullt färdig, väl skickad till allt gott verk.",
 no: "Den hele Skrift er innblest av Gud av Gud og nyttig til lærdom, til overbevisning, til rettledning, til optuktelse i rettferdighet, forat det Guds menneske kan være fullkommen, duelig til all god gjerning.",
 da: "Ethvert skrift er indblæst af Gud og er nyttigt til undervisning, til bevis, til vejledning og til opdragelse i retfærdighed, så at det menneske, som hører Gud til, kan blive fuldkomment, udrustet til al god gerning.",
 },
 "2 Timothy 4:3-4": {
 es: " Porque vendrá tiempo cuando no sufrirán la sana doctrina; antes, teniendo comezón de oir, se amontonarán maestros conforme á sus concupiscencias, Y apartarán de la verdad el oído, y se volverán á las fábulas.",
 fr: "Car il viendra un temps où les hommes ne supporteront pas la saine doctrine; mais, ayant la démangeaison d'entendre des choses agréables, ils se donneront une foule de docteurs selon leurs propres désirs, détourneront l'oreille de la vérité, et se tourneront vers les fables.",
 pt: "Porque virá tempo em que não suportarão a sã doutrina; mas, tendo grande desejo de ouvir coisas agradáveis, ajuntarão para si mestres segundo os seus próprios desejos, e não só desviarão os ouvidos da verdade, mas se voltarão às fábulas.",
 sv: "Ty den tid kommer, då de icke längre skola fördraga den sunda läran, utan efter sina egna begärelser skola samla åt sig lärare hoptals, alltefter som det kliar dem i öronen, en tid då de skola vända sina öron från sanningen, och i stället vända sig till fabler.",
 no: "For det skal komme en tid da de ikke skal tåle den sunde lære, men efter sine egne lyster ta sig selv lærere i hopetall, fordi det klør dem i øret, og de skal vende øret bort fra sannheten og vende sig til eventyr.",
 da: "For der kommer en tid, da folk ikke vil finde sig i den sunde lære, men skaffe sig lærere i hobetal efter deres eget hoved, fordi det kildrer deres ører, og de vil vende øret fra sandheden og slå sig på myter.",
 },
 "1 John 1:3": {
 es: " Lo que hemos visto y oído, eso os anunciamos, para que también vosotros tengáis comunión con nosotros: y nuestra comunión verdaderamente es con el Padre, y con su Hijo Jesucristo.",
 fr: "ce que nous avons vu et entendu, nous vous l'annonçons, à vous aussi, afin que vous aussi vous soyez en communion avec nous. Or, notre communion est avec le Père et avec son Fils Jésus-Christ.",
 pt: "sim, o que vimos e ouvimos, isso vos anunciamos, para que vós também tenhais comunhão conosco; e a nossa comunhão é com o Pai, e com seu Filho Jesus Cristo.",
 sv: "Nåd, barmhärtighet och frid ifrån Gud, Fadern, och ifrån Jesus Kristus, Faderns Son, skall vara med oss i sanning och i kärlek.",
 no: "det som vi har sett og hørt, det forkynner vi og eder, forat og I kan ha samfund med oss; men vårt samfund er med Faderen og med hans Sønn Jesus Kristus.",
 da: "det, vi har set og hørt, forkynder vi også for jer, for at også I kan have fællesskab med os; og vort fællesskab er med Faderen og med hans søn, Jesus Kristus.",
 },
 "1 John 2:1-2": {
 es: " HIJITOS míos, estas cosas os escribo, para que no pequéis; y si alguno hubiere pecado, abogado tenemos para con el Padre, á Jesucristo el justo; Y él es la propiciación por nuestros pecados: y no solamente por los nuestros, sino también por los de todo el mundo.",
 fr: "Mes petits enfants, je vous écris ces choses, afin que vous ne péchiez point. Et si quelqu'un a péché, nous avons un avocat auprès du Père, Jésus-Christ le juste. Il est lui-même une victime expiatoire pour nos péchés, non seulement pour les nôtres, mais aussi pour ceux du monde entier.",
 pt: "Meus filhinhos, estas coisas vos escrevo, para que não pequeis; mas, se alguém pecar, temos um Advogado para com o Pai, Jesus Cristo, o justo. E ele é a propiciação pelos nossos pecados, e não somente pelos nossos, mas também pelos de todo o mundo.",
 no: "Mine barn! dette skriver jeg til eder forat I ikke skal synde; og om nogen synder, da har vi en talsmann hos Faderen, Jesus Kristus, den rettferdige, og han er en soning for våre synder, dog ikke bare for våre, men og for hele verdens.",
 sv: "Mina barn, detta skriver jag till er för att ni inte ska synda. Men om någon syndar, har vi en förespråkare hos Fadern: Jesus Kristus, den rättfärdige. Han är försoningen för våra synder, och inte bara för våra utan också för hela världens.",
 da: "Mine børn, dette skriver jeg til jer, for at I ikke skal synde. Men hvis nogen synder, har vi en talsmand hos Faderen, Jesus Kristus, den retfærdige; han er sonoffer for vore synder, og ikke blot for vore, men for hele verdens.",
 },
 "1 John 4:1": {
 es: " AMADOS, no creáis á todo espíritu, sino probad los espíritus si son de Dios: porque muchos falsos profetas son salidos en el mundo.",
 fr: "Bien-aimés, n'ajoutez pas foi à tout esprit; mais éprouvez les esprits, pour savoir s'ils sont de Dieu, car plusieurs faux prophètes sont venus dans le monde.",
 pt: "Amados, não creiais a todo espírito, mas provai se os espíritos vêm de Deus; porque muitos falsos profetas têm saído pelo mundo.",
 no: "I elskede! tro ikke enhver ånd, men prøv åndene om de er av Gud! for mange falske profeter er gått ut i verden.",
 sv: "Mina älskade, tro inte varje ande, utan pröva andarna om de kommer från Gud, för många falska profeter har gått ut i världen.",
 da: "Mine kære, tro ikke enhver ånd, men prøv ånderne, om de er af Gud, for mange falske profeter er draget ud i verden.",
 },
 "1 John 4:9-11": {
 es: " En esto se mostró el amor de Dios para con nosotros, en que Dios envió á su Hijo unigénito al mundo, para que vivamos por él. En esto consiste el amor: no que nosotros hayamos amado á Dios, sino que él nos amó á nosotros, y ha enviado á su Hijo en propiciación por nuestros pecados. Amados, si Dios así nos ha amado, debemos también nosotros amarnos unos á otros.",
 fr: "L'amour de Dieu a été manifesté envers nous en ce que Dieu a envoyé son Fils unique dans le monde, afin que nous vivions par lui. Et cet amour consiste, non point en ce que nous avons aimé Dieu, mais en ce qu'il nous a aimés et a envoyé son Fils comme victime expiatoire pour nos péchés. Bien-aimés, si Dieu nous a ainsi aimés, nous devons aussi nous aimer les uns les autres.",
 pt: "Nisto se manifestou o amor de Deus para conosco: em que Deus enviou seu Filho unigênito ao mundo, para que por meio dele vivamos. Nisto está o amor: não em que nós tenhamos amado a Deus, mas em que ele nos amou a nós, e enviou seu Filho como propiciação pelos nossos pecados. Amados, se Deus assim nos amou, nós também devemos amar-nos uns aos outros.",
 no: "Ved dette er Guds kjærlighet åpenbaret iblandt oss at Gud har sendt sin Sønn, den enbårne, til verden, forat vi skal leve ved ham. I dette er kjærligheten, ikke at vi har elsket Gud, men at han har elsket oss og sendt sin Sønn til soning for våre synder. I elskede! har Gud elsket oss så, da er og vi skyldige å elske hverandre.",
 sv: "Så uppenbarades Guds kärlek till oss: han sände sin enfödde Son till världen för att vi skulle leva genom honom. Detta är kärleken: inte att vi har älskat Gud, utan att han har älskat oss och sänt sin Son som försoningsoffer för våra synder. Mina älskade, om Gud så har älskat oss, är också vi skyldiga att älska varandra.",
 da: "v9 Ved dette blev Guds kærlighed åbenbaret iblandt os: at Gud har sendt sin enbårne søn til verden, for at vi skal leve ved ham. v10 Déri består kærligheden: ikke i at vi har elsket Gud, men i at han har elsket os og sendt sin søn som et sonoffer for vore synder. v11 Mine kære, når Gud har elsket os således, skylder vi også at elske hinanden.",
 },
 "1 John 4:14-16": {
 es: " Y nosotros hemos visto y testificamos que el Padre ha enviado al Hijo para ser Salvador del mundo. Cualquiera que confesare que Jesús es el Hijo de Dios, Dios está en él, y él en Dios. Y nosotros hemos conocido y creído el amor que Dios tiene para con nosotros. Dios es amor; y el que vive en amor, vive en Dios, y Dios en él.",
 fr: "Et nous, nous avons vu et nous attestons que le Père a envoyé le Fils comme Sauveur du monde. Celui qui confessera que Jésus est le Fils de Dieu, Dieu demeure en lui, et lui en Dieu. Et nous, nous avons connu l'amour que Dieu a pour nous, et nous y avons cru. Dieu est amour; et celui qui demeure dans l'amour demeure en Dieu, et Dieu demeure en lui.",
 pt: "E nós temos visto, e testificamos que o Pai enviou seu Filho como Salvador do mundo. Qualquer que confessar que Jesus é o Filho de Deus, Deus permanece nele, e ele em Deus. E nós conhecemos, e cremos no amor que Deus nos tem. Deus é amor; e quem permanece em amor, permanece em Deus, e Deus nele.",
 no: "Og vi har sett og vidner at Faderen har sendt sin Sønn til frelse for verden. Den som bekjenner at Jesus er Guds Sønn, i ham blir Gud, og han i Gud. Og vi har kjent og trodd den kjærlighet som Gud har til oss. Gud er kjærlighet, og den som blir i kjærligheten, han blir i Gud, og Gud blir i ham.",
 sv: "Och vi har sett och vittnar om att Fadern har sänt sin Son som världens Frälsare. Den som bekänner att Jesus är Guds Son, i honom förblir Gud och han själv förblir i Gud. Och vi har förstått och tror på den kärlek som Gud har till oss. Gud är kärlek, och den som förblir i kärleken förblir i Gud, och Gud förblir i honom.",
 da: "v14 Og vi har set og vidner om, at Faderen har sendt sin søn som verdens frelser. v15 Den, der bekender, at Jesus er Guds søn, i ham bliver Gud, og han selv bliver i Gud. v16 Og vi har kendt og troet på den kærlighed, som Gud har til os. Gud er kærlighed, og den, der bliver i kærligheden, bliver i Gud, og Gud bliver i ham.",
 },
 "1 John 5:9-12": {
 es: " Si recibimos el testimonio de los hombres, el testimonio de Dios es mayor; porque éste es el testimonio de Dios, que ha testificado de su Hijo. El que cree en el Hijo de Dios, tiene el testimonio en sí mismo: el que no cree á Dios, le ha hecho mentiroso; porque no ha creído en el testimonio que Dios ha testificado de su Hijo. Y este es el testimonio: Que Dios nos ha dado vida eterna; y esta vida está en su Hijo. El que tiene al Hijo, tiene la vida: el que no tiene al Hijo de Dios, no tiene la vida.",
 fr: "Si nous recevons le témoignage des hommes, le témoignage de Dieu est plus grand; car le témoignage de Dieu consiste en ce qu'il a rendu témoignage à son Fils. Celui qui croit au Fils de Dieu a ce témoignage en lui-même; celui qui ne croit pas Dieu le fait menteur, puisqu'il ne croit pas au témoignage que Dieu a rendu à son Fils. Et voici ce témoignage, c'est que Dieu nous a donné la vie éternelle, et que cette vie est dans son Fils. Celui qui a le Fils a la vie; celui qui n'a pas le Fils de Dieu n'a pas la vie.",
 pt: "Se recebemos o testemunho dos homens, o testemunho de Deus é este, que de seu Filho testificou - Quem crê no Filho de Deus, em si mesmo tem o testemunho; quem a Deus não crê, mentiroso o fez; porquanto não creu no testemunho que Deus de seu Filho deu. - E o testemunho é este: que Deus nos deu a vida eterna; e esta vida está em seu Filho. Quem tem o Filho tem a vida; quem não tem o Filho de Deus não tem a vida.",
 no: "Tar vi imot menneskenes vidnesbyrd, da er Guds vidnesbyrd større; for dette er Guds vidnesbyrd at han har vidnet om sin Sønn. Den som tror på Guds Sønn, har vidnesbyrdet i sig selv; den som ikke tror Gud, har gjort ham til en løgner; for han har ikke trodd på det vidnesbyrd som Gud har vidnet om sin Sønn. Og dette er vidnesbyrdet at Gud har gitt oss evig liv, og dette liv er i hans Sønn. Den som har Sønnen, han har livet; den som ikke har Guds Sønn, han har ikke livet.",
 sv: "Om vi tar emot människors vittnesbörd, så är Guds vittnesbörd större. Ty detta är Guds vittnesbörd, att han har vittnat om sin Son. Den som tror på Guds Son har vittnesbördet i sitt inre. Den som inte tror på Gud har gjort honom till en lögnare, eftersom han inte har trott på det vittnesbörd som Gud har gett om sin Son. Och detta är vittnesbördet: Gud har gett oss evigt liv, och det livet är i hans Son. Den som har Sonen har livet. Den som inte har Guds Son har inte livet.",
 da: "v9 Hvis vi tager imod menneskers vidnesbyrd, er Guds vidnesbyrd større, for Guds vidnesbyrd er dette, at han har vidnet om sin søn. v10 Den, der tror på Guds søn, har vidnesbyrdet i sig; den, der ikke tror Gud, har gjort ham til en løgner, fordi han ikke har troet på det vidnesbyrd, som Gud har vidnet om sin søn. v11 Og dette er vidnesbyrdet: at Gud har givet os evigt liv, og det liv er i hans søn. v12 Den, der har Sønnen, har livet; den, der ikke har Guds søn, har ikke livet.",
 },
 "2 John 1:3": {
 es: " Sea con vosotros gracia, misericordia, y paz de Dios Padre, y del Señor Jesucristo, Hijo del Padre, en verdad y en amor.",
 fr: "que la grâce, la miséricorde et la paix soient avec vous de la part de Dieu le Père et de la part de Jésus-Christ, le Fils du Père, dans la vérité et la charité!",
 pt: "Graça, misericórdia, paz, da parte de Deus Pai e da parte de Jesus Cristo, o Filho do Pai, serão conosco em verdade e amor.",
 sv: "Ty det gjorde mig stor glädje, då några av bröderna kommo och vittnade om den sanning som bor i dig, eftersom du ju vandrar i sanningen.",
 no: "Nåde, miskunn, fred skal være med oss fra Gud Fader og fra Jesus Kristus, Faderens Sønn, i sannhet og kjærlighet.",
 da: "Nåde, barmhjertighed og fred fra Gud Fader og fra Jesus Kristus, Faderens søn, vil være med os i sandhed og kærlighed.",
 },
 "Ephesians 5:5-6": {
 es: " Porque sabéis esto, que ningún fornicario, ó inmundo, ó avaro, que es servidor de ídolos, tiene herencia en el reino de Cristo y de Dios. Nadie os engañe con palabras vanas; porque por estas cosas viene la ira de Dios sobre los hijos de desobediencia.",
 fr: "Car, sachez-le bien, aucun impudique, ou impur, ou cupide, c'est-à-dire, idolâtre, n'a d'héritage dans le royaume de Christ et de Dieu. Que personne ne vous séduise par de vains discours; car c'est à cause de ces choses que la colère de Dieu vient sur les fils de la rébellion.",
 pt: "Porque bem sabeis isto: que nenhum devasso, ou impuro, ou avarento, o qual é idólatra, tem herança no reino de Cristo e de Deus. Ninguém vos engane com palavras vãs; porque por estas coisas vem a ira de Deus sobre os filhos da desobediência.",
 sv: "Ty det bören I veta, och det insen I också själva, att ingen otuktig eller oren människa har arvedel i Kristi och Guds rike, ej heller någon girig, ty en sådan är en avgudadyrkare. Låten ingen bedraga eder med tomma ord; ty för sådana synder kommer Guds vrede över de ohörsamma.",
 no: "For dette vet og skjønner I at ingen horkarl eller uren eller havesyk, som er en avgudsdyrker, har arv i Kristi og Guds rike. La ingen dåre eder med tomme ord! for på grunn av disse ting kommer Guds vrede over vantroens barn;",
 da: "For det skal I vide, at ingen utugtig eller uren eller grisk – det er en afgudsdyrker – har lod og del i Kristi og Guds rige. Lad ingen narre jer med tomme ord; for på grund af den slags kommer Guds vrede over ulydighedens børn.",
 },
 "1 John 2:3-6": {
 es: " Y en esto sabemos que nosotros le hemos conocido, si guardamos sus mandamientos. El que dice, Yo le he conocido, y no guarda sus mandamientos, el tal es mentiroso, y no hay verdad en él; Mas el que guarda su palabra, la caridad de Dios está verdaderamente perfecta en él: por esto sabemos que estamos en él. El que dice que está en él, debe andar como él anduvo.",
 fr: "Si nous gardons ses commandements, par là nous savons que nous l'avons connu. Celui qui dit: Je l'ai connu, et qui ne garde pas ses commandements, est un menteur, et la vérité n'est point en lui. Mais celui qui garde sa parole, l'amour de Dieu est véritablement parfait en lui: par là nous savons que nous sommes en lui. Celui qui dit qu'il demeure en lui doit marcher aussi comme il a marché lui-même.",
 pt: "E nisto sabemos que o conhecemos; se guardamos os seus mandamentos. Aquele que diz: Eu o conheço, e não guarda os seus mandamentos, é mentiroso, e nele não está a verdade; mas qualquer que guarda a sua palavra, nele realmente se tem aperfeiçoado o amor de Deus. E nisto sabemos que estamos nele; aquele que diz estar nele, também deve andar como ele andou.",
 no: "Og derav vet vi at vi kjenner ham: om vi holder hans bud. Den som sier: Jeg kjenner ham, og ikke holder hans bud, han er en løgner, og i ham er ikke sannheten; men den som holder hans ord, i ham er sannelig kjærligheten til Gud blitt fullkommen. På dette kjenner vi at vi er i ham. Den som sier at han blir i ham, han er og skyldig å vandre således som han vandret.",
 sv: "Och därav vet vi att vi har lärt känna honom, om vi hålla hans bud. Den som säger sig känn honom och icke håller hans bud, han är en lögnare, och i honom är icke sanningen. Men den som håller hans ord, i honom är förvisso Guds kärlek fullkomnad. Därav veta vi att vi äro i honom. Den som säger sig förbliva i honom, han är ock pliktig att själv så vandra som han vandrade.",
 da: "Deraf ved vi, at vi kender ham: at vi holder hans bud. Den, der siger: »Jeg kender ham,« men ikke holder hans bud, er en løgner, og sandheden er ikke i ham. Men den, der holder fast ved hans ord, i ham er Guds kærlighed i sandhed fuldkommet. Deraf ved vi, at vi er i ham. Den, der siger, at han bliver i ham, skylder også selv at leve et sådant liv, som han levede.",
 },
 "1 John 5:3": {
 es: " Porque este es el amor de Dios, que guardemos sus mandamientos; y sus mandamientos no son penosos.",
 fr: "Car l'amour de Dieu consiste à garder ses commandements. Et ses commandements ne sont pas pénibles,",
 pt: "Porque este é o amor de Deus, que guardemos os seus mandamentos; e os seus mandamentos não são penosos;",
 no: "For dette er kjærligheten til Gud at vi holder hans bud; og hans bud er ikke tunge.",
 sv: "Ty detta är kärleken till Gud, att vi håller hans bud. Och hans bud är inte tunga.",
 da: "For dette er kærligheden til Gud: at vi holder hans bud; og hans bud er ikke tunge.",
 },
 "2 John 1:6": {
 es: " Y este es amor, que andemos según sus mandamientos. Este es el mandamiento: Que andéis en él, como vosotros habéis oído desde el principio.",
 fr: "Et l'amour consiste à marcher selon ses commandements. C'est là le commandement dans lequel vous devez marcher, comme vous l'avez appris dès le commencement.",
 pt: "E o amor é este: que andemos segundo os seus mandamentos. Este é o mandamento, como já desde o princípio ouvistes, para que nele andeis.",
 sv: "Dessa hava nu inför församlingen vittnat om din kärlek. Och du gör väl, om du på ett sätt som är värdigt Gud utrustar dem också för fortsättningen av deras resa.",
 no: "Og dette er kjærligheten at vi vandrer efter hans bud. Dette er budet, således som I hørte det fra begynnelsen, at I skal vandre efter det.",
 da: "Og dette er kærligheden: at vi vandrer efter hans bud. Dette er budet, som I har hørt fra begyndelsen, at I skal vandre i det.",
 },
 "1 Corinthians 1:12-13": {
 es: " Quiero decir, que cada uno de vosotros dice: Yo cierto soy de Pablo; pues yo de Apolos; y yo de Cefas; y yo de Cristo. ¿Está dividido Cristo? ¿Fué crucificado Pablo por vosotros? ¿ó habéis sido bautizados en el nombre de Pablo?",
 fr: "Je veux dire que chacun de vous parle ainsi: Moi, je suis de Paul! et moi, d'Apollos! et moi, de Céphas! et moi, de Christ! Christ est-il divisé? Paul a-t-il été crucifié pour vous, ou est-ce au nom de Paul que vous avez été baptisés?",
 pt: "Quero dizer com isto, que cada um de vós diz: Eu sou de Paulo; ou, Eu de Apolo; ou Eu sou de Cefas; ou, Eu de Cristo. será que Cristo está dividido? foi Paulo crucificado por amor de vós? ou fostes vós batizados em nome de Paulo?",
 sv: "Härmed menar jag att bland eder den ene säger: »Jag håller mig till Paulus», den andre: »Jag håller mig till Apollos», en annan: »Jag håller mig till Cefas», åter en annan: »Jag håller mig till Kristus.» -- Är då Kristus delad? Icke blev väl Paulus korsfäst för eder? Och icke bleven I väl döpta i Paulus' namn?",
 no: "Jeg mener dette at enhver av eder sier: Jeg holder mig til Paulus; jeg til Apollos; jeg til Kefas; jeg til Kristus. Er Kristus blitt delt? var det Paulus som blev korsfestet for eder, eller var det til Paulus' navn I blev døpt?",
 da: "v12 Jeg mener dette, at I hver især siger: »Jeg hører til Paulus,« eller: »Jeg hører til Apollos,« eller: »Jeg hører til Kefas,« eller: »Jeg hører til Kristus.« v13 Er Kristus da delt? Blev Paulus korsfæstet for jer? Eller blev I døbt i Paulus' navn?",
 },
 "1 Corinthians 8:6": {
 es: " Nosotros empero no tenemos más de un Dios, el Padre, del cual son todas las cosas, y nosotros en él: y un Señor Jesucristo, por el cual son todas las cosas, y nosotros por él.",
 fr: "néanmoins pour nous il n'y a qu'un seul Dieu, le Père, de qui viennent toutes choses et pour qui nous sommes, et un seul Seigneur, Jésus-Christ, par qui sont toutes choses et par qui nous sommes.",
 pt: "todavia para nós há um só Deus, o Pai, de quem são todas as coisas e para quem nós vivemos; e um só Senhor, Jesus Cristo, pelo qual existem todas as coisas, e por ele nós também.",
 sv: "så finnes dock för oss allenast en enda Gud: Fadern, av vilken allt är, och till vilken vi själva äro, och en enda Herre: Jesus Kristus, genom vilken allt är, och genom vilken vi själva äro.",
 no: "så er det dog for oss bare én Gud, Faderen, av hvem alt er, og vi til ham, og én Herre, Jesus Kristus, ved hvem alt er, og vi ved ham.",
 da: "så har vi dog kun én Gud, Faderen, fra hvem alt er, og til hvem vi er skabt, og én Herre, Jesus Kristus, ved hvem alt er, og ved hvem vi er skabt.",
 },
 "1 Corinthians 12:27-28": {
 es: " Pues vosotros sois el cuerpo de Cristo, y miembros en parte. Y á unos puso Dios en la iglesia, primeramente apóstoles, luego profetas, lo tercero doctores; luego facultades; luego dones de sanidades, ayudas, gobernaciones, géneros de lenguas.",
 fr: "Vous êtes le corps de Christ, et vous êtes ses membres, chacun pour sa part. Et Dieu a établi dans l'Eglise premièrement des apôtres, secondement des prophètes, troisièmement des docteurs, ensuite ceux qui ont le don des miracles, puis ceux qui ont les dons de guérir, de secourir, de gouverner, de parler diverses langues.",
 pt: "Ora, vós sois corpo de Cristo, e individualmente seus membros. E a uns pôs Deus na igreja, primeiramente apóstolos, em segundo lugar profetas, em terceiro mestres, depois operadores de milagres, depois dons de curar, socorros, governos, variedades de línguas.",
 sv: "Men nu ären I Kristi kropp och hans lemmar, var och en i sin mån. Och Gud har i församlingen satt först och främst några till apostlar, för det andra några till profeter, för det tredje några till lärare, vidare några till att utföra kraftgärningar, ytterligare några till att hava helbrägdagörelsens gåvor, eller till att taga sig an de hjälplösa, eller till att vara styresmän, eller till att på olika sätt tala tungomål.",
 no: "Men nu er I Kristi legeme og hans lemmer, hver efter sin del. Og Gud satte i menigheten først nogen til apostler, for det annet profeter, for det tredje lærere, så kraftige gjerninger, så nådegaver til å helbrede, til å hjelpe, til å styre, forskjellige slags tunger.",
 da: "v27 I er Kristi legeme og hver især hans lemmer. v28 I kirken har Gud sat nogle til for det første apostle, for det andet profeter, for det tredje lærere, dernæst mægtige gerninger, dernæst nådegaver til at helbrede, til at hjælpe, til at styre og til forskellige slags tungetale.",
 },
 "1 Corinthians 14:33": {
 es: " Porque Dios no es Dios de disensión, sino de paz; como en todas las iglesias de los santos.",
 fr: "car Dieu n'est pas un Dieu de désordre, mais de paix. Comme dans toutes les Eglises des saints,",
 pt: "porque Deus não é Deus de confusão, mas sim de paz. Como em todas as igrejas dos santos,",
 sv: "Gud är ju icke oordningens Gud, utan fridens.",
 no: "for Gud er ikke uordens Gud, men freds Gud.",
 da: "for Gud er ikke forvirringens, men fredens Gud.",
 },
 "1 Corinthians 15:29": {
 es: " De otro modo, ¿qué harán los que se bautizan por los muertos, si en ninguna manera los muertos resucitan? ¿Por qué pues se bautizan por los muertos?",
 fr: "Autrement, que feraient ceux qui se font baptiser pour les morts? Si les morts ne ressuscitent absolument pas, pourquoi se font-ils baptiser pour eux?",
 pt: "De outra maneira, que farão os que se batizam pelos mortos? Se absolutamente os mortos não ressuscitam, por que então se batizam por eles?",
 sv: "Vad kunna annars de som låta döpa sig för de dödas skull vinna därmed? Om så är att döda alls icke uppstå, varför låter man då döpa sig för deras skull?",
 no: "Hvad gjør da de som lar sig døpe for de døde? Dersom de døde i det hele tatt ikke opstår, hvorfor lar de sig da døpe for dem?",
 da: "Hvad skal det ellers til for, at nogle lader sig døbe for de døde? Hvis døde overhovedet ikke opstår, hvorfor lader de sig så døbe for dem?",
 },
 "1 Corinthians 15:40-42": {
 es: " Y cuerpos hay celestiales, y cuerpos terrestres; mas ciertamente una es la gloria de los celestiales, y otra la de los terrestres. Otra es la gloria del sol, y otra la gloria de la luna, y otra la gloria de las estrellas: porque una estrella es diferente de otra en gloria. Así también es la resurrección de los muertos. Se siembra en corrupción, se levantará en incorrupción;",
 fr: "Il y a aussi des corps célestes et des corps terrestres; mais autre est l'éclat des corps célestes, autre celui des corps terrestres. Autre est l'éclat du soleil, autre l'éclat de la lune, et autre l'éclat des étoiles; même une étoile diffère en éclat d'une autre étoile. Ainsi en est-il de la résurrection des morts. Le corps est semé corruptible; il ressuscite incorruptible;",
 pt: "Também há corpos celestes e corpos terrestres, mas uma é a glória dos celestes e outra a dos terrestres. Uma é a glória do sol, outra a glória da lua e outra a glória das estrelas; porque uma estrela difere em glória de outra estrela. Assim também é a ressurreição, é ressuscitado em incorrupção.",
 sv: "Så finnas ock både himmelska kroppar och jordiska kroppar, men de himmelska kropparnas härlighet är av ett slag, de jordiska kropparnas av ett annat slag. En härlighet har solen, en annan härlighet har månen, åter en annan härlighet hava stjärnorna; ja, den ena stjärnan är icke lik den andra i härlighet. -- Så är det ock med de dödas uppståndelse: vad som bliver sått förgängligt, det uppstår oförgängligt;",
 no: "Og der er himmelske legemer, og der er jordiske legemer; men én herlighet har de himmelske legemer, en annen de jordiske. Én glans har solen, og en annen månen, og en annen stjernene; for den ene stjerne skiller sig fra den andre i glans. Så er det og med de dødes opstandelse. Det såes i forgjengelighet; det opstår i uforgjengelighet;",
 da: "v40 Og der er himmelske legemer og jordiske legemer, men de himmelske legemers herlighed er én, og de jordiske legemers er en anden. v41 Én herlighed har solen, en anden månen og en tredje stjernerne, for den ene stjerne overstråles af den anden. v42 Sådan er det også med de dødes opstandelse. Hvad der sås i forgængelighed, opstår i uforgængelighed.",
 },
 "2 Corinthians 1:2-3": {
 es: " Gracia y paz á vosotros de Dios nuestro Padre, y del Señor Jesucristo. Bendito sea el Dios y Padre del Señor Jesucristo, el Padre de misericordias, y el Dios de toda consolación,",
 fr: "que la grâce et la paix vous soient données de la part de Dieu notre Père et du Seigneur Jésus-Christ! Béni soit Dieu, le Père de notre Seigneur Jésus-Christ, le Père des miséricordes et le Dieu de toute consolation,",
 pt: "Graça a vós, e paz da parte de Deus nosso Pai, e do Senhor Jesus Cristo. Bendito seja o Deus e Pai de nosso Senhor Jesus Cristo, o Pai das misericórdias e Deus de toda a consolação,",
 sv: "Nåd vare med eder och frid ifrån Gud, vår Fader, och Herren Jesus Kristus. Lovad vare vår Herres, Jesu Kristi, Gud och Fader, barmhärtighetens Fader och all trösts Gud,",
 no: "Nåde være med eder og fred fra Gud vår Fader og den Herre Jesus Kristus! Lovet være Gud og vår Herre Jesu Kristi Fader, miskunns Fader og all trøsts Gud,",
 da: "v2 Nåde være med jer og fred fra Gud, vor Fader, og Herren Jesus Kristus! v3 Lovet være Gud, vor Herre Jesu Kristi Fader, barmhjertighedens Fader og al trøsts Gud,",
 },
 "2 Corinthians 11:31": {
 es: " El Dios y Padre del Señor nuestro Jesucristo, que es bendito por siglos, sabe que no miento.",
 fr: "Dieu, qui est le Père du Seigneur Jésus, et qui est béni éternellement, sait que je ne mens point!...",
 pt: "O Deus e Pai do Senhor Jesus, que é eternamente bendito, sabe que não minto.",
 sv: "Herren Jesu Gud och Fader, han som är högtlovad i evighet, vet att jag icke ljuger.",
 no: "Gud og vår Herre Jesu Kristi Fader, han som er velsignet i evighet, vet at jeg ikke lyver!",
 da: "Gud, vor Herre Jesu Kristi Fader, han som er velsignet i evighed, ved, at jeg ikke lyver.",
 },
 "2 Corinthians 12:2": {
 es: " Conozco á un hombre en Cristo, que hace catorce años (si en el cuerpo, no lo sé; si fuera del cuerpo, no lo sé: Dios lo sabe) fué arrebatado hasta el tercer cielo.",
 fr: "Je connais un homme en Christ, qui fut, il y a quatorze ans, ravi jusqu'au troisième ciel si ce fut dans son corps je ne sais, si ce fut hors de son corps je ne sais, Dieu le sait).",
 pt: "Conheço um homem em Cristo que há catorze anos (se no corpo não sei, se fora do corpo não sei; Deus o sabe) foi arrebatado até o terceiro céu.",
 sv: "Jag vet om en man som är i Kristus, att han för fjorton år sedan blev uppryckt ända till tredje himmelen; huruvida det nu var i kroppslig måtto, eller om han var skild från sin kropp, det vet jag icke, Gud allena vet det.",
 no: "Jeg kjenner et menneske i Kristus - om han var i legemet, vet jeg ikke, eller utenfor legemet, vet jeg ikke; Gud vet det - en som for fjorten år siden blev rykket like inn i den tredje himmel.",
 da: "Jeg kender et menneske i Kristus, som for fjorten år siden – om det var i legemet, ved jeg ikke, eller uden for legemet, ved jeg ikke, Gud ved det – blev bortrykket til den tredje himmel.",
 },
 "2 Corinthians 13:1": {
 es: " ESTA tercera vez voy á vosotros. En la boca de dos ó de tres testigos consistirá todo negocio.",
 fr: "Je vais chez vous pour la troisième fois. Toute affaire se réglera sur la déclaration de deux ou de trois témoins.",
 pt: "É esta a terceira vez que vou ter convosco. Por boca de duas ou três testemunhas será confirmada toda palavra.",
 sv: "Det är nu tredje gången som jag skall komma till eder; »efter två eller tre vittnens utsago skall var sak avgöras».",
 no: "Det er nu tredje gang jeg kommer til eder. Ved to og tre vidners ord skal hver sak stå fast.",
 da: "For tredje gang kommer jeg nu til jer. ›På to eller tre vidners mundtlige udsagn skal enhver sag afgøres.‹",
 },
 "1 Corinthians 6:9-10": {
 es: " ¿No sabéis que los injustos no poseerán el reino de Dios? No erréis, que ni los fornicarios, ni los idólatras, ni los adúlteros, ni los afeminados, ni los que se echan con varones, Ni los ladrones, ni los avaros, ni los borrachos, ni los maldicientes, ni los robadores, heredarán el reino de Dios.",
 fr: "Ne savez-vous pas que les injustes n'hériteront point le royaume de Dieu? Ne vous y trompez pas: ni les impudiques, ni les idolâtres, ni les adultères, ni les efféminés, ni les infâmes, ni les voleurs, ni les cupides, ni les ivrognes, ni les outrageux, ni les ravisseurs, n'hériteront le royaume de Dieu.",
 pt: "Não sabeis que os injustos não herdarão o reino de Deus? Não vos enganeis: nem os devassos, nem os idólatras, nem os adúlteros, nem os efeminados, nem os sodomitas, nem os ladrões, nem os avarentos, nem os bêbedos, nem os maldizentes, nem os roubadores herdarão o reino de Deus.",
 sv: "Veten I då icke att de orättfärdiga icke skola få Guds rike till arvedel? Faren icke vilse. Varken otuktiga människor eller avgudadyrkare eller äktenskapsbrytare, varken de som låta bruka sig till synd mot naturen eller de som själva öva sådan synd, varken tjuvar eller giriga eller drinkare eller smädare eller roffare skola få Guds rike till arvedel.",
 no: "Eller vet I ikke at de som gjør urett, ikke skal arve Guds rike? Far ikke vill! Hverken horkarler eller avgudsdyrkere eller ekteskapsbrytere eller bløtaktige eller de som synder mot naturen, eller tyver eller havesyke eller drankere eller baktalere eller røvere skal arve Guds rike.",
 da: "v9 Eller ved I ikke, at uretfærdige ikke skal arve Guds rige? Far ikke vild! Hverken utugtige eller afgudsdyrkere eller ægteskabsbrydere eller mænd, der ligger i med mænd, v10 eller tyve eller griske mennesker, ingen drukkenbolte, ingen spottere, ingen røvere skal arve Guds rige.",
 },
 "2 Corinthians 5:9-10": {
 es: " Por tanto procuramos también, ó ausentes, ó presentes, serle agradables: Porque es menester que todos nosotros parezcamos ante el tribunal de Cristo, para que cada uno reciba según lo que hubiere hecho por medio del cuerpo, ora sea bueno ó malo.",
 fr: "C'est pour cela aussi que nous nous efforçons de lui être agréables, soit que nous demeurions dans ce corps, soit que nous le quittions. Car il nous faut tous comparaître devant le tribunal de Christ, afin que chacun reçoive selon le bien ou le mal qu'il aura fait, étant dans son corps.",
 pt: "Pelo que também nos esforçamos para ser-lhe agradáveis, quer presentes, quer ausentes. Porque é necessário que todos nós sejamos manifestos diante do tribunal de Cristo, para que cada um receba o que fez por meio do corpo, segundo o que praticou, o bem ou o mal.",
 sv: "Därför söka vi ock vår ära i att vara honom till behag, vare sig vi äro hemma eller borta. Ty vi måste alla, sådana vi äro, träda fram inför Kristi domstol, för att var och en skall få igen sitt jordelivs gärningar, alltefter som han har handlat, vare sig han har gjort gott eller ont.",
 no: "Derfor setter vi og vår ære i, enten vi er hjemme eller borte, å tekkes ham. For vi skal alle åpenbares for Kristi domstol, forat enhver kan få igjen det som er skjedd ved legemet, efter det som han har gjort, enten godt eller ondt.",
 da: "Derfor sætter vi en ære i at være ham til behag, hvad enten vi er hjemme eller i fremmed land. For vi skal alle fremstilles for Kristi domstol, for at enhver kan få igen for det, han har gjort her i livet, hvad enten det er godt eller ondt.",
 },
 "Philippians 2:5-9": {
 es: " Haya, pues, en vosotros este sentir que hubo también en Cristo Jesús: El cual, siendo en forma de Dios, no tuvo por usurpación ser igual á Dios: Sin embargo, se anonadó á sí mismo, tomando forma de siervo, hecho semejante á los hombres; Y hallado en la condición como hombre, se humilló á sí mismo, hecho obediente hasta la muerte, y muerte de cruz. Por lo cual Dios también le ensalzó á lo sumo, y dióle un nombre que es sobre todo nombre;",
 fr: "Ayez en vous les sentiments qui étaient en Jésus-Christ, lequel, existant en forme de Dieu, n'a point regardé comme une proie à arracher d'être égal avec Dieu, mais s'est dépouillé lui-même, en prenant une forme de serviteur, en devenant semblable aux hommes; et ayant paru comme un simple homme, il s'est humilié lui-même, se rendant obéissant jusqu'à la mort, même jusqu'à la mort de la croix. C'est pourquoi aussi Dieu l'a souverainement élevé, et lui a donné le nom qui est au-dessus de tout nom,",
 pt: "Tende em vós aquele sentimento que houve também em Cristo Jesus, o qual, subsistindo em forma de Deus, não considerou o ser igual a Deus coisa a que se devia aferrar, mas esvaziou-se a si mesmo, tomando a forma de servo, tornando-se semelhante aos homens; e, achado na forma de homem, humilhou-se a si mesmo, tornando-se obediente até a morte, e morte de cruz. Pelo que também Deus o exaltou soberanamente, e lhe deu o nome que é sobre todo nome;",
 sv: "Varen så till sinnes som Kristus Jesus var, han som var till i Guds-skepnad, men icke räknade jämlikheten med Gud såsom ett byte, utan utblottade sig själv, i det han antog tjänare-skepnad, när han kom i människogestalt. Så befanns han i utvärtes måtto vara såsom en människa och ödmjukade sig och blev lydig intill döden, ja, intill döden på korset. Därför har ock Gud upphöjt honom över allting och givit honom det namn som är över alla namn",
 no: "La dette sinn være i eder, som og var i Kristus Jesus, han som, da han var i Guds skikkelse, ikke aktet det for et rov å være Gud lik, men av sig selv gav avkall på det og tok en tjeners skikkelse på sig, idet han kom i menneskers lignelse, og da han i sin ferd var funnet som et menneske, fornedret han sig selv, så han blev lydig inntil døden, ja korsets død. Derfor har og Gud høit ophøiet ham og gitt ham det navn som er over alt navn,",
 da: "I skal have det sind i jer, som også var i Kristus Jesus, han, som da han var i guddomsskikkelse, ikke holdt det for et rov at være lige med Gud, men gav afkald på det, tog en tjeners skikkelse på og blev mennesker lig; og da han var trådt frem som et menneske, ydmygede han sig og blev lydig indtil døden, ja, døden på et kors. Derfor har Gud højt ophøjet ham og skænket ham navnet over alle navne,",
 },
 "Philippians 2:10-11": {
 es: " Para que en el nombre de Jesús se doble toda rodilla de los que están en los cielos, y de los que en la tierra, y de los que debajo de la tierra; Y toda lengua confiese que Jesucristo es el Señor, á la gloria de Dios Padre.",
 fr: "afin qu'au nom de Jésus tout genou fléchisse dans les cieux, sur la terre et sous la terre, et que toute langue confesse que Jésus-Christ est Seigneur, à la gloire de Dieu le Père.",
 pt: "para que ao nome de Jesus se dobre todo joelho dos que estão nos céus, e na terra, e debaixo da terra, e toda língua confesse que Jesus Cristo é Senhor, para glória de Deus Pai.",
 sv: "för att i Jesu namn alla knän skola böja sig, deras som äro i himmelen, och deras som äro på jorden, och deras som äro under jorden, och för att alla tungor skola bekänna, Gud, Fadern, till ära, att Jesus Kristus är Herre.",
 no: "så at i Jesu navn skal hvert kne bøie sig, deres som er i himmelen og på jorden og under jorden, Og hver tunge bekjenne at Jesus Kristus er Herre, til Gud Faders ære.",
 da: "for at i Jesu navn hvert knæ skal bøje sig, i himlen og på jorden og under jorden, og hver tunge bekende: Jesus Kristus er Herre, til Gud Faders ære.",
 },
 "Philippians 4:8": {
 es: " Por lo demás, hermanos, todo lo que es verdadero, todo lo honesto, todo lo justo, todo lo puro, todo lo amable, todo lo que es de buen nombre; si hay virtud alguna, si alguna alabanza, en esto pensad.",
 fr: "Au reste, frères, que tout ce qui est vrai, tout ce qui est honorable, tout ce qui est juste, tout ce qui est pur, tout ce qui est aimable, tout ce qui mérite l'approbation, ce qui est vertueux et digne de louange, soit l'objet de vos pensées.",
 pt: "Quanto ao mais, irmãos, tudo o que é verdadeiro, tudo o que é honesto, tudo o que é justo, tudo o que é puro, tudo o que é amável, tudo o que é de boa fama, se há alguma virtude, e se há algum louvor, nisso pensai.",
 sv: "För övrigt, mina bröder, vad sant är, vad värdigt, vad rätt, vad rent är, vad som är älskligt och värt att akta, ja, allt vad dygd heter, och allt som förtjänar att prisas -- tänken på allt sådant.",
 no: "For øvrig, brødre, alt som er sant, alt som er ære verdt, alt som er rettferdig, alt som er rent, alt som er elskelig, alt som tales vel om, enhver dyd, og alt det som priselig er - gi akt på det!",
 da: "I øvrigt, brødre, alt, hvad der er sandt, hvad der er ædelt, hvad der er ret, hvad der er rent, hvad der er værd at elske, hvad der er værd at tale godt om, kort sagt: det, der er en dyd, og det, der er ros værd, lad jeres tanker dvæle ved det.",
 },
 "1 Thessalonians 5:2": {
 es: " Porque vosotros sabéis bien, que el día del Señor vendrá así como ladrón de noche,",
 fr: "Car vous savez bien vous-mêmes que le jour du Seigneur viendra comme un voleur dans la nuit.",
 pt: "porque vós mesmos sabeis perfeitamente que o dia do Senhor virá como vem o ladrão de noite;",
 sv: "Ty I veten själva nogsamt att Herrens dag kommer såsom en tjuv om natten.",
 no: "I vet jo selv grant at Herrens dag kommer som en tyv om natten.",
 da: "for I ved selv ganske nøje, at Herrens dag kommer som en tyv om natten.",
 },
 "2 Thessalonians 2:1-3": {
 es: " EMPERO os rogamos, hermanos, cuanto á la venida de nuestro Señor Jesucristo, y nuestro recogimiento á él, Que no os mováis fácilmente de vuestro sentimiento, ni os conturbéis ni por espíritu, ni por palabra, ni por carta como nuestra, como que el día del Señor esté cerca. No os engañe nadie en ninguna manera; porque no vendrá sin que venga antes la apostasía, y se manifieste el hombre de pecado, el hijo de perdición,",
 fr: "Pour ce qui concerne l'avènement de notre Seigneur Jésus-Christ et notre réunion avec lui, nous vous prions, frères, de ne pas vous laisser facilement ébranler dans votre bon sens, et de ne pas vous laisser troubler, soit par quelque inspiration, soit par quelque parole, ou par quelque lettre qu'on dirait venir de nous, comme si le jour du Seigneur était déjà là. Que personne ne vous séduise d'aucune manière; car il faut que l'apostasie soit arrivée auparavant, et qu'on ait vu paraître l'homme du péché, le fils de la perdition,",
 pt: "Ora, quanto à vinda de nosso Senhor Jesus Cristo e à nossa reunião com ele, rogamos-vos, irmãos, que não vos movais facilmente do vosso modo de pensar, nem vos perturbeis, quer por espírito, quer por palavra, quer por epístola como enviada de nós, como se o dia do Senhor estivesse já perto. Ninguém de modo algum vos engane; porque isto não sucederá sem que venha primeiro a apostasia e seja revelado o homem do pecado, o filho da perdição,",
 sv: "I fråga om vår Herres, Jesu Kristi, tillkommelse, och huru vi skola församlas till honom, bedja vi eder, käre bröder, att I icke -- vare sig genom någon »andeingivelse» eller på grund av något ord eller något brev, som förmenas komma från oss -- så hastigt låten eder bringas ur fattningen och förloren besinningen, som om Herrens dag redan stode för dörren. Låten ingen bedraga eder om vad sätt det vara må. Ty först måste avfallet hava skett och »Laglöshetens människa», fördärvets man, hava trätt fram,",
 no: "Vi ber eder, brødre, vedkommende vår Herre Jesu Kristi komme og vår samling med ham, at I ikke så snart må la eder drive fra vett og sans eller la eder skremme, hverken ved nogen ånd eller ved nogen tale eller ved noget brev, likesom det skulde være fra oss, som om Herrens dag stod for døren. La ingen dåre eder på nogen måte! for først må frafallet komme, og syndens menneske åpenbares, fortapelsens sønn,",
 da: "Brødre, hvad vor Herre Jesu Kristi komme og vor samling hos ham angår, beder vi jer om ikke så hurtigt at lade jer bringe fra besindelsen eller blive forfærdede, hverken ved en profeti eller ved et ord eller ved et brev, der skulle være fra os, om at Herrens dag er nær. Lad ingen på nogen måde vildlede jer. For først må faldet komme og den lovløse, fortabelsens søn, åbenbares,",
 },
 "Acts 17:30-31": {
 es: " Empero Dios, habiendo disimulado los tiempos de esta ignorancia, ahora denuncia á todos los hombres en todos los lugares que se arrepientan: Por cuanto ha establecido un día, en el cual ha de juzgar al mundo con justicia, por aquel varón al cual determinó; dando fe á todos con haberle levantado de los muertos.",
 fr: "Dieu, sans tenir compte des temps d'ignorance, annonce maintenant à tous les hommes, en tous lieux, qu'ils aient à se repentir, parce qu'il a fixé un jour où il jugera le monde selon la justice, par l'homme qu'il a désigné, ce dont il a donné à tous une preuve certaine en le ressuscitant des morts...",
 pt: "Mas Deus, não levando em conta os tempos da ignorância, manda agora que todos os homens em todo lugar se arrependam; porquanto determinou um dia em que com justiça há de julgar o mundo, por meio do varão que para isso ordenou; e disso tem dado certeza a todos, ressuscitando-o dentre os mortos.",
 sv: "Med sådana okunnighetens tider har Gud hittills haft fördrag, men nu bjuder han människorna att de alla allestädes skola göra bättring. Ty han har fastställt en dag då han skall 'döma världen med rättfärdighet', genom en man som han har bestämt därtill; och han har åt alla givit en bekräftelse härpå, i det att han har låtit honom uppstå från de döda.»",
 no: "Efterat Gud da har båret over med vankundighetens tider, byder han nu menneskene at de alle allesteds skal omvende sig, eftersom han har fastsatt en dag da han skal dømme verden med rettferdighet ved en mann som han har bestemt til det, efterat han har gitt fullgodt bevis for alle ved å opreise ham fra de døde.",
 da: "Gud har handlet i uvidenhedens tider, men nu befaler han alle mennesker alle vegne, at de skal omvende sig. For han har fastsat en dag, da han vil dømme hele verden med retfærdighed ved en mand, som han har bestemt dertil; og det har han gjort troværdigt for alle ved at lade ham opstå fra de døde.",
 },
 "Romans 2:12": {
 es: " Porque todos los que sin ley pecaron, sin ley también perecerán; y todos los que en la ley pecaron, por la ley serán juzgados:",
 fr: "Tous ceux qui ont péché sans la loi périront aussi sans la loi, et tous ceux qui ont péché avec la loi seront jugés par la loi.",
 pt: "Porque todos os que sem lei pecaram, sem lei também perecerão; e todos os que sob a lei pecaram, pela lei serão julgados.",
 sv: "alla de som utan lag hava syndat skola ock utan lag förgås, och alla de som med lag hava syndat skola genom lag bliva dömda.",
 no: "alle som syndet uten loven, skal også gå fortapt uten loven, og alle som syndet under loven, skal dømmes ved loven;",
 da: "Alle de, der har syndet uden loven, skal også gå fortabt uden loven, og alle de, der har syndet under loven, skal dømmes af loven.",
 },
 "Romans 4:24-25": {
 es: " Sino también por nosotros, á quienes será imputado, esto es, á los que creemos en el que levantó de los muertos á Jesús Señor nuestro, El cual fué entregado por nuestros delitos, y resucitado para nuestra justificación.",
 fr: "c'est encore à cause de nous, à qui cela sera imputé, à nous qui croyons en celui qui a ressuscité des morts Jésus notre Seigneur, lequel a été livré pour nos offenses, et est ressuscité pour notre justification.",
 pt: "mas também por causa de nós a quem há de ser imputado, a nós os que cremos naquele que dos mortos ressuscitou a Jesus nosso Senhor; o qual foi entregue por causa das nossas transgressões, e ressuscitado para a nossa justificação.",
 sv: "utan det skulle gälla också oss; ty det skall tillräknas jämväl oss, oss som tro på honom som från de döda uppväckte Jesus, vår Herre, vilken utgavs för våra synders skull och uppväcktes för vår rättfärdiggörelses skull.",
 no: "men også for vår skyld, som det vil bli tilregnet, vi som tror på ham som opvakte Jesus, vår Herre, fra de døde, han som blev gitt for våre overtredelser og opreist til vår rettferdiggjørelse.",
 da: "men også for vor skyld, vi, som skal få retfærdigheden tilregnet, vi, som tror på ham, der oprejste Jesus, vor Herre, fra de døde, ham, som blev givet hen for vore overtrædelser og blev oprejst for vor retfærdiggørelses skyld.",
 },
 "Romans 8:16-17": {
 es: " Porque el mismo Espíritu da testimonio á nuestro espíritu que somos hijos de Dios. Y si hijos, también herederos; herederos de Dios, y coherederos de Cristo; si empero padecemos juntamente con él, para que juntamente con él seamos glorificados.",
 fr: "L'Esprit lui-même rend témoignage à notre esprit que nous sommes enfants de Dieu. Or, si nous sommes enfants, nous sommes aussi héritiers: héritiers de Dieu, et cohéritiers de Christ, si toutefois nous souffrons avec lui, afin d'être glorifiés avec lui.",
 pt: "O Espírito mesmo testifica com o nosso espírito que somos filhos de Deus; e, se filhos, também herdeiros, herdeiros de Deus e co-herdeiros de Cristo; se é certo que com ele padecemos, para que também com ele sejamos glorificados.",
 sv: "Anden själv vittnar med vår ande att vi äro Guds barn. Men äro vi barn, så äro vi ock arvingar, nämligen Guds arvingar och Kristi medarvingar, om vi eljest lida med honom, för att också med honom bliva förhärligade.",
 no: "Ånden selv vidner med vår ånd at vi er Guds barn; men er vi barn, da er vi også arvinger, Guds arvinger og Kristi medarvinger, såfremt vi lider med ham, forat vi også skal herliggjøres med ham.",
 da: "Ånden selv vidner sammen med vor ånd om, at vi er Guds børn. Men når vi er børn, er vi også arvinger, Guds arvinger og Kristi medarvinger, så sandt som vi lider med ham, for at vi også skal herliggøres med ham.",
 },
 "Romans 8:32-33": {
 es: " El que aun á su propio Hijo no perdonó, antes le entregó por todos nosotros, ¿cómo no nos dará también con él todas las cosas? ¿Quién acusará á los escogidos de Dios? Dios es el que justifica.",
 fr: "Lui, qui n'a point épargné son propre Fils, mais qui l'a livré pour nous tous, comment ne nous donnera-t-il pas aussi toutes choses avec lui? Qui accusera les élus de Dieu? C'est Dieu qui justifie!",
 pt: "Aquele que nem mesmo a seu próprio Filho poupou, antes o entregou por todos nós, como não nos dará também com ele todas as coisas? Quem intentará acusação contra os escolhidos de Deus? É Deus quem os justifica;",
 sv: "Han som icke har skonat sin egen Son, utan utgivit honom för oss alla, huru skulle han kunna annat än också skänka oss allt med honom? Vem vill anklaga Guds utvalda? Gud är den som rättfärdiggör.",
 no: "Han som ikke sparte sin egen Sønn, men gav ham for oss alle, hvorledes skal han kunne annet enn gi oss alle ting med ham? Hvem vil anklage Guds utvalgte? Gud er den som rettferdiggjør;",
 da: "Han, som ikke sparede sin egen søn, men gav ham hen for os alle, vil han ikke med ham skænke os alt? Hvem vil anklage Guds udvalgte? Gud er den, der gør retfærdig.",
 },
 "1 Peter 1:19-20": {
 es: " Sino con la sangre preciosa de Cristo, como de un cordero sin mancha y sin contaminación: Ya ordenado de antes de la fundación del mundo, pero manifestado en los postrimeros tiempos por amor de vosotros,",
 fr: "mais par le sang précieux de Christ, comme d'un agneau sans défaut et sans tache, prédestiné avant la fondation du monde, et manifesté à la fin des temps, à cause de vous,",
 pt: "mas com precioso sangue, como de um cordeiro sem defeito e sem mancha, o sangue de Cristo, o qual, na verdade, foi conhecido ainda antes da fundação do mundo, mas manifesto no fim dos tempos por amor de vós,",
 sv: "Så mycket fastare står nu också för oss det profetiska ordet; och I gören väl, om I akten därpå, såsom på ett ljus som lyser i en dyster vildmark, till dess att dagen gryr, och morgonstjärnan går upp i edra hjärtan. Men det mån I framför allt veta, att ingen profetia i något skriftens ord kan av någon människas egen kraft utläggas.",
 no: "men med Kristi dyre blod som blodet av et ulastelig og lyteløst lam, han som forut var kjent, før verdens grunnvoll blev lagt, men blev åpenbaret ved tidenes ende for eders skyld,",
 da: "men med Kristi dyrebare blod som med blodet af et lam uden fejl og plet. v20 Han var bestemt dertil, før verden blev grundlagt, men er åbenbaret nu ved tidernes ende af hensyn til jer.",
 },
 "1 Peter 1:21": {
 es: " Que por él creéis á Dios, el cual le resucitó de los muertos, y le ha dado gloria, para que vuestra fe y esperanza sea en Dios.",
 fr: "qui par lui croyez en Dieu, lequel l'a ressuscité des morts et lui a donné la gloire, en sorte que votre foi et votre espérance reposent sur Dieu.",
 pt: "que por ele credes em Deus, que o ressuscitou dentre os mortos e lhe deu glória, de modo que a vossa fé e esperança estivessem em Deus.",
 sv: "Ty ingen profetia har någonsin framkommit av en människas vilja, utan därigenom att människor, drivna av den helige Ande, talade vad som gavs dem från Gud.",
 no: "I som ved ham tror på Gud, som opvakte ham fra de døde og gav ham herlighet, så at eders tro også er håp til Gud.",
 da: "der ved ham tror på Gud, som oprejste ham fra de døde og gav ham herlighed, så at jeres tro også er håb til Gud.",
 },
 "1 Peter 3:18-20": {
 es: " Porque también Cristo padeció una vez por los pecados, el justo por los injustos, para llevarnos á Dios, siendo á la verdad muerto en la carne, pero vivificado en espíritu; En el cual también fué y predicó á los espíritus encarcelados; Los cuales en otro tiempo fueron desobedientes, cuando una vez esperaba la paciencia de Dios en los días de Noé, cuando se aparejaba el arca; en la cual pocas, es á saber, ocho personas fueron salvas por agua.",
 fr: "Christ aussi a souffert une fois pour les péchés, lui juste pour des injustes, afin de nous amener à Dieu, ayant été mis à mort quant à la chair, mais ayant été rendu vivant quant à l'Esprit, dans lequel aussi il est allé prêcher aux esprits en prison, qui autrefois avaient été incrédules, lorsque la patience de Dieu se prolongeait, aux jours de Noé, pendant la construction de l'arche, dans laquelle un petit nombre de personnes, c'est-à-dire, huit, furent sauvées à travers l'eau.",
 pt: "Porque também Cristo morreu uma só vez pelos pecados, o justo pelos injustos, para levar-nos a Deus; sendo, na verdade, morto na carne, mas vivificado no espírito; no qual também foi, e pregou aos espíritos em prisão; os quais noutro tempo foram rebeldes, quando a longanimidade de Deus esperava, nos dias de Noé, enquanto se preparava a arca; na qual poucas, isto é, oito almas se salvaram através da água,",
 sv: "Växen i stället till i nåd och i kunskap om vår Herre och Frälsare, Jesus Kristus. Honom tillhör äran, nu och till evighetens dag. Amen.",
 no: "For også Kristus led en gang for synder, en rettferdig for urettferdige, for å føre oss frem til Gud, han som led døden i kjødet, men blev levendegjort i ånden, og i denne gikk han og bort og preket for åndene som var i varetekt, de som fordum hadde vært gjenstridige, dengang da Guds langmodighet ventet i Noahs dager, mens arken blev bygget, i hvilken nogen få - åtte sjeler - blev frelst ved vann,",
 da: "For også Kristus led én gang for synders skyld, en retfærdig for uretfærdiges, for at føre jer til Gud. Han blev dræbt i kødet, men gjort levende i Ånden, v19 og i den gik han også hen og prædikede for ånderne i fængslet. v20 Det var dem, som i Noas dage var ulydige, dengang Gud i sin langmodighed ventede, mens arken blev bygget. I den blev kun nogle få, otte sjæle i alt, frelst gennem vand.",
 },
 "1 Peter 3:22": {
 es: " El cual está á la diestra de Dios, habiendo subido al cielo; estando á él sujetos los ángeles, y las potestades, y virtudes.",
 fr: "qui est à la droite de Dieu, depuis qu'il est allé au ciel, et que les anges, les autorités et les puissances, lui ont été soumis.",
 pt: "que está à destra de Deus, tendo subido ao céu; havendo-se-lhe sujeitado os anjos, e as autoridades, e as potestades.",
 no: "han som er faret op til himmelen og er ved Guds høire hånd, hvor engler og makter og krefter er ham underlagt.",
 sv: "som är på Guds högra sida, sedan han farit upp till himlen, och alla änglar och makter och krafter är honom underlagda.",
 da: "Han er faret op til himlen og sidder ved Guds højre hånd, og engle og magter og myndigheder er ham underlagt.",
 },
 "1 Peter 4:6": {
 es: " Porque por esto también ha sido predicado el evangelio á los muertos; para que sean juzgados en carne según los hombres, y vivan en espíritu según Dios.",
 fr: "Car l'Evangile a été aussi annoncé aux morts, afin que, après avoir été jugés comme les hommes quant à la chair, ils vivent selon Dieu quant à l'Esprit.",
 pt: "Pois é por isto que foi pregado o evangelho até aos mortos, para que, na verdade, fossem julgados segundo os homens na carne, mas vivessem segundo Deus em espírito.",
 no: "For derfor blev evangeliet forkynt også for døde at de visstnok skulde dømmes som mennesker i kjødet, men leve således som Gud i ånden.",
 sv: "Ty därför blev evangeliet predikat också för de döda, att de skulle bli dömda som människor i köttet, men leva efter Gud i anden.",
 da: "For derfor blev evangeliet også forkyndt for døde, for at de, skønt dømt på kødet for menneskers øjne, skulle leve i Ånden for Guds øjne.",
 },
 "2 Peter 1:3-4": {
 es: " Como todas las cosas que pertenecen á la vida y á la piedad nos sean dadas de su divina potencia, por el conocimiento de aquel que nos ha llamado por su gloria y virtud: Por las cuales nos son dadas preciosas y grandísimas promesas, para que por ellas fueseis hechos participantes de la naturaleza divina, habiendo huído de la corrupción que está en el mundo por concupiscencia.",
 fr: "Comme sa divine puissance nous a donné tout ce qui contribue à la vie et à la piété, au moyen de la connaissance de celui qui nous a appelés par sa propre gloire et par sa vertu, lesquelles nous assurent de sa part les plus grandes et les plus précieuses promesses, afin que par elles vous deveniez participants de la nature divine, en fuyant la corruption qui existe dans le monde par la convoitise,",
 pt: "visto como o seu divino poder nos tem dado tudo o que diz respeito à vida e à piedade, pelo pleno conhecimento daquele que nos chamou por sua própria glória e virtude; pelas quais ele nos tem dado as suas preciosas e grandíssimas promessas, para que por elas vos torneis participantes da natureza divina, havendo escapado da corrupção, que pela concupiscência há no mundo.",
 sv: "Ja, det vi hava sett och hört, det förkunna vi ock för eder, på det att också I mån hava gemenskap med oss; och vi hava vår gemenskap med Fadern och med hans Son, Jesus Kristus. Och vi skriva nu detta, för att vår glädje skall bliva fullkomlig.",
 no: "Eftersom hans guddommelige makt har gitt oss alt som tjener til liv og gudsfrykt, ved kunnskapen om ham som kalte oss ved sin egen herlighet og kraft og derved har gitt oss de største og dyreste løfter, forat I ved dem skulde få del i guddommelig natur, idet I flyr bort fra fordervelsen i verden, som kommer av lysten,",
 da: "Hans guddommelige kraft har skænket os alt, hvad der skal til for at leve og være gudfrygtig; det sker ved at kende ham, som kaldte os med sin herlighed og styrke v4 og dermed har skænket os sine dyrebare og største løfter, for at I ved dem kan få del i guddommelig natur, når I er undsluppet fordærvelsen i verden med dens begær.",
 },
 "2 Peter 1:19-21": {
 es: " Tenemos también la palabra profética más permanente, á la cual hacéis bien de estar atentos como á una antorcha que alumbra en lugar oscuro hasta que el día esclarezca, y el lucero de la mañana salga en vuestros corazones: Entendiendo primero esto, que ninguna profecía de la Escritura es de particular interpretación; Porque la profecía no fué en los tiempos pasados traída por voluntad humana, sino los santos hombres de Dios hablaron siendo inspirados del Espíritu Santo.",
 fr: "Et nous tenons pour d'autant plus certaine la parole prophétique, à laquelle vous faites bien de prêter attention, comme à une lampe qui brille dans un lieu obscur, jusqu'à ce que le jour vienne à paraître et que l'étoile du matin se lève dans vos coeurs; sachant tout d'abord vous-mêmes qu'aucune prophétie de l'Ecriture ne peut être un objet d'interprétation particulière, car ce n'est pas par une volonté d'homme qu'une prophétie a jamais été apportée, mais c'est poussés par le Saint-Esprit que des hommes ont parlé de la part de Dieu.",
 pt: "E temos ainda mais firme a palavra profética à qual bem fazeis em estar atentos, como a uma candeia que alumia em lugar escuro, até que o dia amanheça e a estrela da alva surja em vossos corações; sabendo primeiramente isto: que nenhuma profecia da Escritura é de particular interpretação. Porque a profecia nunca foi produzida por vontade dos homens, mas os homens da parte de Deus falaram movidos pelo Espírito Santo.",
 no: "Og dess fastere har vi det profetiske ord, som I gjør vel i å akte på som på et lys som skinner på et mørkt sted, inntil dagen lyser frem og morgenstjernen går op i eders hjerter, idet I først og fremst vet dette at intet profetord i Skriften er gitt til egen tydning; for aldri er noget profetord fremkommet ved et menneskes vilje, men de hellige Guds menn talte drevet av den Hellige Ånd.",
 sv: "Så mycket fastare står nu profetordet för oss, och ni gör väl i att hålla er till det som till ett ljus som lyser på en mörk plats, tills dagen gryr och morgonstjärnan går upp i era hjärtan. Framför allt ska ni veta att ingen profetia i Skriften har kommit till genom egen tolkning. Ty ingen profetia har någonsin kommit fram genom en människas vilja, utan heliga människor från Gud har talat, drivna av den helige Ande.",
 da: "Og desto fastere står profeternes ord for os, og det gør I ret i at være opmærksomme på som på en lampe, der skinner på et mørkt sted, indtil dagen bryder frem, og morgenstjernen stiger op i jeres hjerter. v20 Men først og fremmest skal I vide, at ingen profeti i Skriften er til at tyde på egen hånd. v21 For ingen profeti er nogensinde kommet af et menneskes vilje, men drevet af Helligånden har mennesker sagt det, der kom fra Gud.",
 },
 "Romans 2:13": {
 es: " Porque no los oidores de la ley son justos para con Dios, mas los hacedores de la ley serán justificados.",
 fr: "Ce ne sont pas, en effet, ceux qui écoutent la loi qui sont justes devant Dieu, mais ce sont ceux qui la mettent en pratique qui seront justifiés.",
 pt: "Pois não são justos diante de Deus os que só ouvem a lei; mas serão justificados os que praticam a lei",
 sv: "Ty icke lagens hörare äro rättfärdiga inför Gud, men lagens görare skola förklaras rättfärdiga.",
 no: "for ikke de som hører loven, er rettferdige for Gud, men de som gjør efter loven, skal bli rettferdiggjort.",
 da: "For det er ikke dem, der hører loven, der er retfærdige for Gud, men det er dem, der gør efter loven, der vil blive erklæret retfærdige.",
 },
 "1 Peter 4:17-18": {
 es: " Porque es tiempo de que el juicio comience de la casa de Dios: y si primero comienza por nosotros, ¿qué será el fin de aquellos que no obedecen al evangelio de Dios? Y si el justo con dificultad se salva, ¿á dónde aparecerá el infiel y el pecador?",
 fr: "Car c'est le moment où le jugement va commencer par la maison de Dieu. Or, si c'est par nous qu'il commence, quelle sera la fin de ceux qui n'obéissent pas à l'Evangile de Dieu? Et si le juste se sauve avec peine, que deviendront l'impie et le pécheur?",
 pt: "Porque já é tempo que comece o julgamento pela casa de Deus; e se começa por nós, qual será o fim daqueles que desobedecem ao evangelho de Deus? E se o justo dificilmente se salva, onde comparecerá o ímpio pecador?",
 no: "For det er nu tiden da dommen skal begynne med Guds hus; men begynner det med oss, hvad blir da enden for dem som ikke vil tro Guds evangelium? Og blir den rettferdige vanskelig frelst, hvor skal det da bli av den ugudelige og synderen?",
 sv: "Ty tiden är inne för domen att börja, och den börjar med Guds hus. Men om den börjar med oss, vad blir då slutet för dem som inte lyder Guds evangelium? Och om den rättfärdige med knapp nöd blir frälst, var skall då den ogudaktige och syndaren visa sig?",
 da: "For nu er det tiden, da dommen skal begynde, og den skal begynde med Guds hus. Men begynder den med os, hvordan vil det så ikke ende for dem, der ikke tror på Guds evangelium? v18 Og hvis den retfærdige med nød og næppe frelses, hvordan vil det så ikke gå den ugudelige og synderen?",
 },
 "2 Peter 3:9": {
 es: " El Señor no tarda su promesa, como algunos la tienen por tardanza; sino que es paciente para con nosotros, no queriendo que ninguno perezca, sino que todos procedan al arrepentimiento.",
 fr: "Le Seigneur ne tarde pas dans l'accomplissement de la promesse, comme quelques-uns le croient; mais il use de patience envers vous, ne voulant pas qu'aucun périsse, mais voulant que tous arrivent à la repentance.",
 pt: "O Senhor não retarda a sua promessa, ainda que alguns a têm por tardia; porém é longânimo para convosco, não querendo que ninguém se perca, senão que todos venham a arrepender-se.",
 sv: "Var och en som är född av Gud, han gör icke synd, ty Guds säd förbliver i honom; han kan icke synda, eftersom han är född av Gud.",
 no: "Herren er ikke sen med løftet, således som nogen akter det for senhet, men han har langmodighet med eder, da han ikke vil at nogen skal fortapes, men at alle skal komme til omvendelse.",
 da: "Herren er ikke sen til at opfylde sit løfte, sådan som nogle mener, men han er langmodig over for jer, fordi han ikke vil, at nogen skal gå fortabt, men at alle skal nå til omvendelse.",
 },
 "2 Peter 3:14": {
 es: " Por lo cual, oh amados, estando en esperanza de estas cosas, procurad con diligencia que seáis hallados de él sin mácula, y sin reprensión, en paz.",
 fr: "C'est pourquoi, bien-aimés, en attendant ces choses, appliquez-vous à être trouvés par lui sans tache et irrépréhensibles dans la paix.",
 pt: "Pelo que, amados, como estais aguardando estas coisas, procurai diligentemente que por ele sejais achados imaculados e irrepreensível em paz;",
 sv: "Vi veta att vi hava övergått från döden till livet, ty vi älska bröderna. Den som icke älskar, han förbliver i döden.",
 no: "Derfor, elskede, da I venter dette, så legg vinn på å bli funnet uten flekk og lyte for ham i fred,",
 da: "Derfor, mine kære, skal I, mens I venter på dette, stræbe efter at findes uden plet og lyde, i fred med ham.",
 },
 "Galatians 1:6-8": {
 es: " Estoy maravillado de que tan pronto os hayáis traspasado del que os llamó á la gracia de Cristo, á otro evangelio: No que hay otro, sino que hay algunos que os inquietan, y quieren pervertir el evangelio de Cristo. Mas aun si nosotros ó un ángel del cielo os anunciare otro evangelio del que os hemos anunciado, sea anatema.",
 fr: "Je m'étonne que vous vous détourniez si promptement de celui qui vous a appelés par la grâce de Christ, pour passer à un autre Evangile. Non pas qu'il y ait un autre Evangile, mais il y a des gens qui vous troublent, et qui veulent renverser l'Evangile de Christ. Mais, quand nous-mêmes, quand un ange du ciel annoncerait un autre Evangile que celui que nous vous avons prêché, qu'il soit anathème!",
 pt: "Estou admirado de que tão depressa estejais desertando daquele que vos chamou na graça de Cristo, para outro evangelho, o qual não é outro; senão que há alguns que vos perturbam e querem perverter o evangelho de Cristo. Mas, ainda que nós mesmos ou um anjo do céu vos pregasse outro evangelho além do que já vos pregamos, seja anátema.",
 sv: "Det förundrar mig att I så hastigt avfallen från honom, som har kallat eder till att vara i Kristi nåd, och vänden eder till ett nytt evangelium. Likväl är detta icke något annat »evangelium»; det är allenast så, att några finnas som vålla förvirring bland eder och vilja förvända Kristi evangelium. Men om någon, vore det ock vi själva eller en ängel från himmelen, förkunnar evangelium i strid mot vad vi hava förkunnat för eder, så vare han förbannad.",
 no: "Jeg undrer mig over at I så snart vender eder bort fra ham som kalte eder ved Kristi nåde, til et annet evangelium, skjønt der ikke er noget annet; det er bare nogen som forvirrer eder og vil forvrenge Kristi evangelium. Men selv om vi eller en engel fra himmelen forkynner eder et annet evangelium enn det som vi har forkynt eder, han være forbannet!",
 da: "Jeg undrer mig over, at I så hurtigt lader jer føre bort fra ham, der kaldte jer ved Kristi nåde, til et andet evangelium. v7 Det er bare ikke et evangelium; der er bare nogle, som forvirrer jer og søger at forvrænge evangeliet om Kristus. v8 Men om så vi selv eller en engel fra himlen forkyndte jer et andet evangelium end det, vi har forkyndt jer, forbandet være han.",
 },
 "Galatians 1:11-12": {
 es: " Mas os hago saber, hermanos, que el evangelio que ha sido anunciado por mí, no es según hombre; Pues ni yo lo recibí, ni lo aprendí de hombre, sino por revelación de Jesucristo.",
 fr: "Je vous déclare, frères, que l'Evangile qui a été annoncé par moi n'est pas de l'homme; car je ne l'ai ni reçu ni appris d'un homme, mais par une révélation de Jésus-Christ.",
 pt: "Mas faço-vos saber, irmãos, que o evangelho que por mim foi anunciado não é segundo os homens; porque não o recebi de homem algum, nem me foi ensinado; mas o recebi por revelação de Jesus Cristo.",
 sv: "Ty det vill jag säga eder, mina bröder, att det evangelium som har blivit förkunnat av mig icke är någon människolära. Det är ju icke heller av någon människa som jag har undfått det eller blivit undervisad däri, utan genom en uppenbarelse från Jesus Kristus.",
 no: "Jeg kunngjør eder, brødre, at det evangelium som er blitt forkynt av mig, ikke er menneske-verk; for heller ikke jeg har mottatt det eller lært det av noget menneske, men ved Jesu Kristi åpenbaring.",
 da: "For jeg lader jer vide, brødre, at det evangelium, som er forkyndt af mig, ikke er menneskeværk; v12 jeg har heller ikke modtaget eller lært det af et menneske, men ved en åbenbaring af Jesus Kristus.",
 },
 "Galatians 1:19": {
 es: " Mas á ningún otro de los apóstoles vi, sino á Jacobo el hermano del Señor.",
 fr: "Mais je ne vis aucun autre des apôtres, si ce n'est Jacques, le frère du Seigneur.",
 pt: "Mas não vi a nenhum outro dos apóstolos, senão a Tiago, irmão do Senhor.",
 sv: "Men av de andra apostlarna såg jag ingen; allenast Jakob, Herrens broder, såg jag.",
 no: "men nogen annen av apostlene så jeg ikke, uten Jakob, Herrens bror.",
 da: "Men andre af apostlene så jeg ikke, kun Jakob, Herrens bror.",
 },
 "Galatians 4:7": {
 es: " Así que ya no eres más siervo, sino hijo; y si hijo, también heredero de Dios por Cristo.",
 fr: "Ainsi tu n'es plus esclave, mais fils; et si tu es fils, tu es aussi héritier par la grâce de Dieu.",
 pt: "Portanto já não és mais servo, mas filho; e se és filho, és também herdeiro por Deus.",
 sv: "Så är du nu icke mer träl, utan son; och är du son, så är du ock arvinge, insatt därtill av Gud.",
 no: "Så er du da ikke lenger træl, men sønn; men er du sønn, da er du og arving ved Gud.",
 da: "Så er du ikke længere træl, men søn. Og er du søn, er du også arving, indsat af Gud.",
 },
 "Galatians 5:1": {
 es: " ESTAD, pues, firmes en la libertad con que Cristo nos hizo libres, y no volváis otra vez á ser presos en el yugo de servidumbre.",
 fr: "C'est pour la liberté que Christ nous a affranchis. Demeurez donc fermes, et ne vous laissez pas mettre de nouveau sous le joug de la servitude.",
 pt: "Para a liberdade Cristo nos libertou; permanecei, pois, firmes e não vos dobreis novamente a um jogo de escravidão.",
 sv: "För att vi skola vara fria, har Kristus frigjort oss. Stån därför fasta, och låten icke något nytt träldomsok läggas på eder.",
 no: "Til frihet har Kristus frigjort oss; stå derfor fast, og la eder ikke atter legge under trældoms åk!",
 da: "Til den frihed har Kristus befriet os. Stå derfor fast, og lad jer ikke atter tvinge under trælleåg.",
 },
 "Galatians 6:7": {
 es: " No os engañéis: Dios no puede ser burlado: que todo lo que el hombre sembrare, eso también segará.",
 fr: "Ne vous y trompez pas: on ne se moque pas de Dieu. Ce qu'un homme aura semé, il le moissonnera aussi.",
 pt: "Não vos enganeis; Deus não se deixa escarnecer; pois tudo o que o homem semear, isso também ceifará.",
 sv: "Faren icke vilse. Gud låter icke gäcka sig. Ty vad människan sår, det skall hon ock skörda.",
 no: "Far ikke vill! Gud lar sig ikke spotte; for det som et menneske sår, det skal han og høste.",
 da: "Far ikke vild! Gud lader sig ikke spotte. Hvad et menneske sår, skal det også høste.",
 },
 "Galatians 6:7-9": {
 es: " No os engañéis: Dios no puede ser burlado: que todo lo que el hombre sembrare, eso también segará. Porque el que siembra para su carne, de la carne segará corrupción; mas el que siembra para el Espíritu, del Espíritu segará vida eterna. No nos cansemos, pues, de hacer bien; que á su tiempo segaremos, si no hubiéremos desmayado.",
 fr: "Ne vous y trompez pas: on ne se moque pas de Dieu. Ce qu'un homme aura semé, il le moissonnera aussi. Celui qui sème pour sa chair moissonnera de la chair la corruption; mais celui qui sème pour l'Esprit moissonnera de l'Esprit la vie éternelle. Ne nous lassons pas de faire le bien; car nous moissonnerons au temps convenable, si nous ne nous relâchons pas.",
 pt: "Não vos enganeis; Deus não se deixa escarnecer; pois tudo o que o homem semear, isso também ceifará. Porque quem semeia na sua carne, da carne ceifará a corrupção; mas quem semeia no Espírito, do Espírito ceifará a vida eterna. E não nos cansemos de fazer o bem, porque a seu tempo ceifaremos, se não houvermos desfalecido.",
 sv: "Faren icke vilse. Gud låter icke gäcka sig. Ty vad människan sår, det skall hon ock skörda. Den som sår i sitt kötts åker, han skall av köttet skörda förgängelse, men den som sår i Andens åker, han skall av Anden skörda evigt liv. Och låtom oss icke förtröttas att göra vad gott är; ty om vi icke uppgivas, så skola vi, när tiden är inne, få inbärga vår skörd.",
 no: "Far ikke vill! Gud lar sig ikke spotte; for det som et menneske sår, det skal han og høste. For den som sår i sitt kjød, skal høste fordervelse av kjødet; men den som sår i Ånden, skal høste evig liv av Ånden. Men la oss gjøre det gode og ikke bli trette! for vi skal høste i sin tid, såfremt vi ikke går trett.",
 da: "7 Far ikke vild! Gud lader sig ikke spotte. Hvad et menneske sår, skal det også høste. 8 Den, der sår i sit kød, skal høste fordærv af kødet, men den, der sår i Ånden, skal høste evigt liv af Ånden. 9 Lad os ikke blive trætte af at gøre det gode, for vi skal høste til sin tid, så sandt vi ikke giver op.",
 },
 "Colossians 1:12-19": {
 es: " Dando gracias al Padre que nos hizo aptos para participar de la suerte de los santos en luz: Que nos ha librado de la potestad de las tinieblas, y trasladado al reino de su amado Hijo; En el cual tenemos redención por su sangre, la remisión de pecados: El cual es la imagen del Dios invisible, el primogénito de toda criatura. Porque por él fueron criadas todas las cosas que están en los cielos, y que están en la tierra, visibles é invisibles; sean tronos, sean dominios, sean principados, sean potestades; todo fué criado por él y para él. Y él es antes de todas las cosas, y por él todas las cosas subsisten: Y él es la cabeza del cuerpo que es la iglesia; él que es el principio, el primogénito de los muertos, para que en todo tenga el primado. Por cuanto agradó al Padre que en él habitase toda plenitud,",
 fr: "Rendez grâces au Père, qui vous a rendus capables d'avoir part à l'héritage des saints dans la lumière, qui nous a délivrés de la puissance des ténèbres et nous a transportés dans le royaume du Fils de son amour, en qui nous avons la rédemption, la rémission des péchés. Il est l'image du Dieu invisible, le premier-né de toute la création. Car en lui ont été créées toutes les choses qui sont dans les cieux et sur la terre, les visibles et les invisibles, trônes, dignités, dominations, autorités. Tout a été créé par lui et pour lui. Il est avant toutes choses, et toutes choses subsistent en lui. Il est la tête du corps de l'Eglise; il est le commencement, le premier-né d'entre les morts, afin d'être en tout le premier. Car Dieu a voulu que toute plénitude habitât en lui;",
 pt: "dando graças ao Pai que vos fez idôneos para participar da herança dos santos na luz, e que nos tirou do poder das trevas, e nos transportou para o reino do seu Filho amado; em quem temos a redenção, a saber, a remissão dos pecados; o qual é imagem do Deus invisível, o primogênito de toda a criação; porque nele foram criadas todas as coisas nos céus e na terra, as visíveis e as invisíveis, sejam tronos, sejam dominações, sejam principados, sejam potestades; tudo foi criado por ele e para ele. Ele é antes de todas as coisas, e nele subsistem todas as coisas; também ele é a cabeça do corpo, da igreja; é o princípio, o primogênito dentre os mortos, para que em tudo tenha a preeminência, porque aprouve a Deus que nele habitasse toda a plenitude,",
 sv: "och I skolen med glädje tacka Fadern, som har gjort eder skickliga till delaktighet i den arvslott som de heliga hava i ljuset. Ty han har frälst oss från mörkrets välde och försatt oss i sin älskade Sons rike. I honom hava vi förlossningen, förlåtelsen för våra synder, i honom som är den osynlige Gudens avbild och förstfödd före allt skapat. Ty i honom skapades allt i himmelen och på jorden, synligt såväl som osynligt, både tronänglar och herrar och furstar och väldigheter i andevärlden. Alltsammans har blivit skapat genom honom och till honom. Ja, han är till före allt annat, och alltsammans äger bestånd i honom. Och han är huvudet för kroppen, det är församlingen, han som är begynnelsen, den förstfödde ifrån de döda. Så skulle han i allt vara den främste. Ty det behagade Gud att låta all fullhet taga sin boning i honom",
 no: "så I med glede takker Faderen, som gjorde oss skikkede til å få del i de helliges arvelodd i lyset, han som fridde oss ut av mørkets makt og satte oss over i sin elskede Sønns rike, i hvem vi har forløsningen, syndenes forlatelse. Og han er et billede av Gud den usynlige, den førstefødte fremfor enhver skapning; for i ham er alle ting skapt, de i himlene og de på jorden, de synlige og de usynlige, enten det så er troner eller herredømmer eller makter eller myndigheter; alt er det skapt ved ham og til ham, og han er før alle ting, og alle ting står ved ham. Og han er hovedet for legemet, som er menigheten, han som er ophavet, den førstefødte av de døde, forat han i alle deler skulde være den ypperste; for det var Guds vilje at hele hans fylde skulde ta bolig i ham,",
 da: "12 og takke Faderen, som har gjort jer duelige til at få del i de helliges arv i lyset. 13 Han har udfriet os af mørkets magt og flyttet os over i sin elskede søns rige; 14 i ham har vi forløsningen, syndernes forladelse. 15 Han er den usynlige Guds billede, al skabnings førstefødte. 16 For i ham blev alting skabt i himlene og på jorden, det synlige og det usynlige, troner og herredømmer, magter og myndigheder. Alt er skabt ved ham og til ham. 17 Han er forud for alt, og alt består ved ham. 18 Og han er hoved for legemet, kirken. Han er begyndelsen, den førstefødte af de døde, for at han i alle ting skulle være den første. 19 For i ham besluttede Gud at lade hele sin fylde bo.",
 },
 "Colossians 2:8": {
 es: " Mirad que ninguno os engañe por filosofías y vanas sutilezas, según las tradiciones de los hombres, conforme á los elementos del mundo, y no según Cristo:",
 fr: "Prenez garde que personne ne fasse de vous sa proie par la philosophie et par une vaine tromperie, s'appuyant sur la tradition des hommes, sur les rudiments du monde, et non sur Christ.",
 pt: "Tendo cuidado para que ninguém vos faça presa sua, por meio de filosofias e vãs sutilezas, segundo a tradição dos homens, segundo os rudimentos do mundo, e não segundo Cristo;",
 sv: "Sen till, att ingen får bortföra eder såsom ett segerbyte genom sin tomma och bedrägliga »vishetslära», i det att han åberopar fäderneärvda människomeningar och håller sig till världens »makter» och icke till Kristus.",
 no: "Se til at det ikke må være nogen som gjør eder til sitt rov ved verdslig visdom og tomt bedrag, efter menneskenes lære, efter verdens barnelærdom og ikke efter Kristus.",
 da: "Se til, at ingen fanger jer med den tomme og bedrageriske filosofi, der bygger på menneskers overlevering, på verdens magter og ikke på Kristus.",
 },
 "Colossians 4:16": {
 es: " Y cuando esta carta fuere leída entre vosotros, haced que también sea leída en la iglesia de los Laodicenses; y la de Laodicea que la leáis también vosotros.",
 fr: "Lorsque cette lettre aura été lue chez vous, faites en sorte qu'elle soit aussi lue dans l'Eglise des Laodicéens, et que vous lisiez à votre tour celle qui vous arrivera de Laodicée.",
 pt: "Depois que for lida esta carta entre vós, fazei que o seja também na igreja dos laodicenses; e a de Laodicéia lede-a vós também.",
 no: "Og når dette brev er lest hos eder, da sørg for at det også blir lest i laodikeernes menighet, og at I får lese brevet fra Laodikea!",
 sv: "När detta brev har blivit uppläst hos er, se då till att det också blir uppläst i laodiceernas församling och att ni också läser brevet från Laodicea.",
 da: "Når dette brev er blevet læst op hos jer, sørg da for, at det også bliver læst op i laodikensernes menighed, og at I også får læst brevet fra Laodikea.",
 },
 "Colossians 3:5-6": {
 es: " Amortiguad, pues, vuestros miembros que están sobre la tierra: fornicación, inmundicia, molicie, mala concupiscencia, y avaricia, que es idolatría: Por las cuales cosas la ira de Dios viene sobre los hijos de rebelión.",
 fr: "Faites donc mourir les membres qui sont sur la terre, l'impudicité, l'impureté, les passions, les mauvais désirs, et la cupidité, qui est une idolâtrie. C'est à cause de ces choses que la colère de Dieu vient sur les fils de la rébellion,",
 pt: "Exterminai, pois, as vossas inclinações carnais; a prostituição, a impureza, a paixão, a vil concupiscência, e a avareza, que é idolatria; pelas quais coisas vem a ira de Deus sobre os filhos da desobediência;",
 sv: "Så döden nu edra lemmar, som höra jorden till: otukt, orenhet, lusta, ond begärelse, så ock girigheten, som ju är avgudadyrkan; ty för sådant kommer Guds vrede.",
 no: "Så død da eders jordiske lemmer: utukt, urenhet, brynde, ond lyst og havesyke, som jo er avgudsdyrkelse; for disse ting kommer Guds vrede over vantroens barn;",
 da: "5 Så lad da det jordiske i jer dø: utugt, urenhed, begær, ond lyst og den havesyge, som er afgudsdyrkelse. 6 Det er på grund af den slags, at Guds vrede kommer.",
 },
 "Revelation 1:1": {
 es: " LA revelación de Jesucristo, que Dios le dió, para manifestar á sus siervos las cosas que deben suceder presto; y la declaró, enviándola por su ángel á Juan su siervo,",
 fr: "Révélation de Jésus-Christ, que Dieu lui a donnée pour montrer à ses serviteurs les choses qui doivent arriver bientôt, et qu'il a fait connaître, par l'envoi de son ange, à son serviteur Jean,",
 pt: "Revelação de Jesus Cristo, que Deus lhe deu para mostrar aos seus servos as coisas que brevemente devem acontecer; e, enviando-as pelo seu anjo, as notificou a seu servo João;",
 sv: "Detta är en uppenbarelse från Jesus Kristus, en som Gud gav honom för att visa sina tjänare, vad som snart skall ske. Och medelst ett budskap genom sin ängel gav han det till känna för sin tjänare Johannes,",
 no: "Jesu Kristi åpenbaring, som Gud gav ham forat han skulde vise sine tjenere det som snart skal skje; og han sendte bud ved sin engel og kunngjorde det i tegn for sin tjener Johannes,",
 da: "Jesu Kristi åbenbaring, som Gud gav ham for at vise sine tjenere, hvad der snart skal ske. Han sendte sin engel og kundgjorde det ved tegn for sin tjener Johannes,",
 },
 "Revelation 3:5": {
 es: " El que venciere, será vestido de vestiduras blancas; y no borraré su nombre del libro de la vida, y confesaré su nombre delante de mi Padre, y delante de sus ángeles.",
 fr: "Celui qui vaincra sera revêtu ainsi de vêtements blancs; je n'effacerai point son nom du livre de vie, et je confesserai son nom devant mon Père et devant ses anges.",
 pt: "O que vencer será assim vestido de vestes brancas, e de maneira nenhuma riscarei o seu nome do livro da vida; antes confessarei o seu nome diante de meu Pai e diante dos seus anjos.",
 sv: "Den som vinner seger, han skall så bliva klädd i vita kläder, och jag skall aldrig utplåna hans namn ur livets bok, utan kännas vid hans namn inför min Fader och inför hans änglar.",
 no: "Den som seirer, han skal således bli klædd i hvite klær, og jeg vil ikke utslette hans navn av livsens bok, og jeg vil kjennes ved hans navn for min Fader og for hans engler.",
 da: "Den, der sejrer, skal klædes i hvide klæder, og hans navn vil jeg aldrig slette af livets bog, men jeg vil vedkende mig hans navn over for min fader og hans engle.",
 },
 "Revelation 13:8": {
 es: " Y todos los que moran en la tierra le adoraron, cuyos nombres no están escritos en el libro de la vida del Cordero, el cual fué muerto desde el principio del mundo.",
 fr: "Et tous les habitants de la terre l'adoreront, ceux dont le nom n'a pas été écrit dès la fondation du monde dans le livre de vie de l'agneau qui a été immolé.",
 pt: "E adora-la-ão todos os que habitam sobre a terra, esses cujos nomes não estão escritos no livro do Cordeiro que foi morto desde a fundação do mundo.",
 sv: "Och alla jordens inbyggare skola tillbedja det, ja, envar som icke har sitt namn från världens begynnelse skrivet i livets bok, det slaktade Lammets bok.",
 no: "Og alle som bor på jorden, skal tilbede det, hver den som ikke, fra verdens grunnvoll blev lagt, har fått sitt navn skrevet i livsens bok hos Lammet som er slaktet.",
 da: "Alle, der bor på jorden, vil tilbede det, enhver, hvis navn ikke fra verdens grundlæggelse er skrevet i livets bog, Lammet, det slagtede.",
 },
 "Revelation 14:6": {
 es: " Y vi otro ángel volar por en medio del cielo, que tenía el evangelio eterno para predicarlo á los que moran en la tierra, y á toda nación y tribu y lengua y pueblo,",
 fr: "Je vis un autre ange qui volait par le milieu du ciel, ayant un Evangile éternel, pour l'annoncer aux habitants de la terre, à toute nation, à toute tribu, à toute langue, et à tout peuple.",
 pt: "E vi outro anjo voando pelo meio do céu, e tinha um evangelho eterno para proclamar aos que habitam sobre a terra e a toda nação, e tribo, e língua, e povo,",
 sv: "Och jag såg en annan ängel flyga fram uppe i himlarymden; han hade ett evigt evangelium, som han skulle förkunna för dem som bo på jorden, för alla folkslag och stammar och tungomål och folk.",
 no: "Og jeg så en annen engel flyve under det høieste av himmelen, som hadde et evig evangelium å forkynne for dem som bor på jorden, og for hver ætt og stamme og tunge og folk,",
 da: "Jeg så endnu en engel flyve midt oppe under himlen; den havde et evigt evangelium at forkynde for dem, der bor på jorden, for alle folkeslag og stammer, tungemål og folk,",
 },
 "Revelation 20:12": {
 es: " Y vi los muertos, grandes y pequeños, que estaban delante de Dios; y los libros fueron abiertos: y otro libro fué abierto, el cual es de la vida: y fueron juzgados los muertos por las cosas que estaban escritas en los libros, según sus obras.",
 fr: "Et je vis les morts, les grands et les petits, qui se tenaient devant le trône. Des livres furent ouverts. Et un autre livre fut ouvert, celui qui est le livre de vie. Et les morts furent jugés selon leurs oeuvres, d'après ce qui était écrit dans ces livres.",
 pt: "E vi os mortos, grandes e pequenos, em pé diante do trono; e abriram-se uns livros; e abriu-se outro livro, que é o da vida; e os mortos foram julgados pelas coisas que estavam escritas nos livros, segundo as suas obras.",
 sv: "Och jag såg de döda, både stora och små, stå inför tronen, och böcker blevo upplåtna. Och jämväl en annan bok blev upplåten; det var livets bok. Och de döda blevo dömda efter sina gärningar, på grund av det som var upptecknat i böckerna.",
 no: "Og jeg så de døde, små og store, stå for Gud, og bøker blev åpnet; og en annen bok blev åpnet, som er livsens bok; og de døde blev dømt efter det som var skrevet i bøkene, efter sine gjerninger.",
 da: "Og jeg så de døde, både store og små, stå foran tronen, og bøger blev åbnet. Og en anden bog blev åbnet, det er livets bog. Og de døde blev dømt efter deres gerninger, efter det, der stod skrevet i bøgerne.",
 },
 "Revelation 2:5": {
 es: " Recuerda por tanto de dónde has caído, y arrepiéntete, y haz las primeras obras; pues si no, vendré presto á ti, y quitaré tu candelero de su lugar, si no te hubieres arrepentido.",
 fr: "Souviens-toi donc d'où tu es tombé, repens-toi, et pratique tes premières oeuvres; sinon, je viendrai à toi, et j'ôterai ton chandelier de sa place, à moins que tu ne te repentes.",
 pt: "Lembra-te, pois, donde caíste, e arrepende-te, e pratica as primeiras obras; e se não, brevemente virei a ti, e removerei do seu lugar o teu candeeiro, se não te arrependeres.",
 sv: "Betänk då varifrån du har fallit, och bättra dig, och gör åter sådana gärningar som du gjorde under din första tid. Varom icke, så skall jag komma över dig och skall flytta din ljusstake från dess plats, såframt du icke gör bättring.",
 no: "Kom derfor i hu hvad du er falt ifra, og omvend dig og gjør de første gjerninger! ellers kommer jeg over dig og vil flytte din lysestake fra dens sted, hvis du ikke omvender dig.",
 da: "Husk derfor på, hvorfra du er faldet, og omvend dig, og gør de gerninger, du først gjorde; ellers kommer jeg over dig og flytter din lysestage fra dens plads, hvis ikke du omvender dig.",
 },
 "Revelation 14:12-13": {
 es: " Aquí está la paciencia de los santos; aquí están los que guardan los mandamientos de Dios, y la fe de Jesús. Y oí una voz del cielo que me decía: Escribe: Bienaventurados los muertos que de aquí adelante mueren en el Señor. Sí, dice el Espíritu, que descansarán de sus trabajos; porque sus obras con ellos siguen.",
 fr: "C'est ici la persévérance des saints, qui gardent les commandements de Dieu et la foi de Jésus. Et j'entendis du ciel une voix qui disait: Ecris: Heureux dès à présent les morts qui meurent dans le Seigneur! Oui, dit l'Esprit, afin qu'ils se reposent de leurs travaux, car leurs oeuvres les suivent.",
 pt: "Aqui está a perseverança dos santos, daqueles que guardam os mandamentos de Deus e a fé em Jesus. Então ouvi uma voz do céu, que dizia: Escreve: Bem-aventurados os mortos que desde agora morrem no Senhor. Sim, diz o Espírito, para que descansem dos seus trabalhos, pois as suas obras os acompanham.",
 sv: "Här gäller det för de heliga att hava ståndaktighet, för dem som hålla Guds bud och bevara tron på Jesus.» Och jag hörde en röst från himmelen säga: »Skriv: Saliga äro de döda som dö i Herren härefter. Ja, säger Anden, de skola få vila sig från sitt arbete, ty deras gärningar följa dem.»",
 no: "Her er de helliges tålmodighet, de som holder Guds bud og Jesu tro. Og jeg hørte en røst fra himmelen si: Skriv: Salige er de døde som dør i Herren herefter! Ja, sier Ånden, de skal hvile fra sitt arbeid; for deres gjerninger følger med dem.",
 da: "12 Her kræves der udholdenhed af de hellige, dem som holder fast ved Guds bud og troen på Jesus. 13 Og jeg hørte en røst fra himlen sige: »Skriv: Salige er de døde, som fra nu af dør i Herren.« »Ja,« siger Ånden, »de skal hvile efter deres møje, for deres gerninger følger med dem.«",
 },
 "Revelation 21:8, 27": {
 es: " Mas á los temerosos é incrédulos, á los abominables y homicidas, á los fornicarios y hechiceros, y á los idólatras, y á todos los mentirosos, su parte será en el lago ardiendo con fuego y azufre, que es la muerte segunda. No entrará en ella ninguna cosa sucia, ó que hace abominación y mentira; sino solamente los que están escritos en el libro de la vida del Cordero.",
 fr: "Mais pour les lâches, les incrédules, les abominables, les meurtriers, les impudiques, les enchanteurs, les idolâtres, et tous les menteurs, leur part sera dans l'étang ardent de feu et de soufre, ce qui est la seconde mort. Il n'entrera chez elle rien de souillé, ni personne qui se livre à l'abomination et au mensonge; il n'entrera que ceux qui sont écrits dans le livre de vie de l'agneau.",
 pt: "Mas, quanto aos medrosos, e aos incrédulos, e aos abomináveis, e aos homicidas, e aos adúlteros, e aos feiticeiros, e aos idólatras, e a todos os mentirosos, a sua parte será no lago ardente de fogo e enxofre, que é a segunda morte. E não entrará nela coisa alguma impura, nem o que pratica abominação ou mentira; mas somente os que estão inscritos no livro da vida do Cordeiro.",
 sv: "Men de fega och de otrogna, och de som hava gjort vad styggeligt är, och dråpare och otuktiga människor och trollkarlar och avgudadyrkare och alla lögnare skola få sin del i den sjö som brinner med eld och svavel; detta är den andra döden.» Men intet orent skall någonsin komma ditin, och ingen som gör vad styggeligt är och lögn, utan allenast de som äro skrivna i livets bok, Lammets bok.",
 no: "Men de redde og vantro og vederstyggelige og manndraperne og horkarlene og trollmennene og avgudsdyrkerne og alle løgnerne, deres del skal være i sjøen som brenner med ild og svovel; det er den annen død. Og intet urent skal komme inn i den, og ingen som farer med stygghet og løgn, men bare de som er innskrevet i livsens bok hos Lammet.",
 da: "8 Men de feje og troløse og afskyelige og mordere og utugtige og troldmænd og afgudsdyrkere og alle løgnere skal få deres lod i søen, der brænder med ild og svovl; det er den anden død. ... 27 Men intet urent skal komme ind i den, og ingen, der øver afskyelighed og løgn, men kun de, der står skrevet i Lammets bog, livets bog.",
 },
 "Revelation 22:11-12": {
 es: " El que es injusto, sea injusto todavía: y el que es sucio, ensúciese todavía: y el que es justo, sea todavía justificado: y el santo sea santificado todavía. Y he aquí, yo vengo presto, y mi galardón conmigo, para recompensar á cada uno según fuere su obra.",
 fr: "Que celui qui est injuste soit encore injuste, que celui qui est souillé se souille encore; et que le juste pratique encore la justice, et que celui qui est saint se sanctifie encore. Voici, je viens bientôt, et ma rétribution est avec moi, pour rendre à chacun selon ce qu'est son oeuvre.",
 pt: "Quem é injusto, faça injustiça ainda: e quem está sujo, suje-se ainda; e quem é justo, faça justiça ainda; e quem é santo, santifique-se ainda. Eis que cedo venho e está comigo a minha recompensa, para retribuir a cada um segundo a sua obra.",
 sv: "Må den som är orättfärdig fortfara att öva sin orättfärdighet och den som är oren att orena sig. Så ock den som är rättfärdig, han fortfare att öva sin rättfärdighet, och den som är helig att helga sig. Se, jag kommer snart och har med mig min lön, för att vedergälla var och en efter som hans gärningar äro.",
 no: "La den som gjør urett, fremdeles gjøre urett, og den urene fremdeles bli uren, og den rettferdige fremdeles gjøre rettferdighet, og den hellige fremdeles bli helliggjort! Se, jeg kommer snart, og min lønn er med mig, til å gi enhver igjen efter som hans gjerning er.",
 da: "11 Lad den, der øver uret, stadig øve uret, og den urene stadig være uren, og den retfærdige stadig øve retfærdighed, og den hellige stadig helliges. 12 Se, jeg kommer snart, og min løn er med mig, for at gengælde enhver, som hans gerning er.",
 },
 "Titus 1:2": {
 es: " Para la esperanza de la vida eterna, la cual Dios, que no puede mentir, prometió antes de los tiempos de los siglos,",
 fr: "lesquelles reposent sur l'espérance de la vie éternelle, promise dès les plus anciens temps par le Dieu qui ne ment point,",
 pt: "na esperança da vida eterna, a qual Deus, que não pode mentir, prometeu antes dos tempos eternos,",
 sv: "sänd, därför att det finnes ett hopp om evigt liv -- ty evigt liv har Gud, som icke kan ljuga, för evärdliga tider sedan utlovat,",
 no: "i håp om evig liv, som Gud, han som ikke lyver, har lovt fra evige tider,",
 da: "i håb om evigt liv, som Gud, der ikke lyver, har lovet for evige tider siden,",
 },
 "Titus 1:5-9": {
 es: " Por esta causa te dejé en Creta, para que corrigieses lo que falta, y pusieses ancianos por las villas, así como yo te mandé: El que fuere sin crimen, marido de una mujer, que tenga hijos fieles que no estén acusados de disolución, ó contumaces. Porque es menester que el obispo sea sin crimen, como dispensador de Dios; no soberbio, no iracundo, no amador del vino, no heridor, no codicioso de torpes ganancias; Sino hospedador, amador de lo bueno, templado, justo, santo, continente; Retenedor de la fiel palabra que es conforme á la doctrina: para que también pueda exhortar con sana doctrina, y convencer á los que contradijeren.",
 fr: "Je t'ai laissé en Crète, afin que tu mettes en ordre ce qui reste à régler, et que, selon mes instructions, tu établisses des anciens dans chaque ville, s'il s'y trouve quelque homme irréprochable, mari d'une seule femme, ayant des enfants fidèles, qui ne soient ni accusés de débauche ni rebelles. Car il faut que l'évêque soit irréprochable, comme économe de Dieu; qu'il ne soit ni arrogant, ni colère, ni adonné au vin, ni violent, ni porté à un gain déshonnête; mais qu'il soit hospitalier, ami des gens de bien, modéré, juste, saint, tempérant, attaché à la vraie parole telle qu'elle a été enseignée, afin d'être capable d'exhorter selon la saine doctrine et de réfuter les contradicteurs.",
 pt: "Por esta causa te deixei em Creta, para que pusesses em boa ordem o que ainda não o está, e que em cada cidade estabelecesses anciãos, como já te mandei; alguém que seja irrepreensível, marido de uma só mulher, tendo filhos crentes que não sejam acusados de dissolução, nem sejam desobedientes. Pois é necessário que o bispo seja irrepreensível, como despenseiro de Deus, não soberbo, nem irascível, nem dado ao vinho, nem espancador, nem cobiçoso de torpe ganância; mas hospitaleiro, amigo do bem, sóbrio, justo, piedoso, temperante; retendo firme a palavra fiel, que é conforme a doutrina, para que seja poderoso, tanto para exortar na sã doutrina como para convencer os contradizentes.",
 sv: "När jag lämnade dig kvar på Kreta, var det för att du skulle ordna vad som ännu återstod att ordna, och för att du, på det sätt som jag har ålagt dig, skulle i var särskild stad tillsätta äldste, varhelst någon oförvitlig man funnes, en enda kvinnas man, en som hade troende barn, vilka icke vore i vanrykte för oskickligt leverne eller vore uppstudsiga. Ty en församlingsföreståndare bör vara oförvitlig, såsom det höves en Guds förvaltare, icke självgod, icke snar till vrede, icke begiven på vin, icke våldsam, icke sniken efter slem vinning. Han bör fastmer vara gästvänlig, nitälska för vad gott är, leva tuktigt, rättfärdigt, heligt och återhållsamt; han bör hålla sig stadigt vid det fasta ordet, såsom han har fått lära det, så att han är mäktig både att förmana medelst den sunda läran och att vederlägga dem som säga emot.",
 no: "Derfor lot jeg dig bli efter på Kreta at du skulde sette det i rette skikk som ennu stod tilbake, og innsette eldste i hver by, således som jeg foreskrev dig, om nogen er ulastelig, én kvinnes mann, og har troende barn som ikke har ondt ord på sig for ryggesløshet eller er gjenstridige. For en tilsynsmann skal være ulastelig som en Guds husholder, ikke selvgod, ikke vredladen, ikke drikkfeldig, ikke voldsom, ikke lysten efter ussel vinning, men gjestfri, glad i det gode, sindig, rettferdig, hellig, avholdende, en som holder fast ved det troverdige ord efter læren, forat han kan være i stand til både å formane ved den sunde lære og å tale til rette dem som sier imot.",
 da: "5 Jeg efterlod dig på Kreta, for at du skulle bringe orden i det, der endnu ikke var i orden, og indsætte ældste i byerne, sådan som jeg pålagde dig, 6 hvis en mand er uberygtet, én kvindes mand, og har troende børn, der ikke har ry for udsvævelser eller er genstridige. 7 For en tilsynsmand skal som Guds forvalter være uberygtet, ikke selvrådig, ikke opfarende, ikke drikfældig, ikke voldsom, ikke ude efter ussel vinding, 8 men gæstfri, glad for det gode, besindig, retfærdig, from, afholdende; 9 han skal holde fast ved det troværdige ord i overensstemmelse med læren, for at han kan være i stand til både at formane med den sunde lære og at gendrive dem, der siger imod.",
 },
 "Titus 1:12-13, 16": {
 es: " Dijo uno de ellos, propio profeta de ellos: Los Cretenses, siempre mentirosos, malas bestias, vientres perezosos. Este testimonio es verdadero: por tanto, repréndelos duramente, para que sean sanos en la fe, Profésanse conocer á Dios; mas con los hechos lo niegan, siendo abominables y rebeldes, reprobados para toda buena obra.",
 fr: "L'un d'entre eux, leur propre prophète, a dit: Crétois toujours menteurs, méchantes bêtes, ventres paresseux. Ce témoignage est vrai. C'est pourquoi reprends-les sévèrement, afin qu'ils aient une foi saine, Ils font profession de connaître Dieu, mais ils le renient par leurs oeuvres, étant abominables, rebelles, et incapables d'aucune bonne oeuvre.",
 pt: "Um dentre eles, seu próprio profeta, disse: Os cretenses são sempre mentirosos, bestas ruins, glutões preguiçosos. Este testemunho é verdadeiro. Portanto repreende-os severamente, para que sejam são na fé, Afirmam que conhecem a Deus, mas pelas suas obras o negam, sendo abomináveis, e desobedientes, e réprobos para toda boa obra.",
 sv: "En av dem, en profet av deras eget folk, har sagt: »Kreterna, lögnare jämt, äro odjur, glupska och lata.» Och det vittnesbördet är sant. Du skall därför strängt tillrättavisa dem, så att de bliva sunda i tron De säga sig känna Gud, men med sina gärningar förneka de det; ty de äro vederstyggliga och ohörsamma människor, odugliga till allt gott verk.",
 no: "En av dem, deres egen profet, har sagt: Kreterne er alltid løgnere, onde dyr, late buker. Dette vidnesbyrd er sant. Derfor skal du tale dem strengt til rette, forat de må bli sunde i troen, De sier at de kjenner Gud; men de fornekter ham med sine gjerninger, for de er vederstyggelige og ulydige og uduelige til all god gjerning.",
 da: "12 En af dem, deres egen profet, har sagt: »Kretere er altid løgnere, onde dyr, grådige og dovne.« 13 Dette vidnesbyrd er sandt. Derfor skal du irettesætte dem strengt, for at de må blive sunde i troen... 16 De bekender, at de kender Gud, men i deres gerninger fornægter de ham; de er afskyelige og ulydige, uduelige til al god gerning.",
 },
 "Hebrews 1:3": {
 es: " El cual siendo el resplandor de su gloria, y la misma imagen de su sustancia, y sustentando todas las cosas con la palabra de su potencia, habiendo hecho la purgación de nuestros pecados por sí mismo, se sentó á la diestra de la Majestad en las alturas,",
 fr: "et qui, étant le reflet de sa gloire et l'empreinte de sa personne, et soutenant toutes choses par sa parole puissante, a fait la purification des péchés et s'est assis à la droite de la majesté divine dans les lieux très hauts,",
 pt: "sendo ele o resplendor da sua glória e a expressa imagem do seu Ser, e sustentando todas as coisas pela palavra do seu poder, havendo ele mesmo feito a purificação dos pecados, assentou-se à direita da Majestade nas alturas,",
 sv: "Och eftersom denne är hans härlighets återsken och hans väsens avbild och genom sin makts ord bär allt, har han -- sedan han hade utfört en rening från synderna -- satt sig på Majestätets högra sida i höjden.",
 no: "han som er avglansen av hans herlighet og avbilledet av hans vesen og bærer alle ting ved sin krafts ord, og som derfor, da han hadde gjort renselse for våre synder, satte sig ved Majestetens høire hånd i det høie,",
 da: "Han er en udstråling af hans herlighed og et aftryk af hans væsen, og han bærer alt med sit mægtige ord. Da han havde fuldbragt renselse for synder, tog han sæde ved den Højestes højre hånd i det høje,",
 },
 "Hebrews 5:1-4": {
 es: " PORQUE todo pontífice, tomado de entre los hombres, es constituído á favor de los hombres en lo que á Dios toca, para que ofrezca presentes y sacrificios por los pecados: Que se pueda compadecer de los ignorantes y extraviados, pues que él también está rodeado de flaqueza; Y por causa de ella debe, como por sí mismo, así también por el pueblo, ofrecer por los pecados. Ni nadie toma para sí la honra, sino el que es llamado de Dios, como Aarón.",
 fr: "En effet, tout souverain sacrificateur pris du milieu des hommes est établi pour les hommes dans le service de Dieu, afin de présenter des offrandes et des sacrifices pour les péchés. Il peut être indulgent pour les ignorants et les égarés, puisque la faiblesse est aussi son partage. Et c'est à cause de cette faiblesse qu'il doit offrir des sacrifices pour ses propres péchés, comme pour ceux du peuple. Nul ne s'attribue cette dignité, s'il n'est appelé de Dieu, comme le fut Aaron.",
 pt: "Porque todo sumo sacerdote tomado dentre os homens é constituído a favor dos homens nas coisas concernentes a Deus, para que ofereça dons e sacrifícios pelos pecados, podendo ele compadecer-se devidamente dos ignorantes e errados, porquanto também ele mesmo está rodeado de fraqueza. E por esta razão deve ele, tanto pelo povo como também por si mesmo, oferecer sacrifício pelos pecados. Ora, ninguém toma para si esta honra, senão quando é chamado por Deus, como o foi Arão.",
 sv: "Ty var och en som skall bliva överstepräst uttages bland människor och tillsättes för att till människors bästa göra tjänst inför Gud, genom att frambära gåvor och offer för synder. Och han kan hava undseende med de okunniga och vilsefarande, just därför att han själv är behäftad med svaghet och, för denna sin svaghets skull, måste offra för sina egna synder likaväl som för folkets. Och ingen tager sig själv denna värdighet, utan han måste, såsom Aron, kallas därtill av Gud.",
 no: "For hver yppersteprest tas iblandt mennesker og innsettes for mennesker til tjeneste for Gud, for å frembære både gaver og slaktoffer for synder, som en som kan bære over med de vankundige og villfarende, fordi han også selv er skrøpelighet underlagt, og for dens skyld må frembære syndoffer, som for folket, så og for sig selv. Og ingen tiltar sig selv den ære, men den som kalles av Gud, likesom Aron.",
 da: "1 For enhver ypperstepræst tages jo ud af menneskenes midte og indsættes til at varetage menigmands forhold til Gud, for at han kan frembære gaver og slagtofre for synder. 2 Han kan føle med de uvidende og vildfarende, fordi han også selv er underlagt skrøbelighed, 3 og på grund af den må han frembære syndofre såvel for sig selv som for folket. 4 Og ingen tager sig selv den ære, men han bliver kaldet af Gud, ligesom Aron.",
 },
 "Hebrews 5:5": {
 es: " Así también Cristo no se glorificó á sí mismo haciéndose Pontífice, mas el que le dijo: Tú eres mi Hijo, yo te he engendrado hoy;",
 fr: "Et Christ ne s'est pas non plus attribué la gloire de devenir souverain sacrificateur, mais il la tient de celui qui lui a dit: Tu es mon Fils, Je t'ai engendré aujourd'hui!",
 pt: "assim também Cristo não se glorificou a si mesmo, para se fazer sumo sacerdote, mas o glorificou aquele que lhe disse: Tu és meu Filho, hoje te gerei;",
 sv: "Så tog sig icke heller Kristus själv äran att bliva överstepräst, utan den äran tillföll honom genom den som sade till honom: »Du är min Son, jag har i dag fött dig»,",
 no: "Således tilla da heller ikke Kristus sig den ære å bli yppersteprest, men han som sa til ham: Du er min Sønn, jeg har født dig idag;",
 da: "Således har Kristus heller ikke tilranet sig den ære at være ypperstepræst; det var ham, der sagde til ham: Du er min søn, jeg har født dig i dag;",
 },
 "Hebrews 5:8-9": {
 es: " Y aunque era Hijo, por lo que padeció aprendió la obediencia; Y consumado, vino á ser causa de eterna salud á todos los que le obedecen;",
 fr: "a appris, bien qu'il fût Fils, l'obéissance par les choses qu'il a souffertes, et qui, après avoir été élevé à la perfection, est devenu pour tous ceux qui lui obéissent l'auteur d'un salut éternel,",
 pt: "ainda que era Filho, aprendeu a obediência por meio daquilo que sofreu; e, tendo sido aperfeiçoado, veio a ser autor de eterna salvação para todos os que lhe obedecem,",
 sv: "Så lärde han, fastän han var »Son», lydnad genom sitt lidande; och när han hade blivit fullkomnad, blev han, för alla dem som äro honom lydiga, upphovet till evig frälsning",
 no: "og således lærte han, skjønt han var Sønn, lydighet av det han led, og da han var fullendt, blev han ophav til evig frelse for alle dem som lyder ham,",
 da: "8 Og skønt han var søn, lærte han lydighed af det, han led, 9 og da han havde nået målet, blev han ophav til evig frelse for alle, der adlyder ham,",
 },
 "Hebrews 9:24": {
 es: " Porque no entró Cristo en el santuario hecho de mano, figura del verdadero, sino en el mismo cielo para presentarse ahora por nosotros en la presencia de Dios.",
 fr: "Car Christ n'est pas entré dans un sanctuaire fait de main d'homme, en imitation du véritable, mais il est entré dans le ciel même, afin de comparaître maintenant pour nous devant la face de Dieu.",
 pt: "Pois Cristo não entrou num santuário feito por mãos, figura do verdadeiro, mas no próprio céu, para agora comparecer por nós perante a face de Deus;",
 sv: "Ty Kristus har icke gått in i ett allraheligaste som är gjort med händer, och som allenast är en efterbildning av det sannskyldiga, utan han har gått in i själva himmelen, för att nu träda fram inför Guds ansikte, oss till godo.",
 no: "For Kristus gikk ikke inn i en helligdom som var gjort med hender og bare var et billede av den sanne, men inn i selve himmelen, for nu å åpenbares for Guds åsyn for vår skyld,",
 da: "For Kristus gik ikke ind i en helligdom, der er gjort med hænder og kun er en efterligning af den sande, men ind i selve himlen for nu at træde frem for Guds ansigt for vor skyld.",
 },
 "Hebrews 11:1": {
 es: " ES pues la fe la sustancia de las cosas que se esperan, la demostración de las cosas que no se ven.",
 fr: "Or la foi est une ferme assurance des choses qu'on espère, une démonstration de celles qu'on ne voit pas.",
 pt: "Ora, a fé é o firme fundamento das coisas que se esperam, e a prova das coisas que não se vêem.",
 sv: "Men tron är en fast tillförsikt om det som man hoppas, en övertygelse om ting som man icke ser.",
 no: "Men tro er full visshet om det som håpes, overbevisning om ting som ikke sees.",
 da: "Tro er fast tillid til det, der håbes på, overbevisning om det, der ikke ses.",
 },
 "Hebrews 12:9": {
 es: " Por otra parte, tuvimos por castigadores á los padres de nuestra carne, y los reverenciábamos, ¿por qué no obedeceremos mucho mejor al Padre de los espíritus, y viviremos?",
 fr: "D'ailleurs, puisque nos pères selon la chair nous ont châtiés, et que nous les avons respectés, ne devons-nous pas à bien plus forte raison nous soumettre au Père des esprits, pour avoir la vie?",
 pt: "Além disto, tivemos nossos pais segundo a carne, para nos corrigirem, e os olhavamos com respeito; não nos sujeitaremos muito mais ao Pai dos espíritos, e viveremos?",
 sv: "Vidare: vi hava haft köttsliga fäder, som agade oss, och vi visade försyn för dem; skola vi då icke mycket mer vara underdåniga andarnas Fader, så att vi få leva?",
 no: "Dessuten: våre kjødelige fedre hadde vi til optuktere, og vi hadde ærefrykt for dem; skal vi da ikke meget mere være lydige mot åndenes Fader, så vi får leve?",
 da: "Desuden: Vore jordiske fædre tugtede os, og vi havde ærefrygt for dem; skulle vi da ikke så meget mere underordne os åndernes Fader, for at vi kan leve?",
 },
 "Hebrews 13:8": {
 es: " Jesucristo es el mismo ayer, y hoy, y por los siglos.",
 fr: "Jésus-Christ est le même hier, aujourd'hui, et éternellement.",
 pt: "Jesus Cristo é o mesmo, ontem, e hoje, e eternamente.",
 sv: "Jesus Kristus är densamme i går och i dag, så ock i evighet.",
 no: "Jesus Kristus er igår og idag den samme, ja til evig tid.",
 da: "Jesus Kristus er den samme i går og i dag og til evig tid.",
 },
 "Hebrews 13:20": {
 es: " Y el Dios de paz que sacó de los muertos á nuestro Señor Jesucristo, el gran pastor de las ovejas, por la sangre del testamento eterno,",
 fr: "Que le Dieu de paix, qui a ramené d'entre les morts le grand pasteur des brebis, par le sang d'une alliance éternelle, notre Seigneur Jésus,",
 pt: "Ora, o Deus de paz, que pelo sangue do pacto eterno tornou a trazer dentre os mortos a nosso Senhor Jesus, grande pastor das ovelhas,",
 sv: "Men fridens Gud, som från de döda har återfört vår Herre Jesus, vilken genom ett evigt förbunds blod är den store herden för fåren,",
 no: "Men fredens Gud, som i kraft av en evig pakts blod førte fårenes store hyrde, vår Herre Jesus, op fra de døde,",
 da: "Men fredens Gud, som i kraft af en evig pagts blod førte fårenes store hyrde, vor Herre Jesus, op fra de døde,",
 },
 "Hebrews 3:14": {
 es: " Porque participantes de Cristo somos hechos, con tal que conservemos firme hasta el fin el principio de nuestra confianza;",
 fr: "Car nous sommes devenus participants de Christ, pourvu que nous retenions fermement jusqu'à la fin l'assurance que nous avions au commencement,",
 pt: "porque nos temos tornado participantes de Cristo, se é que guardamos firme até o fim a nossa confiança inicial;",
 sv: "Ty vi hava blivit delaktiga av Kristus, såframt vi eljest intill änden hålla fast vår första tillförsikt.",
 no: "for vi har fått del med Kristus, såfremt vi holder vår første fulle visshet fast inntil enden.",
 da: "For vi har fået del i Kristus, hvis vi blot indtil det sidste holder fast ved den tillid, vi havde i begyndelsen.",
 },
 "Luke 1:70": {
 es: " Como habló por boca de sus santos profetas que fueron desde el principio:",
 fr: "Comme il l'avait annoncé par la bouche de ses saints prophètes des temps anciens, -",
 pt: "assim como desde os tempos antigos tem anunciado pela boca dos seus santos profetas;",
 sv: "såsom han hade lovat genom sin forntida heliga profeters mun.",
 no: "således som han talte gjennem sine hellige profeters munn fra fordums tid av,",
 da: "sådan som han fra gammel tid har talt gennem sine hellige profeters mund,",
 },
 "Luke 3:21-22": {
 es: " Y aconteció que, como todo el pueblo se bautizaba, también Jesús fué bautizado; y orando, el cielo se abrió, Y descendió el Espíritu Santo sobre él en forma corporal, como paloma, y fué hecha una voz del cielo que decía: Tú eres mi Hijo amado, en ti me he complacido.",
 fr: "Tout le peuple se faisant baptiser, Jésus fut aussi baptisé; et, pendant qu'il priait, le ciel s'ouvrit, et le Saint-Esprit descendit sur lui sous une forme corporelle, comme une colombe. Et une voix fit entendre du ciel ces paroles: Tu es mon Fils bien-aimé; en toi j'ai mis toute mon affection.",
 pt: "Quando todo o povo fora batizado, tendo sido Jesus também batizado, e estando ele a orar, o céu se abriu; e o Espírito Santo desceu sobre ele em forma corpórea, como uma pomba; e ouviu-se do céu esta voz: Tu és o meu Filho amado; em ti me comprazo.",
 sv: "När nu allt folket lät döpa sig och jämväl Jesus blev döpt, så skedde därvid, medan han bad, att himmelen öppnades, och den helige Ande sänkte sig ned över honom I lekamlig skepnad såsom en duva; och från himmelen kom en röst: »Du är min älskade Son; i dig har jag funnit behag.»",
 no: "Men det skjedde da alt folket lot sig døpe, og Jesus var blitt døpt og bad, da åpnet himmelen sig, og den Hellige Ånd kom ned over ham i legemlig skikkelse, som en due, og en røst kom fra himmelen: Du er min Sønn, den elskede; i dig har jeg velbehag.",
 da: "21 Mens nu hele folket blev døbt, og også Jesus blev døbt og bad, skete det, at himlen åbnede sig, 22 og Helligånden dalede ned over ham i legemlig skikkelse som en due, og en røst lød fra himlen: »Du er min elskede søn, i dig har jeg velbehag.«",
 },
 "Luke 6:12": {
 es: " Y aconteció en aquellos días, que fué al monte á orar, y pasó la noche orando á Dios.",
 fr: "En ce temps-là, Jésus se rendit sur la montagne pour prier, et il passa toute la nuit à prier Dieu.",
 pt: "Naqueles dias retirou-se para o monte a fim de orar; e passou a noite toda em oração a Deus.",
 sv: "Så hände sig på den tiden att han gick åstad upp på berget för att bedja; och han blev kvar där över natten i bön till Gud.",
 no: "Og det skjedde i de dager at han gikk op i fjellet for å bede, og han var der hele natten i bønn til Gud.",
 da: "I de dage skete det, at han gik ud på bjerget for at bede, og han tilbragte hele natten i bøn til Gud.",
 },
 "Luke 6:40": {
 es: " El discípulo no es sobre su maestro; mas cualquiera que fuere como el maestro, será perfecto.",
 fr: "Le disciple n'est pas plus que le maître; mais tout disciple accompli sera comme son maître.",
 pt: "Não é o discípulo mais do que o seu mestre; mas todo o que for bem instruído será como o seu mestre.",
 sv: "Lärjungen är icke förmer än sin mästare; när någon bliver fullärd, så bliver han allenast sin mästare lik.",
 no: "En disippel er ikke over sin mester, men enhver som er full-lært, blir som sin mester.",
 da: "En discipel står ikke over sin mester, men enhver, der er udlært, skal være som sin mester.",
 },
 "Luke 9:1-2": {
 es: " Y JUNTANDO á sus doce discípulos, les dió virtud y potestad sobre todos los demonios, y que sanasen enfermedades. Y los envió á que predicasen el reino de Dios, y que sanasen á los enfermos.",
 fr: "Jésus, ayant assemblé les douze, leur donna force et pouvoir sur tous les démons, avec la puissance de guérir les maladies. Il les envoya prêcher le royaume de Dieu, et guérir les malades.",
 pt: "Reunindo os doze, deu-lhes poder e autoridade sobre todos os demônios, e para curarem doenças; e enviou-os a pregar o reino de Deus, e fazer curas,",
 sv: "Och han kallade tillhopa de tolv och gav dem makt och myndighet över alla onda andar, så ock makt att bota sjukdomar. Och han sände ut dem till att predika Guds rike och till att bota sjuka.",
 no: "Og han kalte de tolv sammen og gav dem makt og myndighet over alle de onde ånder og til å helbrede sykdommer, og han sendte dem ut for å forkynne Guds rike og helbrede syke.",
 da: "1 Så kaldte han de tolv sammen og gav dem magt og myndighed over alle dæmoner og til at helbrede sygdomme. 2 Og han sendte dem ud for at prædike Guds rige og helbrede de syge.",
 },
 "Luke 10:1, 17-19": {
 es: " Y DESPUÉS de estas cosas, designó el Señor aun otros setenta, los cuales envió de dos en dos delante de sí, á toda ciudad y lugar á donde él había de venir. Y volvieron los setenta con gozo, diciendo: Señor, aun los demonios se nos sujetan en tu nombre. Y les dijo: Yo veía á Satanás, como un rayo, que caía del cielo. He aquí os doy potestad de hollar sobre las serpientes y sobre los escorpiones, y sobre toda fuerza del enemigo, y nada os dañará.",
 fr: "Après cela, le Seigneur désigna encore soixante-dix autres disciples, et il les envoya deux à deux devant lui dans toutes les villes et dans tous les lieux où lui-même devait aller. Les soixante-dix revinrent avec joie, disant: Seigneur, les démons mêmes nous sont soumis en ton nom. Jésus leur dit: Je voyais Satan tomber du ciel comme un éclair. Voici, je vous ai donné le pouvoir de marcher sur les serpents et les scorpions, et sur toute la puissance de l'ennemi; et rien ne pourra vous nuire.",
 pt: "Depois disso designou o Senhor outros setenta, e os enviou adiante de si, de dois em dois, a todas as cidades e lugares aonde ele havia de ir. Voltaram depois os setenta com alegria, dizendo: Senhor, em teu nome, até os demônios se nos submetem. Respondeu-lhes ele: Eu via Satanás, como raio, cair do céu. Eis que vos dei autoridade para pisar serpentes e escorpiões, e sobre todo o poder do inimigo; e nada vos fará dano algum.",
 sv: "Därefter utsåg Herren sjuttiotvå andra och sände ut dem framför sig, två och två, till var stad och ort dit han själv tänkte komma Och de sjuttiotvå kommo tillbaka, uppfyllda av glädje, och sade: »Herre, också de onda andarna äro oss underdåniga genom ditt namn.» Då sade han till dem: »Jag såg Satan falla ned från himmelen såsom en ljungeld. Se, jag har givit eder makt att trampa på ormar och skorpioner och att förtrampa all ovännens härsmakt, och han skall icke kunna göra eder någon skada.",
 no: "Siden utvalgte Herren også sytti andre og sendte dem ut, to og to, i forveien for sig til hver by og hvert sted hvor han selv skulde komme. Og de sytti kom glade tilbake og sa: Herre! endog de onde ånder er oss lydige i ditt navn! Da sa han til dem: Jeg så Satan falle ned fra himmelen som et lyn. Se, jeg har gitt eder makt til å trede på slanger og skorpioner og over alt fiendens velde, og ingen ting skal skade eder;",
 da: "1 Derefter udpegede Herren andre halvfjerds og sendte dem i forvejen to og to til alle de byer og steder, hvor han selv agtede sig hen. \n17 De halvfjerds vendte glade tilbage og fortalte: »Herre, selv dæmonerne adlyder os i dit navn.« \n18 Da sagde han til dem: »Jeg så Satan falde ned fra himlen som et lyn. \n19 Se, jeg har givet jer magt til at træde på slanger og skorpioner og over hele fjendens styrke, og slet intet skal kunne skade jer.",
 },
 "Luke 11:18": {
 es: " Y si también Satanás está dividido contra sí mismo, ¿cómo estará en pie su reino? porque decís que en Beelzebub echo yo fuera los demonios.",
 fr: "Si donc Satan est divisé contre lui-même, comment son royaume subsistera-t-il, puisque vous dites que je chasse les démons par Béelzébul?",
 pt: "Ora, pois, se Satanás está dividido contra si mesmo, como subsistirá o seu reino? Pois dizeis que eu expulso dos demônios por Belzebu.",
 sv: "Om nu Satan har kommit i strid med sig själv, huru kan då hans rike hava bestånd? I sägen ju att det är med Beelsebul som jag driver ut de onda andarna.",
 no: "Men er nu også Satan kommet i strid med sig selv, hvorledes kan da hans rike bli stående? I sier jo at jeg driver de onde ånder ut ved Be'elsebul.",
 da: "Hvis nu Satan er kommet i splid med sig selv, hvordan kan hans rige så bestå? I siger jo, at det er ved Beelzebul, jeg driver dæmonerne ud.",
 },
 "Luke 13:34": {
 es: " ¡Jerusalem, Jerusalem! que matas á los profetas, y apedreas á los que son enviados á ti: ¡cuántas veces quise juntar tus hijos, como la gallina sus pollos debajo de sus alas, y no quisiste!",
 fr: "Jérusalem, Jérusalem, qui tues les prophètes et qui lapides ceux qui te sont envoyés, combien de fois ai-je voulu rassembler tes enfants, comme une poule rassemble sa couvée sous ses ailes, et vous ne l'avez pas voulu!",
 pt: "Jerusalém, Jerusalém, que matas os profetas, e apedrejas os que a ti são enviados! Quantas vezes quis eu ajuntar os teus filhos, como a galinha ajunta a sua ninhada debaixo das asas, e não quiseste!",
 sv: "Jerusalem, Jerusalem, du som dräper profeterna och stenar dem som äro sända till dig! Huru ofta har jag icke velat församla dina barn, likasom hönan församlar sina kycklingar under sina vingar! Men haven icke velat.",
 no: "Jerusalem! Jerusalem! du som slår ihjel profetene og stener dem som er sendt til dig! hvor ofte jeg vilde samle dine barn, likesom en høne samler sine kyllinger under sine vinger! Og I vilde ikke.",
 da: "Jerusalem, Jerusalem! du, som slår profeterne ihjel og stener dem, der er sendt til dig. Hvor ofte har jeg ikke villet samle dine børn, som en høne samler sine kyllinger under vingen, men I ville ikke.",
 },
 "Luke 23:42-43": {
 es: " Y dijo á Jesús: Acuérdate de mí cuando vinieres á tu reino. Entonces Jesús le dijo: De cierto te digo, que hoy estarás conmigo en el paraíso.",
 fr: "Et il dit à Jésus: Souviens-toi de moi, quand tu viendras dans ton règne. Jésus lui répondit: Je te le dis en vérité, aujourd'hui tu seras avec moi dans le paradis.",
 pt: "Então disse: Jesus, lembra-te de mim, quando entrares no teu reino. Respondeu-lhe Jesus: Em verdade te digo que hoje estarás comigo no paraíso.",
 sv: "Sedan sade han: »Jesus, tänk på mig, när du kommer i ditt rike.» Han svarade honom: »Sannerligen säger jag dig: I dag skall du vara med mig i paradiset.»",
 no: "Og han sa: Jesus! kom mig i hu når du kommer i ditt rike! Og han sa til ham: Sannelig sier jeg dig: Idag skal du være med mig i Paradis.",
 da: "42 Og han sagde: »Jesus, husk mig, når du kommer i dit rige.« \n43 Og Jesus sagde til ham: »Sandelig siger jeg dig: I dag skal du være med mig i Paradis.«",
 },
};